function getSheetDimension(ws){
  if(!ws||!ws['!ref']) return {maxRow:0,maxCol:0,ref:''};
  try{
    const r=XLSX.utils.decode_range(ws['!ref']);
    return {maxRow:r.e.r+1,maxCol:r.e.c+1,ref:ws['!ref']};
  }catch(e){ return {maxRow:0,maxCol:0,ref:ws['!ref']||''}; }
}
function verifyExactTemplateShape(wb){
  const issues=[];
  const names=wb.SheetNames||[];
  if(names.length!==4) issues.push(`시트 수=${names.length}, 기대=4`);
  const checks=[EXACT_TEMPLATE_EXPECTED.main,EXACT_TEMPLATE_EXPECTED.form1,EXACT_TEMPLATE_EXPECTED.form2,EXACT_TEMPLATE_EXPECTED.form3];
  checks.forEach(def=>{
    const sn=names[def.sheetIndex];
    const ws=wb.Sheets[sn];
    if(!ws){ issues.push(`${def.sheetIndex+1}번째 시트 없음: 기대 ${def.name}`); return; }
    if(sn!==def.name) issues.push(`${def.sheetIndex+1}번째 시트명=${sn}, 기대=${def.name}`);
    const d=getSheetDimension(ws);
    if(d.maxRow!==def.maxRow || d.maxCol!==def.maxCol) issues.push(`${sn} 범위=${d.ref}, 기대=${def.maxRow}행 ${def.maxCol}열`);
    const mergeCount=Array.isArray(ws['!merges'])?ws['!merges'].length:0;
    if(def.mergedCount && mergeCount!==def.mergedCount) issues.push(`${sn} 병합=${mergeCount}, 기대=${def.mergedCount}`);
  });
  const ws1=wb.Sheets[EXACT_TEMPLATE_EXPECTED.main.name]||wb.Sheets[names[0]];
  const ws4=wb.Sheets[EXACT_TEMPLATE_EXPECTED.form3.name]||wb.Sheets[names[3]];
  const mainChecks=[[1,11],[9,19],[10,26],[108,124],[109,125],[110,126],[111,127],[112,128]];
  mainChecks.forEach(([inum,row])=>{
    const v=sheetGet(ws1,row,1)?.v;
    if(String(v).trim()!==String(inum)) issues.push(`1탭 A${row}=${v||''}, 기대=${inum}`);
  });
  if(ws4){
    [[1,9],[110,118],[111,119],[112,121]].forEach(([inum,row])=>{
      const v=sheetGet(ws4,row,1)?.v;
      if(String(v).trim()!==String(inum)) issues.push(`4탭 A${row}=${v||''}, 기대=${inum}`);
    });
    const formulaChecks=[[10,"='80871631'!I12"],[18,"='80871631'!I26"],[115,"='80871631'!I123"]];
    formulaChecks.forEach(([row,expected])=>{
      const f=sheetGet(ws4,row,FORM3_RESULT_COL)?.f;
      const shown=f?('='+f):String(sheetGet(ws4,row,FORM3_RESULT_COL)?.v||'');
      if(shown!==expected) issues.push(`4탭 E${row}=${shown}, 기대=${expected}`);
    });
  }
  return issues;
}
function normalizeResultItemsForCertificate(){
  const by={};
  (STATE.itemStatus||[]).forEach(it=>{ const n=parseInt(it.inum,10); if(n>=1&&n<=112 && !by[n]) by[n]=it; });
  const rows=[];
  for(let n=1;n<=112;n++){
    const src=by[n]||{};
    rows.push(Object.assign({},src,{inum:String(n),outputCell:mainResultCellForInum(n),form3Cell:form3ResultCellForInum(n)}));
  }
  return rows;
}

