const el=id=>document.getElementById(id);
const setEl=(id,v)=>{const e=el(id);if(e)e.textContent=v;};
function sanitizePlainText(v,maxLen=0){
  if(v===null||v===undefined) return '';
  let s='';
  if(typeof v==='string') s=v;
  else if(typeof v==='number') s=Number.isFinite(v)?String(v):'';
  else if(typeof v==='boolean') s=v?'true':'false';
  else if(v instanceof Date) s=v.toISOString();
  else if(typeof v==='object'){
    if(typeof v.text==='string') s=v.text;
    else if(v.result!==undefined&&typeof v.result!=='object') s=String(v.result);
    else if(Array.isArray(v.richText)) s=v.richText.map(x=>x&&x.text?x.text:'').join('');
    else { try{s=JSON.stringify(v);}catch(e){s=String(v);} }
  } else s=String(v);
  s=s.replace(/[\u0000-\u0008\u000B\u000C\u000E-\u001F\u007F]/g,' ');
  s=s.replace(/\r\n/g,'\n').replace(/\r/g,'\n');
  if(maxLen>0 && s.length>maxLen) s=s.slice(0,maxLen);
  return s;
}
function escHtml(v,maxLen=0){
  return sanitizePlainText(v,maxLen)
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;')
    .replace(/'/g,'&#39;');
}
function safeCellValue(v){
  if(v===null||v===undefined) return '';
  if(typeof v==='number') return Number.isFinite(v)?v:'';
  if(typeof v==='boolean') return v;
  if(v instanceof Date) return v;
  return sanitizePlainText(v,32767);
}
function addSafeRow(ws,arr){ return ws.addRow((arr||[]).map(safeCellValue)); }
function scoreDecodedDXF(txt){
  const repl=(txt.match(/\uFFFD/g)||[]).length;
  const nul=(txt.match(/\u0000/g)||[]).length;
  let score=0;
  if(/\bSECTION\b/.test(txt)) score+=20;
  if(/\bENTITIES\b/.test(txt)) score+=15;
  if(/\bEOF\b/.test(txt)) score+=10;
  if(/\bHEADER\b/.test(txt)) score+=8;
  if(/AcDb|TEXT|MTEXT|DIMENSION|LAYER/.test(txt)) score+=10;
  score-=repl*5;
  score-=nul*5;
  return score;
}
async function readDxfTextSmart(file){
  const buf=await file.arrayBuffer();
  const bytes=new Uint8Array(buf);
  const encodings=['utf-8','euc-kr','cp949'];
  let best={enc:'utf-8',score:-Infinity,text:''};
  for(const enc of encodings){
    try{
      const td=new TextDecoder(enc,{fatal:false});
      const txt=td.decode(bytes);
      const score=scoreDecodedDXF(txt);
      if(score>best.score) best={enc,score,text:txt};
    }catch(e){}
  }
  if(!best.text){
    const td=new TextDecoder('utf-8',{fatal:false});
    const txt=td.decode(bytes);
    best={enc:'utf-8',score:scoreDecodedDXF(txt),text:txt};
  }
  return best;
}

