let curStep=1;
function goStep(n, force=false){
  if(n>1&&!force&&!STATE.analysisRun){
    const missing=[];
    if(!(STATE.dxfText||STATE.pdfFile)) missing.push('도면 파일(DXF/PDF)');
    if(!STATE.xlsxBuffer) missing.push('빈 검사성적서 XLSX 양식');
    const msg=missing.length
      ? '분석 실행 전 필수 파일이 부족합니다.\n부족한 파일: '+missing.join(', ')+'\n\n도면 파일과 XLSX 양식을 모두 업로드한 뒤 [분석 시작]을 누르세요.'
      : '파일이 모두 준비됐습니다. [분석 시작] 버튼을 눌러 분석을 실행하세요.';
    showAlert('분석 필요',msg);
    return;
  }
  for(let i=1;i<=5;i++){
    const s=el('stp'+i),c=el('step'+i),l=el('sl'+i);
    if(!s||!c) continue;
    s.className='step'+(i<n?' done':i===n?' active':'');
    c.classList.toggle('hidden',i!==n);
    if(l) l.style.background=i<n?'var(--c-ok)':'var(--border)';
  }
  curStep=n;
  if(n===3)renderCompleteness();
  if(n===4)renderItems();
  if(n===5)renderVerify();
}

