function onDxfFile(inp){
  const f=inp.files[0]; if(!f) return;
  const ext=f.name.split('.').pop().toLowerCase();
  if(ext==='dwg'){
    showAlert('DWG 미지원','DWG는 직접 분석 불가합니다.\nAutoCAD에서 DXF(R2013) 또는 PDF로 변환 후 업로드해주세요.');
    inp.value=''; return;
  }
  STATE.drawingType=ext==='pdf'?'pdf':'dxf';
  STATE.dxfFile=f; STATE.pdfFile=ext==='pdf'?f:null;
  el('cardDxf').classList.add('done');
  const info=el('dxfInfo');
  info.innerHTML=`<strong>${escHtml(f.name)}</strong><br>형식: ${ext.toUpperCase()} / 파싱 가능`;
  info.classList.add('show');
  if(ext==='dxf'){
    readDxfTextSmart(f).then(res=>{
      STATE.dxfText=res.text;
      STATE.dxfEncoding=res.enc;
      STATE.dxfDecodeScore=res.score;
      const bad=(res.text.match(/\uFFFD/g)||[]).length;
      info.innerHTML=`<strong>${escHtml(f.name)}</strong><br>형식: DXF / 파싱 가능<br>디코딩: ${escHtml(res.enc)} / 깨진문자: ${bad}`;
      renderDXFPreview();
      checkReady();
    }).catch(err=>{
      showAlert('DXF 업로드 실패','DXF 텍스트 디코딩 중 오류가 발생했습니다.\n'+(err?.message||String(err)));
      inp.value='';
      setDXFPreviewEmpty('DXF 미리보기를 생성할 수 없습니다: '+(err?.message||String(err)));
    });
  } else {
    STATE.dxfText='';
    setDXFPreviewEmpty('PDF 파일은 현재 DXF 도면 미리보기 대상이 아닙니다.');
    checkReady();
  }
}

async function onXlsxFile(inp){
  const f=inp.files[0]; if(!f) return;

  // ── 진단 상태 초기화
  const _diag={step:'init',file:f.name,size:f.size};
  const _fail=(step,label,e)=>{
    _diag.step=step;
    console.error('[XLSX_UPLOAD_FAIL]',step,e);
    showAlert('XLSX 업로드 실패 — '+step,
      '[파일명] '+f.name+'\n[단계] '+label+'\n[오류] '+(e?.stack||e?.message||String(e)));
  };

  console.log('[XLSX_UPLOAD] 01 file selected', f.name, f.size);
  console.log('[XLSX_UPLOAD] 02 ExcelJS type', typeof ExcelJS);
  console.log('[XLSX_UPLOAD] 03 XLSX type', typeof XLSX);

  // A. 라이브러리 확인
  if(typeof XLSX==='undefined'){
    _fail('A_SHEETJS_UNDEFINED','SheetJS(XLSX) 미로드',new Error('XLSX is undefined'));
    return;
  }
  if(typeof ExcelJS==='undefined'){
    _fail('B_EXCELJS_UNDEFINED','ExcelJS 미로드',new Error('ExcelJS is undefined'));
    return;
  }

  // B. arrayBuffer
  let originalBuf;
  try{
    originalBuf=await f.arrayBuffer();
    console.log('[XLSX_UPLOAD] 04 arrayBuffer loaded', originalBuf.byteLength);
  }catch(e){_fail('C_ARRAYBUFFER','파일 읽기(arrayBuffer)',e);return;}
  if(!originalBuf||originalBuf.byteLength<100){
    _fail('C_ARRAYBUFFER_EMPTY','파일 크기 부족',new Error('byteLength='+originalBuf?.byteLength));return;
  }

  // C. SheetJS read
  let wb;
  try{
    console.log('[XLSX_UPLOAD] 05 SheetJS read start');
    wb=XLSX.read(new Uint8Array(originalBuf),{type:'array',cellStyles:true,cellNF:true,sheetStubs:true});
    console.log('[XLSX_UPLOAD] 06 SheetJS read success', wb.SheetNames);
  }catch(e){_fail('D_SHEETJS_READ','SheetJS XLSX.read',e);return;}
  if(!wb||!wb.SheetNames||!wb.SheetNames.length){
    _fail('D_SHEETJS_NO_SHEET','시트 없음',new Error('SheetNames empty'));return;
  }

  // D. TemplateSanitizer detect
  let sanitResult;
  try{
    sanitResult=TemplateSanitizer.detect(wb);
    console.log('[XLSX_UPLOAD] 07 TemplateSanitizer detect', JSON.stringify(sanitResult).substring(0,120));
  }catch(e){_fail('E_SANITIZER_DETECT','TemplateSanitizer.detect',e);return;}

  console.log('[XLSX_UPLOAD] 08 sanitize required', sanitResult.hasMarkers);

  // E. sanitize or passthrough
  let effectiveBuf;
  if(sanitResult.hasMarkers){
    // E1. sanitizeWorkbook
    try{
      wb=TemplateSanitizer.sanitizeWorkbook(wb);
    }catch(e){_fail('F_SANITIZE_WB','TemplateSanitizer.sanitizeWorkbook',e);return;}
    // E2. XLSX.write — 실패 시 fallback 없음
    try{
      const arr=XLSX.write(wb,{bookType:'xlsx',type:'array',cellStyles:true});
      effectiveBuf=arr instanceof ArrayBuffer ? arr : new Uint8Array(arr).buffer;
    }catch(e){
      _fail('G_XLSX_WRITE','XLSX.write(sanitized wb)',e);
      inp.value=''; return;
    }
    // E3. 재감지 검증
    try{
      const wb2=XLSX.read(new Uint8Array(effectiveBuf),{type:'array'});
      const rechk=TemplateSanitizer.detect(wb2);
      if(rechk.hasMarkers) console.warn('[XLSX_UPLOAD] sanitize 후 마커 잔류:', rechk.markerCount);
    }catch(e){console.warn('[XLSX_UPLOAD] 재감지 실패(무시):', e.message);}
  }else{
    effectiveBuf=originalBuf;
  }

  try{
    const bLen=effectiveBuf instanceof ArrayBuffer?effectiveBuf.byteLength:(effectiveBuf.length||effectiveBuf.byteLength||0);
    console.log('[XLSX_UPLOAD] 09 effectiveBuf ready', bLen);
  }catch(e){}

  // F. STATE 저장
  STATE.xlsxOriginalBuffer=originalBuf;
  STATE.xlsxBuffer=effectiveBuf;
  STATE.workbook=wb;
  STATE.xlsxFile=f;
  STATE.dataSheetName=wb.SheetNames[0];
  STATE.templateSanitized=sanitResult.hasMarkers;
  STATE.templateSanitizerReport=sanitResult;
  console.log('[XLSX_UPLOAD] 12 STATE saved', !!STATE.xlsxBuffer);

  // G. ExcelJS load
  console.log('[XLSX_UPLOAD] 10 ExcelJS load start');
  try{
    const buf4ej=effectiveBuf instanceof ArrayBuffer
      ? effectiveBuf
      : (effectiveBuf.buffer||effectiveBuf);
    const ejWb=new ExcelJS.Workbook();
    await ejWb.xlsx.load(buf4ej);
    STATE.workbookObj=ejWb;
    STATE.exceljsTemplate=ejWb;
    console.log('[XLSX_UPLOAD] 11 ExcelJS load success');
    // H. TemplateDependencyScanner
    try{STATE.depScanResult=TemplateDependencyScanner.scan(ejWb);}catch(e){console.warn('[XLSX_UPLOAD] depScan 실패(무시):',e.message);}
  }catch(e){
    // ExcelJS 실패는 경고로 표시하되 STATE.xlsxBuffer는 이미 설정됨 — 부분 성공
    console.error('[XLSX_UPLOAD] ExcelJS load 실패:', e);
    showAlert('ExcelJS 워크북 로드 부분 실패',
      'XLSX 파일은 읽었지만 ExcelJS 워크북 로드에서 실패했습니다.\n이 문제는 파일 선택 문제가 아니라 ExcelJS 호환성 또는 생성된 버퍼 문제입니다.\n\n오류: '+e.message+'\n\n⚠ 다운로드 기능은 제한될 수 있습니다. 분석은 계속 진행 가능합니다.');
    // 부분 성공 처리 — workbookObj 없이도 analyzeBtn 활성화는 가능
  }

  // H. UI 표시
  const sheets=wb.SheetNames;
  let infoHtml=`<strong>${escHtml(f.name)}</strong>`;
  infoHtml+=`<br>시트: ${sheets.length}개 (${escHtml(sheets.slice(0,4).join(', '))})`;
  infoHtml+=`<br>주시트: ${escHtml(STATE.dataSheetName)}`;
  if(sanitResult.hasMarkers){
    infoHtml+=`<br><span style="color:var(--c-rev)">⚠ 빨간번호 마커 ${sanitResult.markerCount}개 감지</span>`;
    infoHtml+=`<br><span style="color:var(--c-ok)">✅ 자동 공란화 완료</span>`;
    infoHtml+=`<br><span style="color:var(--c-ok)">✅ sanitized buffer 적용</span>`;
    if(STATE.workbookObj) infoHtml+=`<br><span style="color:var(--c-ok)">✅ ExcelJS 로드 완료</span>`;
  }else{
    infoHtml+=`<br><span style="color:var(--c-ok)">✅ 빨간번호 마커 없음</span>`;
    if(STATE.workbookObj) infoHtml+=`<br><span style="color:var(--c-ok)">✅ ExcelJS 로드 완료</span>`;
  }
  try{
    el('xlsxInfo').innerHTML=infoHtml;
    el('xlsxInfo').classList.add('show');
    el('cardXlsx').classList.add('done');
    console.log('[XLSX_UPLOAD] 13 UI updated');
  }catch(e){console.error('[XLSX_UPLOAD] UI 업데이트 실패:',e);}

  // I. checkReady
  try{checkReady(); console.log('[XLSX_UPLOAD] 14 checkReady complete', !el('analyzeBtn')?.disabled);}
  catch(e){console.error('[XLSX_UPLOAD] checkReady 실패:',e);}
}


