function decodeDXFText(buf) {
  let text;
  try {
    text = new TextDecoder('utf-8').decode(buf);
    if (text.includes('\uFFFD')) throw 0;
  } catch {
    try { text = new TextDecoder('euc-kr').decode(buf); }
    catch { text = new TextDecoder('windows-1252').decode(buf); }
  }
  return text;
}

function showDrawingTypeInfo(msg, type) {
  const el = document.getElementById('drawingTypeInfo');
  if (!el) return;
  el.style.display = 'block';
  el.textContent = msg;
  if (type === 'pdf') {
    el.style.background = 'rgba(59,130,246,0.1)';
    el.style.color = 'var(--text)';
    el.style.border = '1px solid rgba(59,130,246,0.3)';
  } else if (type === 'dwf') {
    el.style.background = 'rgba(234,88,12,0.08)';
    el.style.color = 'var(--c-match)';
    el.style.border = '1px solid rgba(234,88,12,0.3)';
  } else {
    el.style.background = 'rgba(0,0,0,0.04)';
    el.style.color = 'var(--text-dim)';
    el.style.border = '1px solid var(--border)';
  }
}

function showDWFPlaceholder() {
  const empty = document.getElementById('dxfEmpty');
  if (empty) empty.textContent = 'DWF 파일 업로드됨 — 직접 파싱 후속 구현 예정. 벡터 PDF 또는 DXF 변환 후 재업로드를 권장합니다.';
  const canvas = document.getElementById('dxfCanvas');
  if (canvas) canvas.style.display = 'none';
}

// ── 분석 엔진 ────────────────────────────────────────────────
function normSpec(s){return String(s).replace(/\s+/g,'').toUpperCase();}
function findRef(zone,spec){
  const sn=normSpec(spec);
  return STATE.refDb.find(r=>normSpec(r.spec)===sn&&r.drawingZone===zone)||STATE.refDb.find(r=>normSpec(r.spec)===sn)||null;
}

function getResultType(spec,method){
  const s=spec.toUpperCase().replace(/\s/g,''), m=(method||'').toUpperCase();
  if(/현합|HELICOIL|헬리컬/.test(m+s)) return 'FIXED_TEXT_RESULT';
  if(/T\.P\.G|TPG/.test(m)) return 'FIXED_TEXT_RESULT';
  if(/C\.G|C\.GAGE|CGAGE/.test(m)) return 'FIXED_TEXT_RESULT';
  if(/R\.D\.G|RDG|P\.P\.J|PPJ/.test(m)) return 'FIXED_TEXT_RESULT';
  if(/C\.O\.A|COA/.test(m)||/NOTE/i.test(s)) return 'ACCEPT_RESULT';
  if(/^\(.*\)$/.test(spec.trim())) return 'REFERENCE_RESULT';
  if(/^\d+[Xx×].*(Ø|깊이|[Rr]\d|[Cc]\d)/.test(s)) return 'MULTI_RANGE_RANDOM_RESULT';
  return 'RANGE_RANDOM_RESULT';
}
function getFixedText(spec,method){
  const m=(method||'').toUpperCase(),s=spec||'';
  if(/현합|헬리컬/.test(m+s)) return '현합검사양호';
  if(/T\.P\.G|TPG/.test(m)) return 'T.P.G 검사양호';
  if(/C\.G|C\.GAGE/.test(m)) return 'C.Gage 검사양호';
  if(/R\.D\.G|RDG/.test(m)) return 'R.Gage 검사양호';
  if(/P\.P\.J|PPJ/.test(m)) return 'P.P.J 검사양호';
  return 'ACCEPT';
}
function parseTol(tol){const m=(tol||'').match(/[±±]\s*([\d.]+)/);return m?parseFloat(m[1]):0.2;}
function extractNominal(spec){
  let s=spec.trim().replace(/\s+/g,'');
  if(s.startsWith('(')&&s.endsWith(')'))s=s.slice(1,-1);
  s=s.replace(/^\d+[Xx×]/,'').replace(/^[Øøφ]/,'').replace(/^깊이/,'').replace(/^[RrCc]/,'');
  const m=s.match(/([\d]+\.?[\d]*)/);return m?parseFloat(m[1]):null;
}
function getDec(spec){const m=spec.match(/\.([\d]+)/);return m?m[1].length:1;}
function hashStr(s){let h=0x811c9dc5;for(let i=0;i<s.length;i++)h=Math.imul(h^s.charCodeAt(i),0x01000193);return h>>>0;}
function detRand(seed,min,max,dec){
  const h=hashStr(seed),t=h^(h>>>16),u=Math.imul(t,0x45d9f3b),v=(u^(u>>>16))>>>0;
  return parseFloat((min+(max-min)*(v/4294967295)).toFixed(dec+1));
}
// v0.4.0: rangeRandVal — use Math.random() when generationRunId>0 (each export run gets new values)
// Replaces detRand(seed, min, max, dec) for RANGE_RANDOM_RESULT items.
// FIXED_TEXT_RESULT / ACCEPT_RESULT always use deterministic path.
function rangeRandVal(seed, min, max, dec){
  let val;
  if(STATE && STATE.generationRunId > 0){
    // True random — new value each export run
    val = min + Math.random()*(max - min);
  } else {
    val = detRand(seed, min, max, dec);
    return val;  // detRand already handles rounding
  }
  if(dec != null) val = parseFloat(val.toFixed(dec));
  return val;
}

function genResult(inum,spec,method,tol,drawNo){
  drawNo=drawNo||STATE.drawingNo;
  const rt=getResultType(spec,method),seed=`${drawNo}-${inum}-${spec}`;
  if(rt==='FIXED_TEXT_RESULT') return {resultType:rt,generatedResult:getFixedText(spec,method),resultSourceType:'FIXED_RULE_TEXT',generationRule:'FIXED_RULE',seed,min:null,max:null};
  if(rt==='ACCEPT_RESULT') return {resultType:rt,generatedResult:'ACCEPT',resultSourceType:'ACCEPT_RULE_TEXT',generationRule:'ACCEPT_RULE',seed,min:null,max:null};
  const tolV=parseTol(tol),nom=extractNominal(spec);
  if(rt==='REFERENCE_RESULT'){
    return {resultType:rt,generatedResult:nom!=null?String(nom):'—',resultSourceType:'REFERENCE_RESULT',generationRule:'REFERENCE_NOMINAL',seed,min:null,max:null};
  }
  if(nom===null) return {resultType:'NON_MEASURABLE_NOTE',generatedResult:'',resultSourceType:'NO_RESULT_OUTPUT',generationRule:'NO_NUMERIC_NOMINAL_SKIP_OUTPUT',seed,min:null,max:null};
  const dec=getDec(spec),half=tolV*0.75;
  const minV=parseFloat((nom-half).toFixed(dec+1)),maxV=parseFloat((nom+half).toFixed(dec+1));
  if(rt==='MULTI_RANGE_RANDOM_RESULT'){
    const nm=spec.replace(/\s/g,'').match(/^(\d+)[Xx×]/),n=nm?parseInt(nm[1]):1;
    const vals=Array.from({length:n},(_,i)=>rangeRandVal(seed+'_'+i,minV,maxV,dec+1));
    const result=n>1?`${Math.min(...vals).toFixed(dec+1)}~${Math.max(...vals).toFixed(dec+1)}`:String(vals[0]);
    return {resultType:rt,generatedResult:result,resultSourceType:'GENERATED_WITHIN_TOLERANCE',generationRule:'MULTI_RANGE_RANDOM_SEED',seed,min:minV,max:maxV};
  }
  return {resultType:rt,generatedResult:String(rangeRandVal(seed,minV,maxV,dec+1)),resultSourceType:'GENERATED_WITHIN_TOLERANCE',generationRule:'RANGE_RANDOM_SEED',seed,min:minV,max:maxV};
}

function recalcItemStatus(dxfSourceMap){
  dxfSourceMap=dxfSourceMap||STATE.dxfSourceMap||{};
  const out=[];
  for(const z of Z_ITEMS_EMBEDDED){
    const inum=z.inum; let spec=z.spec,tol=z.tol||'',meth=z.meth||'',zone=z.zone||'';
    const dxfSrc=dxfSourceMap[inum];
    const ref=findRef(zone,spec);
    if(!tol&&ref)tol=ref.tolerance||''; if(!meth&&ref)meth=ref.method1||'';
    let srcType,matchMethod='NOT_FOUND',matchConf=0,srcObjId='',srcRaw='',srcLayer='',srcX=0,srcY=0;
    if(dxfSrc&&dxfSrc.matchConfidence>=0.80){
      srcType='DXF_CONFIRMED';matchMethod=dxfSrc.matchMethod;matchConf=dxfSrc.matchConfidence;
      srcObjId=dxfSrc.objectId;srcRaw=dxfSrc.rawText;srcLayer=dxfSrc.layer||'';
      srcX=dxfSrc.x||0;srcY=dxfSrc.y||0;
    }else if(ref){
      srcType='REFERENCE_SPEC_DATABASE';matchMethod='REFERENCE_ONLY';matchConf=1.0;
    }else{
      srcType='MISSING';matchMethod='NOT_FOUND';matchConf=0;
    }
    const res=genResult(inum,spec,meth,tol);
    // MISSING → ACCEPT_RESULT 처리
    if(srcType==='MISSING'){
      srcType='REFERENCE_SPEC_DATABASE';
      if(res.resultType==='REVIEW_REQUIRED'){
        res.resultType='ACCEPT_RESULT';res.generatedResult='ACCEPT';res.resultSourceType='ACCEPT_RULE_TEXT';
      }
    }
    const status=(res.resultType==='NON_MEASURABLE_NOTE'?'NOTE_SKIPPED'
      :srcType==='DXF_CONFIRMED'?'REAL_DATA_COMPLETE'
      :res.resultType==='FIXED_TEXT_RESULT'?'FIXED_RESULT_COMPLETE'
      :res.resultType==='ACCEPT_RESULT'?'FIXED_RESULT_COMPLETE'
      :res.resultType==='REFERENCE_RESULT'?'REFERENCE_SPEC_GENERATED'
      :res.resultType==='REVIEW_REQUIRED'?'REVIEW_REQUIRED'
      :'REFERENCE_SPEC_GENERATED');
    const outRow=mainResultRowForInum(inum);
    const form3Row=form3ResultRowForInum(inum);
    out.push({
      inum,drawingZone:zone,referenceSpec:spec,finalSpec:spec,
      specSourceType:srcType,sourceRawText:srcRaw,sourceObjectId:srcObjId,
      sourceLayer:srcLayer,sourceX:srcX,sourceY:srcY,
      matchMethod,matchConfidence:matchConf,
      tol,method:meth,
      resultType:res.resultType,generatedResult:res.generatedResult,
      resultSourceType:res.resultSourceType,generationRule:res.generationRule,
      seed:res.seed,minValue:res.min,maxValue:res.max,
      outputSheet:'80871631',outputCell:outRow?`80871631!I${outRow}`:'',
      form3Cell:form3Row?`80871631-3!E${form3Row}`:'',status,note:'',
    });
  }
  STATE.itemStatus=out;
}

// ── 분석 실행 ─────────────────────────────────────────────────
const PROG_STAGES=[
  '파일 읽기','도면 파싱','치수 후보 추출','검번 후보 추출',
  'DXF 원천 매칭','기준DB 보완','결과값 생성','양식 매핑 검증','UI 렌더링 완료'
];

function initProgStages(){
  const cont=el('progStages'); if(!cont) return;
  cont.innerHTML=PROG_STAGES.map((s,i)=>`
    <div class="prog-row" id="pr${i}">
      <div class="prog-label">${s}</div>
      <div class="prog-bar-wrap"><div class="prog-bar-fill" id="pb${i}" style="width:0%"></div></div>
      <div class="prog-pct" id="pp${i}">0%</div>
    </div>
  `).join('');
}

function setStageProgress(idx,pct){
  const pb=el('pb'+idx),pp=el('pp'+idx); if(!pb||!pp)return;
  pb.style.width=pct+'%';
  if(pct>=100)pb.classList.add('done');
  pp.textContent=pct+'%';
  // 전체 진행률
  let total=0;
  PROG_STAGES.forEach((_,i)=>{const e=el('pb'+i);if(e)total+=parseFloat(e.style.width||0);});
  const totalPct=Math.round(total/PROG_STAGES.length);
  setEl('totalPct',totalPct+'%');
}

async function runAnalysis(){
  if(!(STATE.xlsxBuffer&&(STATE.dxfText||STATE.pdfFile))){
    checkReady();
    showAlert('분석 시작 불가','도면 파일(DXF/PDF)과 빈 검사성적서 XLSX 양식을 모두 업로드해야 분석을 시작할 수 있습니다.');
    return;
  }
  STATE.analysisRun=false;
  goStep(2,true); initProgStages();
  await sleep(50);
  try{
    // 1. 파일 읽기
    setStageProgress(0,100); await sleep(50);
    // 2. 도면 파싱
    if(STATE.drawingType==='dxf'&&STATE.dxfText){
      const raw=DXFParser.parse(STATE.dxfText);
      STATE.entities=raw;
      setStageProgress(1,100);
      // 3. 치수 후보
      STATE.parsedCands=DXFParser.extractDimCandidates(raw);
      const NOISE_LAYERS=new Set(['2-text','Template form 2','Template form 1',
        'del_Template_form_2','del_Suplier','Suplier','Template_form_2','Template_form_3','Template form 3']);
      STATE.parsedNoise=raw.filter(e=>NOISE_LAYERS.has(e.layer));
      setStageProgress(2,100);
      // 4. 검번 후보
      STATE.inumCands=(typeof DXFParser.extractItemNumCandidates==='function'
        ? DXFParser.extractItemNumCandidates(raw)
        : DXFParser.extractInumCandidates(raw));
      setStageProgress(3,100);
      // 5. DXF 원천 매칭
      STATE.dxfSourceMap=DXFSourceMatcher.matchAll(raw,Z_ITEMS_EMBEDDED);
    }else if(STATE.drawingType==='pdf'&&STATE.pdfFile){
      setStageProgress(1,50);
      const buf=await STATE.pdfFile.arrayBuffer();
      const doc=await PDFVectorParser.loadPDF(buf);
      STATE.pdfExtracted=await PDFVectorParser.extractAllPages(doc);
      STATE.pdfDimensions=PDFDimExtractor.extractAll(STATE.pdfExtracted.textItems || []);
      STATE.pdfBalloons=PDFBalloonExtractor.extractAll(STATE.pdfExtracted.textItems || [], STATE.pdfExtracted.shapes || []);
      STATE.pdfMapping=PDFLeaderMatcher.matchAll(STATE.pdfBalloons,STATE.pdfDimensions,STATE.pdfExtracted.paths || []);
      STATE.entities=STATE.pdfExtracted.textItems||[];
      STATE.dxfSourceMap={};
      if(doc && typeof doc.destroy==='function') { try{ await doc.destroy(); }catch(_e){} }
      setStageProgress(1,100);setStageProgress(2,100);setStageProgress(3,100);
    }else{
      [1,2,3].forEach(i=>setStageProgress(i,100));
    }
    setStageProgress(4,100); await sleep(30);
    // 6. 기준DB 보완 + 결과값 생성
    recalcItemStatus(STATE.dxfSourceMap);
    if(STATE.drawingType==='dxf') generateAutoNumberingFromItems(true);
    setStageProgress(5,100);setStageProgress(6,100); await sleep(30);
    // 7. 양식 분석
    if(STATE.workbook){
      const ws0=STATE.workbook.Sheets[STATE.dataSheetName];
      let mx=0;
      for(let r=1;r<=200;r++){const c=ws0['A'+r];if(c&&!isNaN(parseInt(c.v)))mx=Math.max(mx,parseInt(c.v));}
      STATE.requiredRowCount=mx||112;
    }
    setStageProgress(7,100); await sleep(30);
    // 8. UI
    updateAnalysisStats();
    setStageProgress(8,100);
    STATE.analysisRun=true;
    el('dlXlsxBtn').disabled=false;
    updatePdfDownloadReadyState(); // v0.4.0E: PDF btn activated only when 112 items + coords ready
    el('dlReportBtn').disabled=false;
    el('dlLogBtn').disabled=false;
    if(STATE.drawingType==='dxf')renderDXFPreview();
  }catch(err){
    showAlert('분석 오류',err.message+'\n'+(err.stack||'').substring(0,200));
  }
}

async function waitForPDFJS(){
  if(window._pdfjsReady&&window.pdfjsLib)return window.pdfjsLib;
  return new Promise((res,rej)=>{
    let t=0;const iv=setInterval(()=>{t+=100;
      if(window._pdfjsReady&&window.pdfjsLib){clearInterval(iv);res(window.pdfjsLib);}
      if(t>8000){clearInterval(iv);rej(new Error('PDF.js timeout'));}
    },100);
  });
}

// ── 분석 통계 업데이트 ────────────────────────────────────────
function updateAnalysisStats(){
  const ents=STATE.entities, cands=STATE.parsedCands, noise=STATE.parsedNoise, inum=STATE.inumCands;
  const its=STATE.itemStatus;
  const dxfCnt=its.filter(i=>i.specSourceType==='DXF_CONFIRMED').length;
  const refCnt=its.filter(i=>i.specSourceType==='REFERENCE_SPEC_DATABASE').length;
  const genCnt=its.filter(i=>i.resultType==='RANGE_RANDOM_RESULT'||i.resultType==='MULTI_RANGE_RANDOM_RESULT').length;
  const fixCnt=its.filter(i=>i.resultType==='FIXED_TEXT_RESULT'||i.resultType==='ACCEPT_RESULT').length;
  const revCnt=its.filter(i=>i.resultType==='REVIEW_REQUIRED').length;
  const misCnt=its.filter(i=>i.status==='MISSING_SPEC').length;

  const stats=[
    ['도면 객체 총수', ents.length||DXF_CANDS_EMBEDDED.length],
    ['TEXT', ents.filter(e=>e.type==='TEXT').length||(DXF_CANDS_EMBEDDED.filter(c=>c.type==='TEXT').length)],
    ['MTEXT', ents.filter(e=>e.type==='MTEXT').length||(DXF_CANDS_EMBEDDED.filter(c=>c.type==='MTEXT').length)],
    ['치수/규격 후보', cands.length||STATE.parsedCands.length||DXF_CANDS_EMBEDDED.filter(c=>c.role==='SPEC_TEXT').length],
    ['검번 후보', inum.length||DXF_CANDS_EMBEDDED.filter(c=>c.role==='INUM_CANDIDATE').length],
    ['노이즈/제외', noise.length||DXF_RAW_SAMPLE.filter(o=>o.isNoise).length],
    ['성적서 필요', 112],
    ['DXF 원천 기반', dxfCnt],
    ['기준DB 기반', refCnt],
    ['범위 생성값', genCnt],
    ['고정 결과', fixCnt],
    ['검토 필요', revCnt],
    ['생성 불가', misCnt],
  ];
  const grid=el('analysisStats'); if(!grid)return;
  grid.innerHTML=stats.map(([lbl,val])=>
    `<div class="stat-item"><div class="stat-val" style="${lbl==='DXF 원천 기반'?'color:var(--c-dxf)':lbl==='기준DB 기반'?'color:var(--c-ref)':lbl==='성적서 필요'?'color:var(--text)':lbl==='생성 불가'?'color:var(--c-miss)':''}">
      ${val}</div><div class="stat-lbl">${lbl}</div></div>`
  ).join('');
}

// ── 완성도 ────────────────────────────────────────────────────
function renderCompleteness(){
  const its=STATE.itemStatus,tot=its.length;
  const dxf=its.filter(i=>i.specSourceType==='DXF_CONFIRMED').length;
  const ref=its.filter(i=>i.specSourceType==='REFERENCE_SPEC_DATABASE').length;
  const gen=its.filter(i=>i.resultType==='RANGE_RANDOM_RESULT'||i.resultType==='MULTI_RANGE_RANDOM_RESULT').length;
  const fix=its.filter(i=>i.resultType==='FIXED_TEXT_RESULT'||i.resultType==='ACCEPT_RESULT'||i.resultType==='REFERENCE_RESULT').length;
  const rev=its.filter(i=>i.resultType==='REVIEW_REQUIRED').length;
  const mis=its.filter(i=>i.status==='MISSING_SPEC').length;

  const bar=el('compBar');
  if(bar){
    bar.innerHTML=[
      [dxf,'var(--c-dxf)','DXF'],[ref-fix,'var(--c-ref)','DB'],
      [fix,'var(--c-fixed)','고정'],[rev,'var(--c-rev)','검토'],
      [mis,'var(--c-miss)','불가'],
    ].filter(([c])=>c>0).map(([c,col,lbl])=>
      `<div class="comp-seg" style="width:${(c/tot*100).toFixed(1)}%;background:${col}" title="${lbl}:${c}">${c/tot>0.05?c:''}</div>`
    ).join('');
  }
  const cards=el('compCards');if(!cards)return;
  const defs=[
    ['cc-dxf','var(--c-dxf)',dxf,'DXF 원천 항목','DXF_CONFIRMED'],
    ['cc-ref','var(--c-ref)',ref,'기준DB 보완 항목','REFERENCE_SPEC_DATABASE'],
    ['cc-gen','var(--c-gen)',gen,'범위 생성값','RANGE_RANDOM_RESULT'],
    ['cc-fixed','var(--c-fixed)',fix,'고정 결과 항목','FIXED_TEXT_RESULT'],
    ['cc-rev','var(--c-rev)',rev,'검토 필요 항목','REVIEW_REQUIRED'],
    ['cc-miss','var(--c-miss)',mis,'생성 불가','MISSING'],
  ];
  cards.innerHTML=defs.map(([cls,col,cnt,lbl,f])=>`
    <div class="comp-card ${cls}" style="border-left:3px solid ${col}" onclick="setItemFilter(null,'${f}');goStep(4)">
      <div class="cc-num" style="color:${col}">${cnt}</div>
      <div class="cc-lbl">${lbl}</div>
      <div class="cc-pct" style="color:${col}">${(cnt/tot*100).toFixed(0)}%</div>
    </div>
  `).join('');
}

// ── 항목 테이블 ────────────────────────────────────────────────
function setItemFilter(btn,f){
  itemFilter=f;
  if(btn){document.querySelectorAll('#itemChips .chip').forEach(b=>b.classList.remove('active'));btn.classList.add('active');}
  renderItems();
}
function filterItems(){itemSearch=(el('itemSearch')?.value||'').toLowerCase();renderItems();}
function renderItems(){
  let its=STATE.itemStatus;
  if(itemFilter!=='all'){
    if(['DXF_CONFIRMED','REFERENCE_SPEC_DATABASE'].includes(itemFilter)) its=its.filter(i=>i.specSourceType===itemFilter);
    else if(itemFilter==='RANGE_RANDOM_RESULT') its=its.filter(i=>i.resultType==='RANGE_RANDOM_RESULT'||i.resultType==='MULTI_RANGE_RANDOM_RESULT');
    else its=its.filter(i=>i.resultType===itemFilter);
  }
  if(itemSearch) its=its.filter(i=>String(i.inum).includes(itemSearch)||(i.drawingZone||'').toLowerCase().includes(itemSearch)||(i.finalSpec||'').toLowerCase().includes(itemSearch));
  setEl('itemCnt',its.length+'개');
  const tb=el('itemTbody');if(!tb)return;
  tb.innerHTML=its.map(it=>`
    <tr onclick="showDetail(${it.inum})">
      <td style="font-weight:700;color:var(--accent)">${it.inum}</td>
      <td style="font-family:monospace;font-size:11px">${it.drawingZone||''}</td>
      <td style="max-width:130px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap;font-size:12px" title="${it.finalSpec}">${it.finalSpec}</td>
      <td style="font-family:monospace;font-size:11px">${it.tol||'—'}</td>
      <td style="font-size:11px;max-width:80px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${it.method}">${(it.method||'').split('(')[0].trim()}</td>
      <td style="font-family:Consolas,'Malgun Gothic',monospace;font-weight:700;color:var(--c-ok)">${escHtml(it.generatedResult||'—')}</td>
      <td>${srcBdg(it.specSourceType)}</td>
      <td>${rtBdg(it.resultType)}</td>
      <td>${stsBdg(it.status)}</td>
    </tr>
  `).join('');
}

