function srcBdg(t){
  return {'DXF_CONFIRMED':'<span class="bdg bdg-dxf">DXF 원천</span>',
           'REFERENCE_SPEC_DATABASE':'<span class="bdg bdg-ref">기준DB 보완</span>',
           'MISSING':'<span class="bdg bdg-miss">MISSING</span>',
  }[t]||`<span class="bdg bdg-noise">${t}</span>`;
}
function rtBdg(t){
  return {'RANGE_RANDOM_RESULT':'<span class="bdg bdg-gen">범위 생성</span>',
           'MULTI_RANGE_RANDOM_RESULT':'<span class="bdg bdg-gen">복수 범위</span>',
           'FIXED_TEXT_RESULT':'<span class="bdg bdg-fixed">고정 문구</span>',
           'ACCEPT_RESULT':'<span class="bdg bdg-fixed">ACCEPT</span>',
           'REFERENCE_RESULT':'<span class="bdg bdg-ref_result">참조값</span>',
           'REVIEW_REQUIRED':'<span class="bdg bdg-rev">검토 필요</span>',
  }[t]||`<span class="bdg bdg-noise">${t}</span>`;
}
function stsBdg(s){
  return {'REAL_DATA_COMPLETE':'<span class="bdg bdg-dxf">완료</span>',
           'REFERENCE_SPEC_GENERATED':'<span class="bdg bdg-ref">기준DB</span>',
           'FIXED_RESULT_COMPLETE':'<span class="bdg bdg-fixed">고정값</span>',
           'REVIEW_REQUIRED':'<span class="bdg bdg-rev">검토필요</span>',
           'MISSING_SPEC':'<span class="bdg bdg-miss">생성불가</span>',
  }[s]||`<span class="bdg bdg-noise">${s}</span>`;
}

