// ── DXF 미리보기 ─────────────────────────────────────────────
function setDXFPreviewEmpty(msg){
  const wrap=el('dxfPreviewCanvasWrap'); if(!wrap) return;
  wrap.classList.remove('collapsed');
  wrap.innerHTML=`<div class="dxf-preview-empty" id="dxfPreviewEmpty">${escHtml(msg||'DXF 파일을 업로드하면 이 영역에 도면 미리보기가 표시됩니다.')}</div>`;
  setEl('dxfPreviewStatus',msg||'DXF 파일을 업로드하면 이 영역에 도면 미리보기가 표시됩니다.');
  setEl('dxfPreviewFile',STATE.dxfFile?STATE.dxfFile.name:'파일 없음');
  setEl('dxfPreviewCount','엔티티 0');
  setEl('dxfPreviewBounds','범위 -');
  renderDXFNumberingUI();
}
function dxfPreviewNum(v){const n=parseFloat(v);return Number.isFinite(n)?n:null;}
function dxfPreviewCleanText(v){
  return DXFParser.cleanText(String(v||'')).replace(/\s+/g,' ').trim();
}
function parseDXFPreviewEntities(text){
  const lines=String(text||'').split(/\r?\n/);
  const entities=[];
  let i=0,inEntities=false,currentPolyline=null;
  const finishPolyline=()=>{
    if(currentPolyline&&currentPolyline.points.length>1) entities.push(currentPolyline);
    currentPolyline=null;
  };
  while(i<lines.length-1){
    const code=lines[i].trim(), value=lines[i+1].trim();
    if(code==='0'&&value==='SECTION'){i+=2;continue;}
    if(value==='ENTITIES'){inEntities=true;i+=2;continue;}
    if(inEntities&&code==='0'&&value==='ENDSEC'){finishPolyline();break;}
    if(!inEntities||code!=='0'){i+=2;continue;}
    const type=value;
    let j=i+2, layer='', closed=false, textValue='';
    const points=[], e={type,layer:''};
    while(j<lines.length-1){
      const c=lines[j].trim(), v=lines[j+1].trim();
      if(c==='0') break;
      if(c==='8') layer=v;
      else if(c==='10'){
        const x=dxfPreviewNum(v), y=dxfPreviewNum(lines[j+3]);
        if(lines[j+2]&&lines[j+2].trim()==='20'&&x!==null&&y!==null) points.push({x,y});
        e.x=x;
      }else if(c==='20') e.y=dxfPreviewNum(v);
      else if(c==='11') e.x2=dxfPreviewNum(v);
      else if(c==='21') e.y2=dxfPreviewNum(v);
      else if(c==='40') e.r=dxfPreviewNum(v);
      else if(c==='50') e.a1=dxfPreviewNum(v);
      else if(c==='51') e.a2=dxfPreviewNum(v);
      else if(c==='70') closed=(parseInt(v,10)&1)===1;
      else if(c==='1'||c==='3') textValue+=v;
      j+=2;
    }
    e.layer=layer;
    if(type==='POLYLINE'){finishPolyline();currentPolyline={type:'POLYLINE',layer,points:[],closed:false};}
    else if(type==='VERTEX'&&currentPolyline&&e.x!==null&&e.y!==null){currentPolyline.points.push({x:e.x,y:e.y});}
    else if(type==='SEQEND'){finishPolyline();}
    else if(type==='LINE'&&e.x!==null&&e.y!==null&&e.x2!==null&&e.y2!==null){entities.push(e);}
    else if((type==='CIRCLE'||type==='ARC')&&e.x!==null&&e.y!==null&&e.r!==null){entities.push(e);}
    else if(type==='LWPOLYLINE'&&points.length>1){entities.push({type,layer,points,closed});}
    else if((type==='TEXT'||type==='MTEXT'||type==='DIMENSION'||type==='ATTRIB')&&e.x!==null&&e.y!==null){
      const cleaned=dxfPreviewCleanText(textValue);
      if(cleaned) entities.push({...e,text:cleaned});
    }
    i=Math.max(j,i+2);
  }
  finishPolyline();
  return entities;
}
function getDXFPreviewBounds(entities){
  let minX=Infinity,minY=Infinity,maxX=-Infinity,maxY=-Infinity;
  const add=(x,y)=>{if(Number.isFinite(x)&&Number.isFinite(y)){minX=Math.min(minX,x);minY=Math.min(minY,y);maxX=Math.max(maxX,x);maxY=Math.max(maxY,y);}};
  (entities||[]).forEach(e=>{
    if(e.points) e.points.forEach(p=>add(p.x,p.y));
    add(e.x,e.y); add(e.x2,e.y2);
    if((e.type==='CIRCLE'||e.type==='ARC')&&Number.isFinite(e.r)){add(e.x-e.r,e.y-e.r);add(e.x+e.r,e.y+e.r);}
  });
  if(!Number.isFinite(minX)||!Number.isFinite(minY)) return null;
  if(maxX-minX<1){maxX+=0.5;minX-=0.5;}
  if(maxY-minY<1){maxY+=0.5;minY-=0.5;}
  return {minX,minY,maxX,maxY,width:maxX-minX,height:maxY-minY};
}
function dxfPreviewInitialViewBox(bounds){
  const pad=Math.max(bounds.width,bounds.height)*0.04||10;
  return [bounds.minX-pad,bounds.minY-pad,bounds.width+pad*2,bounds.height+pad*2];
}
function dxfPreviewPoint(bounds,x,y){return {x, y:bounds.minY+bounds.maxY-y};}
function arcPath(bounds,e){
  const a1=(e.a1||0)*Math.PI/180, a2=(e.a2||0)*Math.PI/180;
  const p1=dxfPreviewPoint(bounds,e.x+Math.cos(a1)*e.r,e.y+Math.sin(a1)*e.r);
  const p2=dxfPreviewPoint(bounds,e.x+Math.cos(a2)*e.r,e.y+Math.sin(a2)*e.r);
  let diff=((e.a2||0)-(e.a1||0))%360; if(diff<0) diff+=360;
  const large=diff>180?1:0;
  return `M ${p1.x} ${p1.y} A ${e.r} ${e.r} 0 ${large} 0 ${p2.x} ${p2.y}`;
}
function entityToSvg(e,bounds){
  const cls=(e.type==='DIMENSION')?'pv-dim':'pv-line';
  if(e.type==='LINE'){
    const a=dxfPreviewPoint(bounds,e.x,e.y),b=dxfPreviewPoint(bounds,e.x2,e.y2);
    return `<line class="${cls}" x1="${a.x}" y1="${a.y}" x2="${b.x}" y2="${b.y}"/>`;
  }
  if(e.type==='LWPOLYLINE'||e.type==='POLYLINE'){
    const pts=e.points.map(p=>{const q=dxfPreviewPoint(bounds,p.x,p.y);return `${q.x},${q.y}`;}).join(' ');
    return `<polyline class="pv-poly" points="${pts}" ${e.closed?'data-closed="1"':''}/>`;
  }
  if(e.type==='CIRCLE'){
    const c=dxfPreviewPoint(bounds,e.x,e.y);
    return `<circle class="pv-circle" cx="${c.x}" cy="${c.y}" r="${e.r}"/>`;
  }
  if(e.type==='ARC') return `<path class="pv-arc" d="${arcPath(bounds,e)}"/>`;
  if(e.text){
    const p=dxfPreviewPoint(bounds,e.x,e.y);
    const text=escHtml(e.text,80);
    return `<text class="${e.type==='DIMENSION'?'pv-text pv-dim-text':'pv-text'}" x="${p.x}" y="${p.y}">${text}</text>`;
  }
  return '';
}
function dxfNumberNorm(s){
  return String(s||'')
    .replace(/\s/g,'')
    .replace(/[()（）]/g,'')
    .replace(/[±]/g,'')
    .replace(/[Φ⌀]/g,'Ø')
    .toUpperCase();
}
function dxfNumberSignature(s){
  const n=dxfNumberNorm(s);
  if(!n) return '';
  if(/^(\d+X)?R\d+(\.\d+)?/.test(n)) return n.match(/^(\d+X)?R\d+(\.\d+)?/)[0];
  if(/^(\d+X)?C\d+(\.\d+)?/.test(n)) return n.match(/^(\d+X)?C\d+(\.\d+)?/)[0];
  if(/^M\d+(\.\d+)?(X\d+(\.\d+)?)?/.test(n)) return n.match(/^M\d+(\.\d+)?(X\d+(\.\d+)?)?/)[0];
  if(/^Ø?\d+(\.\d+)?/.test(n)) return n.match(/^Ø?\d+(\.\d+)?/)[0];
  return n;
}
function isWeakNumberOnlySpec(s){
  const sig=dxfNumberSignature(s);
  return /^\d+(\.\d+)?$/.test(sig);
}
function buildDXFPreviewObjectIndex(){
  const idx={};
  (STATE.entities||[]).forEach((e,i)=>{
    const id=e.objectId||`E${String(i+1).padStart(4,'0')}`;
    idx[id]={...e,objectId:id};
  });
  return idx;
}
function getDXFEntityPoint(e){
  if(!e) return null;
  const x=Number.isFinite(e.x)?e.x:null, y=Number.isFinite(e.y)?e.y:null;
  const x2=Number.isFinite(e.x2)?e.x2:null, y2=Number.isFinite(e.y2)?e.y2:null;
  if(x!==null&&y!==null&&x2!==null&&y2!==null) return {x:(x+x2)/2,y:(y+y2)/2};
  if(x!==null&&y!==null) return {x,y};
  return null;
}
function findSpecTextMatches(item){
  const rawTargets=[item.sourceRawText,item.finalSpec,item.referenceSpec].filter(Boolean);
  const targets=rawTargets.map(dxfNumberSignature).filter(Boolean);
  if(!targets.length) return [];
  const cands=[...(STATE.parsedCands||[]),...(STATE.entities||[]).filter(e=>e.text)];
  const hits=[];
  cands.forEach((e,i)=>{
    const raw=e.cleanText||e.cleanedText||DXFParser.cleanText(e.text||'');
    const clean=dxfNumberSignature(raw);
    if(!clean) return;
    const exact=targets.some(t=>clean===t);
    const sameRaw=item.sourceRawText&&dxfNumberNorm(raw)===dxfNumberNorm(item.sourceRawText);
    if(exact||sameRaw){
      const p=getDXFEntityPoint(e);
      if(p) hits.push({entity:e,point:p,method:sameRaw?'sourceRawTextExact':'finalSpecSignature',confidence:sameRaw?0.86:(isWeakNumberOnlySpec(clean)?0.68:0.78),index:i,signature:clean});
    }
  });
  return hits;
}
function dxfSignatureCounts(){
  const counts={};
  const cands=[...(STATE.parsedCands||[]),...(STATE.entities||[]).filter(e=>e.text)];
  cands.forEach(e=>{
    const sig=dxfNumberSignature(e.cleanText||e.cleanedText||DXFParser.cleanText(e.text||''));
    if(sig) counts[sig]=(counts[sig]||0)+1;
  });
  return counts;
}
function zoneCenterPoint(zone,bounds){
  if(!zone||!bounds) return null;
  const s=String(zone).toUpperCase();
  const letter=(s.match(/[A-F]/)||[])[0];
  const nums=s.match(/\d+/g)||[];
  const col=letter?letter.charCodeAt(0)-65:((parseInt(nums[0],10)||1)-1);
  const row=parseInt(nums[nums.length-1],10)||1;
  const cols=6, rows=4;
  const x=bounds.minX+(Math.max(0,Math.min(cols-1,col))+0.5)*(bounds.width/cols);
  const y=bounds.maxY-(Math.max(0,Math.min(rows-1,row-1))+0.5)*(bounds.height/rows);
  return {x,y};
}
function makeFailedNumberItem(item,number,reason){
  return {
    id:`num_item_${String(number).padStart(3,'0')}`,number,itemNo:String(item.inum||number),
    source:'auto',status:'AUTO_PLACE_FAILED',x:null,y:null,anchorX:null,anchorY:null,labelX:null,labelY:null,
    confidence:0,matchMethod:reason||'none',itemTraceId:`trace_${String(item.inum||number).padStart(3,'0')}`,
    sourceObjectId:item.sourceObjectId||'',sourceRawText:item.sourceRawText||'',finalSpec:item.finalSpec||item.referenceSpec||'',drawingZone:item.drawingZone||'',
    memo:'자동 배치 실패',createdAt:new Date().toISOString(),updatedAt:null,
  };
}
function applyNumberOverlapOffsets(items,bounds){
  const placed=(items||[]).filter(x=>Number.isFinite(x.x)&&Number.isFinite(x.y)&&x.status!=='AUTO_PLACE_FAILED'&&x.status!=='USER_DELETED');
  const minDist=Math.max(bounds?.width||600,bounds?.height||400)*0.018;
  placed.forEach((item,i)=>{
    item.anchorX=item.x; item.anchorY=item.y; item.labelX=item.x; item.labelY=item.y; item.offsetApplied=false;
    let nearby=0;
    for(let j=0;j<i;j++){
      const prev=placed[j];
      const dx=(item.labelX??item.x)-(prev.labelX??prev.x), dy=(item.labelY??item.y)-(prev.labelY??prev.y);
      if(Math.hypot(dx,dy)<minDist) nearby++;
    }
    if(nearby>0){
      const angle=(nearby%8)*(Math.PI/4);
      const step=minDist*(1+Math.floor(nearby/8));
      item.labelX=item.x+Math.cos(angle)*step;
      item.labelY=item.y+Math.sin(angle)*step;
      item.offsetApplied=true;
      item.memo=(item.memo?item.memo+'; ':'')+'OVERLAP_ADJUSTED';
      if(item.status==='AUTO_PLACED') item.status='AUTO_AMBIGUOUS';
    }
  });
}
function generateAutoNumberingFromItems(force=false){
  if(!force&&STATE.dxfNumbering.autoGenerated) return STATE.dxfNumbering.items;
  const items=(STATE.itemStatus&&STATE.itemStatus.length?STATE.itemStatus:ITEM_STATUS_EMBEDDED)||[];
  const objectIndex=buildDXFPreviewObjectIndex();
  const bounds=STATE.dxfPreview?.bounds||getDXFPreviewBounds(STATE.dxfPreview?.entities||STATE.entities||[]);
  const sigCounts=dxfSignatureCounts();
  const out=[];
  items.forEach((it,idx)=>{
    const number=parseInt(it.inum,10)||idx+1;
    let p=null,status='AUTO_PLACE_FAILED',confidence=0,matchMethod='none',sourceObjectId=it.sourceObjectId||'',sourceRawText=it.sourceRawText||'';
    const specSig=dxfNumberSignature(it.finalSpec||it.referenceSpec||'');
    const rawSig=dxfNumberSignature(sourceRawText||'');
    if(Number.isFinite(it.sourceX)&&Number.isFinite(it.sourceY)&&it.sourceX!==0&&it.sourceY!==0&&it.matchConfidence>=0.80){
      p={x:it.sourceX,y:it.sourceY};
      const verified=specSig&&rawSig&&specSig===rawSig;
      const duplicate=verified&&(sigCounts[specSig]||0)>1;
      status=verified&&!duplicate&&it.matchConfidence>=0.90?'AUTO_PLACED':'AUTO_AMBIGUOUS';
      confidence=status==='AUTO_PLACED'?(it.matchConfidence||0.92):Math.min(it.matchConfidence||0.7,0.74);
      matchMethod=verified?(duplicate?'sourceXYDuplicateSignature':'sourceXYVerified'):'sourceXYUnverified';
    }else if(sourceObjectId&&objectIndex[sourceObjectId]){
      p=getDXFEntityPoint(objectIndex[sourceObjectId]);
      const objRaw=objectIndex[sourceObjectId].text||objectIndex[sourceObjectId].cleanText||'';
      const objSig=dxfNumberSignature(objRaw);
      const verified=specSig&&objSig&&specSig===objSig;
      status=p?(verified?'AUTO_PLACED':'AUTO_AMBIGUOUS'):'AUTO_PLACE_FAILED';
      confidence=verified?(it.matchConfidence||0.88):0.66;
      matchMethod=verified?'sourceObjectIdVerified':'sourceObjectIdUnverified';
    }
    // v0.3.9: try balloon anchor BEFORE text-pattern fallback
    if(!p&&STATE.dxfBalloons&&STATE.dxfBalloons.length){
      const balloon=findBalloonForItemNo(STATE.dxfBalloons,it.inum);
      if(balloon&&Number.isFinite(balloon.x)&&Number.isFinite(balloon.y)){
        p={x:balloon.x,y:balloon.y};
        confidence=balloon.confidence;
        status=confidence>=0.85?'AUTO_PLACED':'AUTO_AMBIGUOUS';
        matchMethod='balloonAnchor';
        sourceObjectId=`BALLOON_${balloon.balloonNo}`;
        sourceRawText=balloon.textRaw||sourceRawText;
      }
    }
    // v0.4.0: try PDF visual candidate match before text-pattern fallback
    // This routes zone='2*' items to PDF page 2 with normalized coordinates.
    // Also handles zone='1*' items that match PDF page 1 visible candidates as a backup.
    if(!p){
      const pdfCand = matchItemToPDFVisualCandidate(it);
      if(pdfCand && Number.isFinite(pdfCand.xNormApprox) && Number.isFinite(pdfCand.yNormApprox)){
        // Mark this item for PDF coord-space routing — will be set up below
        it._pdfVisualMatch = pdfCand;
        confidence = pdfCand.confidence || 0.80;
        // multiCandidate: ambiguous but accepted as best guess
        if(pdfCand.multiCandidate) status='AUTO_AMBIGUOUS';
        else status = confidence>=0.85 ? 'AUTO_PLACED' : 'AUTO_AMBIGUOUS';
        matchMethod = pdfCand.conflict ? 'pdfVisualMatchZoneConflict' : 'pdfVisualMatch';
        sourceObjectId = `PDF_P${pdfCand.matchPage}_${pdfCand.normalizedText}`;
        sourceRawText = pdfCand.candidateText || sourceRawText;
        // Set a sentinel non-null p so downstream skips findSpecTextMatches/drawingZone fallbacks
        p = {x: 0, y: 0, _isPDF: true};
      }
    }
    // v0.4.0 PATCH: try Notes section anchor BEFORE findSpecTextMatches
    // (so #110 doesn't get caught by generic DXF text match before reaching notes)
    if(!p && typeof matchItemToNotesAnchor === 'function'){
      const notesCand = matchItemToNotesAnchor(it);
      if(notesCand){
        it._pdfVisualMatch = notesCand;
        confidence = notesCand.confidence || 0.90;
        status = 'AUTO_PLACED';
        matchMethod = 'pdfNotesAnchor';
        sourceObjectId = `PDF_P1_NOTE_${notesCand.label||'note'}`;
        sourceRawText = notesCand.candidateText || sourceRawText;
        p = {x: 0, y: 0, _isPDF: true};
      }
    }
    if(!p){
      const matches=findSpecTextMatches(it);
      if(matches.length===1){
        p=matches[0].point;
        confidence=matches[0].confidence;
        status=confidence>=0.80?'AUTO_PLACED':'AUTO_AMBIGUOUS';
        matchMethod=matches[0].method;
        sourceObjectId=matches[0].entity.objectId||sourceObjectId||`MATCH_${matches[0].index+1}`;
        sourceRawText=matches[0].entity.text||matches[0].entity.cleanText||sourceRawText;
      }else if(matches.length>1){
        p=matches[0].point; status='AUTO_AMBIGUOUS'; confidence=0.61; matchMethod='multipleSpecTextMatches';
        sourceObjectId=matches[0].entity.objectId||sourceObjectId||`MATCH_${matches[0].index+1}`;
        sourceRawText=matches[0].entity.text||matches[0].entity.cleanText||sourceRawText;
      }
    }
    // v0.4.0: try PDF visual candidate match before zoneCenter fallback
    // This handles:
    //   - zone='2*' items (DXF sheet_2 missing) → routed to PDF page 2 with normalized coordinates
    //   - zone='1*' items where DXF text match failed → routed to PDF page 1 as backup
    if(!p && typeof matchItemToPDFVisualCandidate === 'function'){
      const pdfCand = matchItemToPDFVisualCandidate(it);
      if(pdfCand && Number.isFinite(pdfCand.xNormApprox) && Number.isFinite(pdfCand.yNormApprox)){
        it._pdfVisualMatch = pdfCand;
        confidence = pdfCand.confidence || 0.80;
        if(pdfCand.multiCandidate) status='AUTO_AMBIGUOUS';
        else status = confidence>=0.85 ? 'AUTO_PLACED' : 'AUTO_AMBIGUOUS';
        matchMethod = pdfCand.conflict ? 'pdfVisualMatchZoneConflict' : 'pdfVisualMatch';
        sourceObjectId = `PDF_P${pdfCand.matchPage}_${pdfCand.normalizedText}`;
        sourceRawText = pdfCand.candidateText || sourceRawText;
        p = {x: 0, y: 0, _isPDF: true};
      }
    }
    if(!p&&it.drawingZone&&bounds){
      p=zoneCenterPoint(it.drawingZone,bounds);
      if(p){status='PLACEMENT_REVIEW_REQUIRED';confidence=0.35;matchMethod='drawingZoneCenter';}
    }
    if(!p){
      const failed=makeFailedNumberItem(it,number,'noCoordinateMatch');
      failed.sheetId='unknown';
      out.push(failed);
      return;
    }
    // v0.3.8: assign sheetId from matched entity or point coordinates
    let sheetId='unknown';
    // v0.4.0: PDF-routed items get PDF sheetId immediately, skip DXF routing
    if(it._pdfVisualMatch && Number.isFinite(it._pdfVisualMatch.matchPage)){
      sheetId = 'sheet_pdf_p' + it._pdfVisualMatch.matchPage;
    } else if(STATE.dxfSheets&&STATE.dxfSheets.length){
      if(sourceObjectId&&objectIndex[sourceObjectId]){
        sheetId=findSheetIdForEntity(objectIndex[sourceObjectId]);
      }
      if(sheetId==='unknown') sheetId=findSheetIdForPoint(p.x,p.y,STATE.dxfSheets);
    }
    // If sheetId is still unknown but we have multiple sheets, downgrade status
    let finalStatus=status;
    // v0.4.0: PDF-routed items never need downgrade — they have a defined sheet
    if(!it._pdfVisualMatch && STATE.dxfSheets&&STATE.dxfSheets.length>=2&&sheetId==='unknown'&&finalStatus==='AUTO_PLACED'){
      finalStatus='PLACEMENT_REVIEW_REQUIRED';
    }
    out.push({
      id:`num_item_${String(number).padStart(3,'0')}`,number,itemNo:String(it.inum||number),source:'auto',status:finalStatus,sheetId,
      itemTraceId:`trace_${String(it.inum||number).padStart(3,'0')}`,sourceObjectId,sourceRawText,
      finalSpec:it.finalSpec||it.referenceSpec||'',drawingZone:it.drawingZone||'',x:p.x,y:p.y,anchorX:p.x,anchorY:p.y,labelX:p.x,labelY:p.y,
      confidence,matchMethod,memo:finalStatus==='AUTO_PLACED'?'':'위치 확인 필요',createdAt:new Date().toISOString(),updatedAt:null,
      _pdfVisualMatch: it._pdfVisualMatch||null,  // v0.4.0: carry PDF visual match into post-processing
    });
  });
  // v0.4.0D: for ALL items — store sourceCoord + pdfOutputCoord separately
  for(const out_item of out){
    const m = out_item._pdfVisualMatch;
    if(m && Number.isFinite(m.xNormApprox) && Number.isFinite(m.yNormApprox)){
      // Store DXF origin if x/y available
      if(Number.isFinite(out_item.x) && Number.isFinite(out_item.y)){
        out_item.sourceCoord = {
          type:'dxf', sheetId:out_item.sheetId||'sheet_1',
          x:out_item.x, y:out_item.y, matchMethod:out_item.matchMethod
        };
      }
      // PDF output coord from visual candidate
      out_item.pdfOutputCoord = {
        type:'pdf', pageNo:m.matchPage,
        sheetId:'sheet_pdf_p'+m.matchPage,
        xNorm:m.xNormApprox, yNorm:m.yNormApprox,
        matchMethod:'pdfVisualMatch',
        positionStatus:'AUTO_PLACED',
        viewName:m.viewName, candidateText:m.candidateText
      };
      // Keep coordSpace='pdf' for backward compat with renderPDFMarkers (old path)
      out_item.coordSpace = 'pdf';
      out_item.pageNo  = m.matchPage;
      out_item.xNorm   = m.xNormApprox;
      out_item.yNorm   = m.yNormApprox;
      out_item.sheetId = 'sheet_pdf_p' + m.matchPage;
      delete out_item.x; delete out_item.y; delete out_item.labelX; delete out_item.labelY;
      delete out_item._pdfVisualMatch;
    } else if(Number.isFinite(out_item.x) && Number.isFinite(out_item.y)){
      // DXF-only item — store sourceCoord and flag pdfOutputCoord as missing
      out_item.sourceCoord = {
        type:'dxf', sheetId:out_item.sheetId||'sheet_1',
        x:out_item.x, y:out_item.y, matchMethod:out_item.matchMethod
      };
      // Will be filled by buildPdfOutputCoordinatesForAllItems()
      if(!out_item.pdfOutputCoord) out_item.pdfOutputCoord = null;
    }
  }
  applyNumberOverlapOffsets(out,bounds);
  STATE.dxfNumbering.items=out;
  STATE.dxfNumbering.autoGenerated=true;
  STATE.dxfNumbering.selectedId=null;
  STATE.dxfNumbering.pendingAction=null;
  // v0.3.10: if no DXF sheet_2 exists and PDF sheets are loaded, reclassify zone='2*' items to PDF visual reference
  if(typeof reclassifyMissingSheet2Items === 'function') reclassifyMissingSheet2Items();
  // v0.4.0D: build pdfOutputCoord for ALL items (DXF and PDF alike)
  if(typeof buildPdfOutputCoordinatesForAllItems === 'function') buildPdfOutputCoordinatesForAllItems(out);
  renderDXFNumberMarkers();
  renderDXFNumberingUI();
  return out;
}
function ensureAutoNumberingGenerated(){
  if(!STATE.dxfNumbering.autoGenerated||!(STATE.dxfNumbering.items||[]).length) generateAutoNumberingFromItems(true);
}
function regenerateAutoNumbering(){
  STATE.dxfNumbering.autoGenerated=false;
  generateAutoNumberingFromItems(true);
}
function createDXFNumberMarker(item,bounds){
  if(!Number.isFinite(item.x)||!Number.isFinite(item.y)||item.status==='AUTO_PLACE_FAILED'||STATE.dxfNumbering.mode!=='numbering') return '';
  // v0.3.8: sheet filter — unknown sheetId only shown in 'all' view (decision 3); active sheet view shows only matching items
  const active=STATE.activeSheetId||'all';
  if(STATE.dxfSheets&&STATE.dxfSheets.length>=2&&active!=='all'){
    if(item.sheetId!==active) return '';
  }else if(active!=='all'&&item.sheetId==='unknown'){
    return '';
  }
  const p=dxfPreviewPoint(bounds,Number.isFinite(item.labelX)?item.labelX:item.x,Number.isFinite(item.labelY)?item.labelY:item.y);
  const selected=item.id===STATE.dxfNumbering.selectedId?' selected':'';
  const tip=`${item.itemNo||item.number} | ${item.finalSpec||''} | ${item.status||''} | sheet ${item.sheetId||'-'} | conf ${item.confidence??''} | ${item.matchMethod||''}`;
  return `<g class="dxf-number-marker${selected}" data-status="${escHtml(item.status||'AUTO_PLACED')}" data-item-no="${escHtml(item.itemNo||'')}" data-sheet-id="${escHtml(item.sheetId||'unknown')}" data-confidence="${escHtml(item.confidence??'')}" data-match-method="${escHtml(item.matchMethod||'')}" data-number-id="${escHtml(item.id)}" transform="translate(${p.x} ${p.y})">
    <title>${escHtml(tip)}</title>
    <circle r="6"></circle>
    <text y=".2">${escHtml(item.number)}</text>
  </g>`;
}
function renderDXFNumberMarkers(){
  // v0.4.0D: PDF sheet active → delegate entirely to renderPDFMarkers, skip SVG layer
  const activeId = STATE.activeSheetId;
  if(typeof activeId === 'string' && activeId.indexOf('sheet_pdf_') === 0){
    const sheet = (STATE.pdfReferenceSheets||[]).find(s=>s.sheetId === activeId);
    if(sheet && typeof renderPDFMarkers === 'function') renderPDFMarkers(sheet);
    return;  // do NOT try to update SVG dxfNumberLayer
  }
  const layer=el('dxfNumberLayer');
  const bounds=STATE.dxfPreview?.bounds;
  if(!layer||!bounds) return;
  layer.innerHTML=(STATE.dxfNumbering.items||[]).filter(item=>!isPDFItem||!isPDFItem(item)).map(item=>createDXFNumberMarker(item,bounds)).join('');
  layer.querySelectorAll('.dxf-number-marker').forEach(g=>{
    g.addEventListener('pointerdown',ev=>{ev.stopPropagation();});
    g.addEventListener('click',ev=>{
      ev.stopPropagation();
      selectDXFNumber(g.getAttribute('data-number-id'));
    });
  });
  updateDXFNumberMarkerSizing();
}
function renderDXFNumberingUI(){
  const ns=STATE.dxfNumbering||{mode:'view',items:[]};
  const viewBtn=el('dxfModeViewBtn'), numBtn=el('dxfModeNumberBtn');
  if(viewBtn) viewBtn.className='btn btn-secondary dxf-mode-btn '+(ns.mode==='view'?'active-view':'');
  if(numBtn) numBtn.className='btn btn-secondary dxf-mode-btn '+(ns.mode==='numbering'?'active-numbering':'');
  const rows=ns.items||[];
  const auto=rows.filter(x=>x.status==='AUTO_PLACED').length;
  const review=rows.filter(x=>x.status==='AUTO_AMBIGUOUS'||x.status==='PLACEMENT_REVIEW_REQUIRED').length;
  const failed=rows.filter(x=>x.status==='AUTO_PLACE_FAILED').length;
  const manual=rows.filter(x=>x.status==='MANUAL_PLACED'||x.status==='USER_REPOSITIONED').length;
  const visible=rows.filter(x=>Number.isFinite(x.x)&&Number.isFinite(x.y)&&x.status!=='AUTO_PLACE_FAILED').length;
  setEl('dxfNumberingTotal',rows.length+'개');
  setEl('dxfNumberingAuto',auto+'개');
  setEl('dxfNumberingReview',review+'개');
  setEl('dxfNumberingFailed',failed+'개');
  setEl('dxfNumberingManual',manual+'개');
  setEl('dxfNumberingVisible',visible+'개');
  const selected=(ns.items||[]).find(x=>x.id===ns.selectedId);
  setEl('dxfNumberingSelected',selected?selected.number+'번':'없음');
  if(typeof updateItemDetailPanel==='function') updateItemDetailPanel();
  if(typeof scrollToSelectedMarker==='function') scrollToSelectedMarker();
  setEl('dxfNumberingBalloons',(STATE.dxfBalloons||[]).length+'개');
  const help=ns.pendingAction
    ? '위치 지정 중입니다. 도면을 드래그해 이동할 수 있으며, 원하는 위치를 짧게 클릭하면 배치됩니다. ESC로 취소할 수 있습니다.'
    : ns.mode==='numbering'
      ? '자동 넘버링: 성적서 항목 기준으로 도면 위치를 자동 배치합니다. 빈 공간 클릭만으로 새 번호는 생성되지 않습니다.'
      : '일반 모드에서는 번호 오버레이를 숨기고 도면만 확인합니다.';
  setEl('dxfNumberingHelp',help);
  renderDXFNumberList();
}
function setDXFPreviewMode(mode){
  STATE.dxfNumbering.mode=mode==='numbering'?'numbering':'view';
  if(STATE.dxfNumbering.mode==='numbering') ensureAutoNumberingGenerated();
  renderDXFNumberMarkers();
  renderDXFNumberingUI();
}
function svgPointToDXF(ev){
  const svg=el('dxfPreviewSvg'), bounds=STATE.dxfPreview?.bounds;
  if(!svg||!bounds) return null;
  const pt=svg.createSVGPoint();
  pt.x=ev.clientX; pt.y=ev.clientY;
  const m=svg.getScreenCTM();
  if(!m) return null;
  const s=pt.matrixTransform(m.inverse());
  return {x:s.x,y:bounds.minY+bounds.maxY-s.y};
}
function addDXFNumberAt(x,y){
  const ns=STATE.dxfNumbering;
  const target=(ns.items||[]).find(v=>v.id===ns.selectedId);
  if(target){
    target.x=x; target.y=y; target.source='manual';
    target.anchorX=x; target.anchorY=y; target.labelX=x; target.labelY=y; target.offsetApplied=false;
    target.status=target.status==='AUTO_PLACE_FAILED'?'MANUAL_PLACED':'USER_REPOSITIONED';
    target.confidence=1; target.matchMethod='userPlacement'; target.updatedAt=new Date().toISOString();
    ns.pendingAction=null;
    renderDXFNumberMarkers();
    renderDXFNumberingUI();
  }
}
function selectDXFNumber(id){
  STATE.dxfNumbering.selectedId=id||null;
  renderDXFNumberMarkers();
  renderDXFNumberingUI();
}
function deleteDXFNumber(id){
  const ns=STATE.dxfNumbering;
  const item=(ns.items||[]).find(x=>x.id===id);
  if(item){
    item.status='USER_DELETED'; item.x=null; item.y=null; item.anchorX=null; item.anchorY=null; item.labelX=null; item.labelY=null; item.source='manual'; item.updatedAt=new Date().toISOString();
  }
  renderDXFNumberMarkers();
  renderDXFNumberingUI();
}
function deleteSelectedDXFNumber(){
  const id=STATE.dxfNumbering?.selectedId;
  if(id) deleteDXFNumber(id);
}
function deleteLastDXFNumber(){
  const ns=STATE.dxfNumbering;
  const last=(ns.items||[]).filter(x=>x.status!=='AUTO_PLACE_FAILED'&&Number.isFinite(x.x)&&Number.isFinite(x.y)).slice(-1)[0];
  if(last) deleteDXFNumber(last.id);
}
function clearDXFNumbers(){
  STATE.dxfNumbering.items=[];
  STATE.dxfNumbering.selectedId=null;
  STATE.dxfNumbering.autoGenerated=false;
  STATE.dxfNumbering.pendingAction=null;
  renderDXFNumberMarkers();
  renderDXFNumberingUI();
}
function beginSelectedDXFNumberReposition(){
  if(!STATE.dxfNumbering.selectedId) return;
  STATE.dxfNumbering.mode='numbering';
  // v0.4.0D: 객체 방식 — handlePDFOverlayClick과 handleDXFPreviewClickForNumbering 모두 호환
  STATE.dxfNumbering.pendingAction={kind:'reposition', targetId:STATE.dxfNumbering.selectedId};
  renderDXFNumberingUI();
}
function beginSelectedDXFNumberPlacement(){
  const ns=STATE.dxfNumbering;
  let target=(ns.items||[]).find(x=>x.id===ns.selectedId&&(!Number.isFinite(x.x)||!Number.isFinite(x.y)||x.status==='AUTO_PLACE_FAILED'||x.status==='USER_DELETED'));
  if(!target) target=(ns.items||[]).find(x=>x.status==='AUTO_PLACE_FAILED'||x.status==='USER_DELETED');
  if(!target) return;
  ns.selectedId=target.id;
  ns.mode='numbering';
  // v0.4.0D: 객체 방식 — PDF/DXF 클릭 핸들러 모두 호환
  ns.pendingAction={kind:'place', targetId:target.id};
  renderDXFNumberMarkers();
  renderDXFNumberingUI();
}
function toggleDXFNumberList(){
  STATE.dxfNumbering.listOpen=!STATE.dxfNumbering.listOpen;
  renderDXFNumberList();
}
function setDXFNumberFilter(btn,filter){
  STATE.dxfNumbering.filter=filter||'all';
  document.querySelectorAll('#dxfNumberingFilters .chip').forEach(b=>b.classList.remove('active'));
  if(btn) btn.classList.add('active');
  renderDXFNumberList();
}
function filterDXFNumberRows(rows){
  const f=STATE.dxfNumbering.filter||'all';
  if(f==='all') return rows;
  if(f==='review') return rows.filter(x=>x.status==='AUTO_AMBIGUOUS'||x.status==='PLACEMENT_REVIEW_REQUIRED');
  if(f==='manual') return rows.filter(x=>x.status==='MANUAL_PLACED'||x.status==='USER_REPOSITIONED');
  if(f==='low_confidence') return rows.filter(x=>Number(x.confidence||0)<0.75);
  if(f==='overlap') return rows.filter(x=>x.offsetApplied||String(x.memo||'').includes('OVERLAP_ADJUSTED'));
  return rows.filter(x=>x.status===f);
}
function renderDXFNumberList(){
  const box=el('dxfNumberingList'), tb=el('dxfNumberingTbody'), btn=el('dxfNumberListBtn');
  if(!box||!tb) return;
  box.classList.toggle('open',!!STATE.dxfNumbering.listOpen);
  if(btn) btn.textContent=STATE.dxfNumbering.listOpen?'번호 목록 숨기기':'번호 목록 보기';
  const rows=filterDXFNumberRows(STATE.dxfNumbering.items||[]);
  tb.innerHTML=rows.length?rows.map(item=>`
    <tr onclick="selectDXFNumber('${escHtml(item.id)}')" style="cursor:pointer;${item.positionReviewStatus==='USER_CONFIRMED'||item.positionReviewStatus==='USER_REPOSITIONED'?'background:rgba(16,185,129,0.06);':item.positionReviewStatus==='POSITION_LOCKED'?'background:rgba(124,58,237,0.06);':item.positionReviewStatus==='POSITION_REVIEW_REQUIRED'?'background:rgba(239,68,68,0.06);':''}">
      <td>${escHtml(item.number)}</td>
      <td>${escHtml(item.itemNo||item.number)}</td>
      <td>${escHtml(item.finalSpec||'')}</td>
      <td>${escHtml(item.drawingZone||'')}</td>
      <td>${(()=>{const s=item.positionReviewStatus||'AUTO_PLACED_UNVERIFIED';const L={'AUTO_PLACED_UNVERIFIED':'🟡미확정','USER_CONFIRMED':'🟢확정','USER_REPOSITIONED':'🟢수정됨','POSITION_LOCKED':'🟣고정','POSITION_REVIEW_REQUIRED':'🔴검토필요'};return L[s]||s;})()}</td>
      <td>${escHtml(item.sheetId||'-')}</td>
      <td>${Number.isFinite(item.x)?Number(item.x).toFixed(2):'-'}</td>
      <td>${Number.isFinite(item.y)?Number(item.y).toFixed(2):'-'}</td>
      <td>${escHtml(item.status||'')}</td>
      <td>${typeof item.confidence==='number'?item.confidence.toFixed(2):escHtml(item.confidence||'')}</td>
      <td>${escHtml(item.matchMethod||'')}</td>
      <td>${escHtml(item.memo||'')}</td>
      <td>
        <button class="btn btn-secondary" style="padding:3px 8px;font-size:10px" onclick="event.stopPropagation();selectDXFNumber('${escHtml(item.id)}')">선택</button>
        <button class="btn btn-secondary" style="padding:3px 8px;font-size:10px" onclick="event.stopPropagation();selectDXFNumber('${escHtml(item.id)}');beginSelectedDXFNumberPlacement()">위치지정</button>
      </td>
    </tr>`).join(''):`<tr><td colspan="14" style="color:var(--text-dim);text-align:center">등록된 번호가 없습니다.</td></tr>`;
}
function updateDXFNumberMarkerSizing(){
  const svg=el('dxfPreviewSvg'), vb=STATE.dxfPreview?.viewBox;
  if(!svg||!vb) return;
  const rect=svg.getBoundingClientRect();
  const unit=vb[2]/Math.max(rect.width||1,1);
  const r=Math.max(unit*10,Math.max(vb[2],vb[3])*0.004);
  svg.querySelectorAll('.dxf-number-marker circle').forEach(c=>c.setAttribute('r',r));
  svg.querySelectorAll('.dxf-number-marker text').forEach(t=>t.setAttribute('font-size',Math.max(r*1.05,1.8)));
}

// ============================================================================
// v0.3.8: DXF Sheet Detector (inlined from review_extract/dxf-sheet-detector.js)
// ============================================================================

// ============================================================================
// 1. ENTRY POINT
// ============================================================================
// detectDXFSheets(entities, dxfText)
//   entities : array of parsed entities from parseDXFPreviewEntities()
//   dxfText  : raw DXF text (string), used by layout detector for OBJECTS scan
// returns:
//   { method, sheets, log, notes }
//   method  : 'layout' | 'frame' | 'cluster' | 'single'
//   sheets  : Array<Sheet> where Sheet = {
//               id           : 'sheet_1' | 'sheet_2' | ...
//               name         : '도면 1/2' | '도면 2/2' | ...
//               source       : 'layout' | 'frame' | 'cluster' | 'single'
//               isDetected   : true/false  (false → tab disabled in UI)
//               entities     : [...]   (subset of parent entities)
//               bounds       : {minX,minY,maxX,maxY,width,height}
//               viewBox      : [x,y,w,h]
//               confidence   : 0..1
//               note         : '' or human-readable hint
//             }
//   log     : Array<{step, result, detail}>  (for sheet-detection-report.md)
//   notes   : Array<string>  (human-readable summary lines for the same report)
function detectDXFSheets(entities, dxfText){
  const log=[], notes=[];
  const drawable=(entities||[]).filter(e=>e&&['LINE','LWPOLYLINE','POLYLINE','CIRCLE','ARC','TEXT','MTEXT','DIMENSION','ATTRIB'].includes(e.type));
  if(!drawable.length){
    return {method:'single',sheets:[],log:[{step:'init',result:'no_entities'}],notes:['표시 가능한 엔티티가 없습니다.']};
  }

  // 1) Layout detection (best-effort)
  const layoutResult=tryLayoutDetection(dxfText,drawable);
  log.push({step:'layout',sheets:layoutResult.sheets.length,reason:layoutResult.reason});
  if(layoutResult.sheets.length>=2){
    notes.push(`LAYOUT 기반 ${layoutResult.sheets.length}개 시트 감지 (각 paper space에 엔티티 존재)`);
    return finalize('layout',layoutResult.sheets,log,notes);
  }
  notes.push(`LAYOUT 기반 감지 실패: ${layoutResult.reason}`);

  // 2) Frame detection
  const frameResult=tryFrameDetection(drawable);
  log.push({step:'frame',candidates:frameResult.candidates,sheets:frameResult.sheets.length,reason:frameResult.reason});
  if(frameResult.sheets.length>=2){
    notes.push(`Frame 기반 ${frameResult.sheets.length}개 시트 감지 (큰 닫힌 LWPOLYLINE 프레임)`);
    return finalize('frame',frameResult.sheets,log,notes);
  }
  notes.push(`Frame 기반 감지 실패: ${frameResult.reason} (감지된 프레임 후보 ${frameResult.candidates}개)`);

  // 3) Cluster detection (1D k-means on Y, then X)
  const clusterResult=tryClusterDetection(drawable);
  log.push({step:'cluster',axis:clusterResult.axis,gapRatio:clusterResult.gapRatio,minShare:clusterResult.minShare,confidence:clusterResult.confidence,reason:clusterResult.reason});
  if(clusterResult.sheets.length>=2&&clusterResult.confidence>=0.55){
    notes.push(`Cluster 기반 ${clusterResult.sheets.length}개 시트 감지 (${clusterResult.axis}축 분리, 신뢰도 ${clusterResult.confidence.toFixed(2)})`);
    return finalize('cluster',clusterResult.sheets,log,notes);
  }
  notes.push(`Cluster 기반 감지 실패: ${clusterResult.reason} (신뢰도 ${clusterResult.confidence.toFixed(2)}, 임계 0.55)`);

  // 4) Single sheet fallback
  const single=makeSingleSheet(drawable);
  notes.push('단일 시트로 처리합니다. 참고 PDF가 2페이지여도 DXF 자체에서는 2번째 시트를 분리할 수 없었습니다.');
  return finalize('single',[single],log,notes);
}

function finalize(method,sheets,log,notes){
  sheets.forEach((s,i)=>{
    if(!s.id) s.id=`sheet_${i+1}`;
    if(!s.name) s.name=sheets.length>1?`도면 ${i+1}/${sheets.length}`:'도면 1/1';
    if(!s.source) s.source=method;
    if(typeof s.isDetected!=='boolean') s.isDetected=true;
    if(!s.bounds) s.bounds=getSheetBounds(s.entities||[]);
    if(s.bounds&&!s.viewBox) s.viewBox=initialViewBoxFromBounds(s.bounds);
    if(typeof s.confidence!=='number') s.confidence=1.0;
  });
  return {method,sheets,log,notes};
}

// ============================================================================
// 2. LAYOUT DETECTION
// ============================================================================
function tryLayoutDetection(dxfText,drawable){
  if(!dxfText||typeof dxfText!=='string') return {sheets:[],reason:'no_dxf_text'};
  // Parse LAYOUT objects in OBJECTS section to extract names and block_record refs
  const lines=dxfText.split(/\r?\n/);
  const layouts=[];
  for(let i=0;i<lines.length-1;i++){
    if(lines[i].trim()==='AcDbLayout'){
      const info={};
      let j=i+1;
      while(j<lines.length-1){
        const c=lines[j].trim();
        if(c==='0') break;
        const v=lines[j+1];
        if(c==='1') info.name=v;
        else if(c==='71') info.tabOrder=parseInt(v,10);
        else if(c==='330') info.blockRecordRef=String(v).trim();
        j+=2;
      }
      if(info.name) layouts.push(info);
      i=j;
    }
  }
  if(layouts.length<2) return {sheets:[],reason:`LAYOUT 정의 ${layouts.length}개 (Model 제외 paper space 없음)`};

  // Paper space layouts only (Model is tabOrder 0)
  const paperLayouts=layouts.filter(l=>l.name!=='Model');
  if(paperLayouts.length<1) return {sheets:[],reason:'paper space layout 없음'};

  // To use layouts as sheets we need entities to be tagged with paper_space + layout owner.
  // Count entities with paper_space flag (code 67) for any sign of paper-space content.
  // Note: parseDXFPreviewEntities() in v0.3.7 does NOT capture code 67; this is intentional —
  // the current parser flattens everything into model space. Until the parser is extended,
  // layout detection here can only report "found N layouts but parser cannot route entities".
  return {sheets:[],reason:`LAYOUT ${paperLayouts.length}개 발견했으나 현재 파서가 paper_space 플래그를 추출하지 않아 라우팅 불가 (cloudconvert 변환본은 어차피 paper space가 비어있음)`};
}

// ============================================================================
// 3. FRAME DETECTION (closed LWPOLYLINEs of sheet-size)
// ============================================================================
function tryFrameDetection(drawable){
  const polys=drawable.filter(e=>(e.type==='LWPOLYLINE'||e.type==='POLYLINE')&&e.closed&&Array.isArray(e.points)&&e.points.length>=3);
  if(!polys.length) return {sheets:[],candidates:0,reason:'closed polyline 없음'};

  // Compute bbox of each
  const frames=[];
  polys.forEach(p=>{
    const xs=p.points.map(pt=>pt.x).filter(Number.isFinite);
    const ys=p.points.map(pt=>pt.y).filter(Number.isFinite);
    if(!xs.length) return;
    const minX=Math.min(...xs),maxX=Math.max(...xs),minY=Math.min(...ys),maxY=Math.max(...ys);
    const w=maxX-minX,h=maxY-minY;
    // sheet-size heuristic: at least 200 units in both, area > 40000
    if(w<200||h<200) return;
    if(w*h<40000) return;
    frames.push({entity:p,bbox:{minX,minY,maxX,maxY,width:w,height:h}});
  });
  if(frames.length<2) return {sheets:[],candidates:frames.length,reason:`프레임 후보 ${frames.length}개 (≥2 필요)`};

  // Sort frames left→right, top→bottom (reading order)
  frames.sort((a,b)=>{
    const ay=a.bbox.minY,by=b.bbox.minY;
    if(Math.abs(ay-by)>50) return by-ay;  // top first
    return a.bbox.minX-b.bbox.minX;
  });

  // Build sheets, assigning entities by bbox containment
  const sheets=frames.map((f,i)=>{
    const sheetEntities=drawable.filter(e=>entityFitsInBbox(e,f.bbox));
    return {
      id:`sheet_${i+1}`,
      name:`도면 ${i+1}/${frames.length}`,
      source:'frame',
      isDetected:true,
      entities:sheetEntities,
      bounds:f.bbox,
      confidence:0.85,
      note:`닫힌 ${f.entity.type} 프레임 기준`,
    };
  });
  return {sheets,candidates:frames.length,reason:'ok'};
}

// ============================================================================
// 4. CLUSTER DETECTION (1D k-means on Y, then X)
// ============================================================================
function tryClusterDetection(drawable){
  const centers=[];
  drawable.forEach(e=>{
    const c=entityCentroid(e);
    if(c) centers.push({entity:e,x:c.x,y:c.y});
  });
  if(centers.length<10) return {sheets:[],axis:'-',gapRatio:0,minShare:0,confidence:0,reason:'centroid 산출 가능 엔티티 부족'};

  const yResult=clusterOn1D(centers,'y');
  const xResult=clusterOn1D(centers,'x');
  // Choose the axis with higher confidence
  const best=yResult.confidence>=xResult.confidence?yResult:xResult;
  if(!best.split) return {sheets:[],axis:best.axis,gapRatio:best.gapRatio,minShare:best.minShare,confidence:best.confidence,reason:best.reason};

  // Build sheets from cluster assignment
  const sheets=[];
  best.clusters.forEach((cluster,i)=>{
    const ents=cluster.map(p=>p.entity);
    const bb=getSheetBounds(ents);
    sheets.push({
      id:`sheet_${i+1}`,
      name:`도면 ${i+1}/${best.clusters.length}`,
      source:'cluster',
      isDetected:true,
      entities:ents,
      bounds:bb,
      confidence:best.confidence,
      note:`${best.axis}축 클러스터 (gap ${best.gapRatio.toFixed(3)})`,
    });
  });
  return {sheets,axis:best.axis,gapRatio:best.gapRatio,minShare:best.minShare,confidence:best.confidence,reason:'ok'};
}

function clusterOn1D(points,axis){
  const vals=points.map(p=>p[axis]).filter(Number.isFinite).sort((a,b)=>a-b);
  if(vals.length<10) return {axis,split:false,gapRatio:0,minShare:0,confidence:0,reason:`${axis}축 표본 부족`};

  // k-means k=2
  let c0=vals[0],c1=vals[vals.length-1];
  for(let it=0;it<20;it++){
    const g0=[],g1=[];
    vals.forEach(v=>{ (Math.abs(v-c0)<=Math.abs(v-c1)?g0:g1).push(v); });
    const nc0=g0.length?g0.reduce((a,b)=>a+b,0)/g0.length:c0;
    const nc1=g1.length?g1.reduce((a,b)=>a+b,0)/g1.length:c1;
    if(nc0===c0&&nc1===c1) break;
    c0=nc0; c1=nc1;
  }
  // Assign final and compute gap
  const lower=[],upper=[];
  const splitMid=(c0+c1)/2;
  points.forEach(p=>{ (p[axis]<splitMid?lower:upper).push(p); });
  if(!lower.length||!upper.length) return {axis,split:false,gapRatio:0,minShare:0,confidence:0,reason:'단일 클러스터'};
  const lowerMax=Math.max(...lower.map(p=>p[axis]));
  const upperMin=Math.min(...upper.map(p=>p[axis]));
  if(lowerMax>=upperMin) return {axis,split:false,gapRatio:0,minShare:0,confidence:0,reason:'경계가 겹침'};
  const gap=upperMin-lowerMax;
  const spread=vals[vals.length-1]-vals[0];
  const gapRatio=spread>0?gap/spread:0;
  const minShare=Math.min(lower.length,upper.length)/points.length;
  // Confidence: gapRatio * 10 + minShare, clamped
  let confidence=Math.min(0.95,gapRatio*10+minShare);
  // Require both gapRatio >= 0.05 AND minShare >= 0.20 to consider this a real split
  if(gapRatio<0.05||minShare<0.20){
    return {axis,split:false,gapRatio,minShare,confidence,reason:`gap ${gapRatio.toFixed(3)}<0.05 또는 share ${minShare.toFixed(3)}<0.20`};
  }
  // Order clusters: smaller axis-mean first (so lower → sheet_1 for X, but for Y we want TOP → sheet_1 in reading order)
  let clusters;
  if(axis==='y'){
    // Reading order: upper Y first (top of page) → sheet_1
    clusters=[upper,lower];
  }else{
    // Left-to-right: lower X first
    clusters=[lower,upper];
  }
  return {axis,split:true,clusters,gapRatio,minShare,confidence,reason:'ok'};
}

// ============================================================================
// 5. SINGLE SHEET FALLBACK
// ============================================================================
function makeSingleSheet(drawable){
  const bb=getSheetBounds(drawable);
  return {
    id:'sheet_1',
    name:'도면 1/1',
    source:'single',
    isDetected:true,
    entities:drawable.slice(),
    bounds:bb,
    confidence:1.0,
    note:'단일 시트 fallback',
  };
}

// ============================================================================
// 6. SUPPORT
// ============================================================================
function entityCentroid(e){
  if(!e) return null;
  const xs=[],ys=[];
  if(Array.isArray(e.points)){
    e.points.forEach(p=>{ if(Number.isFinite(p.x)&&Number.isFinite(p.y)){xs.push(p.x);ys.push(p.y);} });
  }
  if(Number.isFinite(e.x)&&Number.isFinite(e.y)){xs.push(e.x);ys.push(e.y);}
  if(Number.isFinite(e.x2)&&Number.isFinite(e.y2)){xs.push(e.x2);ys.push(e.y2);}
  if(!xs.length) return null;
  return {x:xs.reduce((a,b)=>a+b,0)/xs.length,y:ys.reduce((a,b)=>a+b,0)/ys.length};
}

function entityFitsInBbox(e,bb){
  const c=entityCentroid(e);
  if(!c) return false;
  // Tolerance: 10% of bbox dimensions
  const tx=bb.width*0.10,ty=bb.height*0.10;
  return c.x>=bb.minX-tx&&c.x<=bb.maxX+tx&&c.y>=bb.minY-ty&&c.y<=bb.maxY+ty;
}

function getSheetBounds(entities){
  let minX=Infinity,minY=Infinity,maxX=-Infinity,maxY=-Infinity;
  const add=(x,y)=>{ if(Number.isFinite(x)&&Number.isFinite(y)){ if(x<minX)minX=x; if(y<minY)minY=y; if(x>maxX)maxX=x; if(y>maxY)maxY=y; } };
  (entities||[]).forEach(e=>{
    if(Array.isArray(e.points)) e.points.forEach(p=>add(p.x,p.y));
    add(e.x,e.y); add(e.x2,e.y2);
    if((e.type==='CIRCLE'||e.type==='ARC')&&Number.isFinite(e.r)){ add(e.x-e.r,e.y-e.r); add(e.x+e.r,e.y+e.r); }
  });
  if(!Number.isFinite(minX)||!Number.isFinite(minY)) return null;
  if(maxX-minX<1){ maxX+=0.5; minX-=0.5; }
  if(maxY-minY<1){ maxY+=0.5; minY-=0.5; }
  return {minX,minY,maxX,maxY,width:maxX-minX,height:maxY-minY};
}

function initialViewBoxFromBounds(b){
  if(!b) return null;
  const pad=Math.max(b.width,b.height)*0.04||10;
  return [b.minX-pad,b.minY-pad,b.width+pad*2,b.height+pad*2];
}

// ============================================================================
// 7. SHEET LOOKUP HELPERS (used by numbering-overlay to assign sheetId)
// ============================================================================
// Given a point (x,y) in DXF coords, find which sheet's bounds contain it.
// Returns sheet.id or 'unknown' if no match or multiple matches with no clear winner.
function findSheetIdForPoint(x,y,sheets){
  if(!sheets||!sheets.length) return 'unknown';
  if(sheets.length===1) return sheets[0].id;
  if(!Number.isFinite(x)||!Number.isFinite(y)) return 'unknown';
  const containing=sheets.filter(s=>s.isDetected&&s.bounds&&x>=s.bounds.minX&&x<=s.bounds.maxX&&y>=s.bounds.minY&&y<=s.bounds.maxY);
  if(containing.length===1) return containing[0].id;
  if(containing.length===0){
    // Find nearest sheet center
    let best=null,bestD=Infinity;
    sheets.forEach(s=>{
      if(!s.isDetected||!s.bounds) return;
      const cx=(s.bounds.minX+s.bounds.maxX)/2,cy=(s.bounds.minY+s.bounds.maxY)/2;
      const d=Math.hypot(x-cx,y-cy);
      if(d<bestD){bestD=d;best=s;}
    });
    return best?best.id:'unknown';
  }
  // Multiple sheets contain the point (overlapping bounds) → ambiguous
  return 'unknown';
}

// Given a sheet array, return total entity count after dedup.
function totalSheetEntities(sheets){
  const seen=new WeakSet(); let n=0;
  (sheets||[]).forEach(s=>{ (s.entities||[]).forEach(e=>{ if(!seen.has(e)){seen.add(e);n++;} }); });
  return n;
}


// ============================================================================
// v0.3.8: Multi-Sheet Helpers (sheet tabs, active sheet management)
// ============================================================================
function setActiveSheet(sheetId){
  // v0.4.0D: accept DXF sheets, PDF sheets, and 'all'
  const dxfSheets = STATE.dxfSheets || [];
  const pdfSheets = STATE.pdfReferenceSheets || [];
  const isAll     = sheetId === 'all';
  const dxfMatch  = dxfSheets.find(s => s.id === sheetId && s.isDetected);
  const pdfMatch  = pdfSheets.find(s => s.sheetId === sheetId);
  if(isAll || dxfMatch || pdfMatch){
    STATE.activeSheetId = sheetId;
  } else {
    // fallback: first detected DXF → first PDF → all
    STATE.activeSheetId = dxfSheets.find(s=>s.isDetected)?.id
                       || pdfSheets[0]?.sheetId
                       || 'all';
  }
  applyActiveSheetView();
  renderSheetTabs();
  renderDXFNumberMarkers();
  renderDXFNumberingUI();
}
function getActiveSheetEntities(){
  // v0.4.0D: PDF sheets handled by applyActiveSheetView before this is called
  if(STATE.activeSheetId==='all'||!STATE.dxfSheets.length){
    const seen=new WeakSet(),out=[];
    STATE.dxfSheets.forEach(s=>{if(!s.isDetected) return; (s.entities||[]).forEach(e=>{if(!seen.has(e)){seen.add(e);out.push(e);}})});
    return out;
  }
  const s=STATE.dxfSheets.find(s=>s.id===STATE.activeSheetId);
  return s?(s.entities||[]):[];
}
function getActiveSheetBounds(){
  if(STATE.activeSheetId==='all'||!STATE.dxfSheets.length){
    // Combined bounds over all detected sheets
    return getDXFPreviewBounds(getActiveSheetEntities());
  }
  const s=STATE.dxfSheets.find(s=>s.id===STATE.activeSheetId);
  return s?s.bounds:null;
}
function applyActiveSheetView(){
  // v0.4.0D: PDF sheet 분기 — PDF canvas 표시, DXF canvas 숨김
  const pdfSheet = (STATE.pdfReferenceSheets||[]).find(s=>s.sheetId===STATE.activeSheetId);
  if(pdfSheet){
    // Show PDF canvas, hide DXF canvas
    const pdfWrap = el('dxfPdfCanvasWrap');
    const dxfWrap = el('dxfPreviewCanvasWrap');
    if(pdfWrap){ pdfWrap.classList.add('active'); pdfWrap.style.display='block'; }
    if(dxfWrap) dxfWrap.style.display = 'none';
    if(typeof renderPDFActiveSheet === 'function') renderPDFActiveSheet(pdfSheet);
    return;
  }
  // DXF sheet or 'all' — hide PDF canvas, show DXF canvas
  const pdfWrap2 = el('dxfPdfCanvasWrap');
  const dxfWrap2 = el('dxfPreviewCanvasWrap');
  if(pdfWrap2){ pdfWrap2.classList.remove('active'); pdfWrap2.style.display='none'; }
  if(dxfWrap2) dxfWrap2.style.display = '';
  const ents=getActiveSheetEntities();
  const bounds=getActiveSheetBounds();
  if(!bounds||!ents.length){setDXFPreviewEmpty('선택한 시트에 표시 가능한 엔티티가 없습니다.');return;}
  // Re-derive viewBox if not stored per sheet
  let vb;
  if(STATE.activeSheetId!=='all'){
    const s=STATE.dxfSheets.find(s=>s.id===STATE.activeSheetId);
    vb=s&&s.viewBox?s.viewBox.slice():dxfPreviewInitialViewBox(bounds);
  }else{
    vb=dxfPreviewInitialViewBox(bounds);
  }
  STATE.dxfPreview={entities:ents,bounds,viewBox:vb,scale:1,collapsed:STATE.dxfPreview?.collapsed||false,error:null};
  // Re-render SVG
  const wrap=el('dxfPreviewCanvasWrap'); if(!wrap) return;
  const maxDraw=3500;
  const svgBody=ents.slice(0,maxDraw).map(e=>entityToSvg(e,bounds)).join('');
  wrap.classList.remove('collapsed');
  wrap.innerHTML=`<svg class="dxf-preview-svg" id="dxfPreviewSvg" xmlns="http://www.w3.org/2000/svg" viewBox="${vb.join(' ')}" preserveAspectRatio="xMidYMid meet">${svgBody}<g id="dxfNumberLayer"></g></svg>`;
  attachDXFPreviewPan();
  attachDXFNumberingClick();
  setEl('dxfPreviewCount',`엔티티 ${ents.length}${ents.length>maxDraw?' / 표시 '+maxDraw:''}`);
  setEl('dxfPreviewBounds',`${bounds.width.toFixed(1)} x ${bounds.height.toFixed(1)}`);
}
function renderSheetTabs(){
  const wrap=el('dxfSheetTabs'); if(!wrap) return;
  const sheets=STATE.dxfSheets||[];
  const pdfSheets=STATE.pdfReferenceSheets||[];   // v0.4.0 fix: declare pdfSheets first
  const detect=STATE.sheetDetection;
  // v0.3.10: show tab bar when EITHER DXF or PDF sheets exist
  if(!sheets.length && !pdfSheets.length){wrap.style.display='none'; return;}
  wrap.style.display='flex';
  // Always show sheet_1, sheet_2, and 전체 보기 buttons.
  // Disabled if sheet not detected (option 2-B).
  const detectedCount=sheets.filter(s=>s.isDetected).length;
  // v0.3.10 option 2-B: force 2 DXF tabs only when no PDF sheets are present
  // When PDF sheets exist, show exact detected DXF sheets (PDF tabs take over the 2nd-page role)
  const showCount = pdfSheets.length > 0 ? Math.max(1, detectedCount) : Math.max(2, detectedCount);
  const btnsHtml=[];
  for(let i=0;i<showCount;i++){
    const sheet=sheets[i];
    const id=sheet?sheet.id:`sheet_${i+1}`;
    // v0.3.8: when forcing 2-tab display with only 1 detected sheet, rename "도면 1/1" → "도면 1/2"
    // so the disabled tab makes sense as "도면 2/2 (감지 안 됨)"
    const name=sheet?(showCount>sheets.length?`도면 ${i+1}/${showCount}`:sheet.name):`도면 ${i+1}/${showCount}`;
    const enabled=sheet&&sheet.isDetected;
    const active=enabled&&STATE.activeSheetId===id;
    const title=enabled?(sheet.note||name):'DXF에서 자동 감지되지 않은 시트입니다.';
    btnsHtml.push(`<button class="dxf-sheet-tab${active?' active':''}" ${enabled?`onclick="setActiveSheet('${id}')"`:''} ${enabled?'':'disabled'} title="${escHtml(title)}">${escHtml(name)}</button>`);
  }
  // v0.3.10: PDF visual sheet tabs (between DXF tabs and '전체 보기')
  for(const ps of pdfSheets){
    const isActive=STATE.activeSheetId===ps.sheetId;
    btnsHtml.push(`<button class="dxf-sheet-tab dxf-sheet-tab-pdf${isActive?' active':''}" onclick="setActiveSheet('${ps.sheetId}')" title="PDF 시각 기준 자료 (수동 위치 지정)">📄 ${escHtml(ps.sheetName)}</button>`);
  }
  btnsHtml.push(`<button class="dxf-sheet-tab${STATE.activeSheetId==='all'?' active':''}" onclick="setActiveSheet('all')" title="모든 시트의 엔티티/번호를 한 화면에 표시">전체 보기</button>`);
  el('dxfSheetTabsButtons').innerHTML=btnsHtml.join('');
  // Detection info line
  let info='';
  if(detect){
    const m={layout:'LAYOUT 기반',frame:'프레임 기반',cluster:'클러스터 기반',single:'단일 시트 (자동 분리 실패)'}[detect.method]||detect.method;
    info=`감지: ${m} · ${detectedCount}개 시트`;
  }
  setEl('dxfSheetDetectionInfo',info);
}

// ============================================================================
// v0.3.9: BALLOON DETECTOR (CIRCLE+integer TEXT pattern)
// ============================================================================
// Scope: Detect explicit balloon/callout symbols in DXF (CIRCLE + integer TEXT inside).
// New in v0.3.9. Inspired by PDFBalloonExtractor from v0.2.x sibling project (PDF/DWF parser line).
//
// Why this exists:
// When a DXF was prepared by a quality engineer who manually placed inspection balloons
// (circle + number inside) on top of the drawing, those balloons are EXPLICIT, HUMAN-AUTHORED
// anchors for the inspection numbering items. They give us a near-1.0 confidence match
// for "this number belongs HERE", which is stronger than any text-pattern guess.
//
// What this returns:
// detectDXFBalloons(entities, bounds) → {
//   balloons: [
//     { balloonNo, x, y, radius, confidence, source, circleEntity, textEntity }
//     ...
//   ],
//   log: { circlesScanned, smallCirclesKept, integerTextsScanned, matched, rejected },
// }
//
// Detection strategy (priority order):
// 1. CIRCLE + integer TEXT centered inside (the canonical balloon pattern)
// 2. INSERT block reference whose BLOCK definition contains BOTH a circle AND a text
//    (covered as future extension — current implementation does step 1 only)

function detectDXFBalloons(entities, bounds){
  const log={circlesScanned:0,smallCirclesKept:0,integerTextsScanned:0,matched:0,rejected:0,rejectedReasons:{}};
  if(!Array.isArray(entities)||!entities.length||!bounds) return {balloons:[],log};

  const minDim=Math.min(bounds.width||1,bounds.height||1);
  // Balloon size band: between 0.5% and 5% of smallest sheet dimension
  // For a 549×389 sheet that's r between ~2 and ~20 units. Real balloons are typically
  // 3-15 units; below 2 is likely a center mark, above 20 is a real geometry circle.
  const minR=minDim*0.005;
  const maxR=minDim*0.050;

  // Step 1: filter CIRCLE entities to balloon-size band
  const allCircles=entities.filter(e=>e&&e.type==='CIRCLE'&&Number.isFinite(e.r));
  log.circlesScanned=allCircles.length;
  const sizedCircles=allCircles.filter(c=>{
    if(c.r<minR){log.rejected++;log.rejectedReasons.tooSmall=(log.rejectedReasons.tooSmall||0)+1;return false;}
    if(c.r>maxR){log.rejected++;log.rejectedReasons.tooLarge=(log.rejectedReasons.tooLarge||0)+1;return false;}
    return true;
  });
  log.smallCirclesKept=sizedCircles.length;

  // Step 2: collect candidate TEXT/MTEXT entities that look like balloon contents
  // Balloons typically contain 1-3 digit integers, optionally wrapped in parens or with prefix letters.
  // We accept: "1", "12", "123", "(45)", "A1", "B-3" — but rank pure integers highest.
  const balloonNumRegex=/^\(?([A-Z]?-?\d{1,3})\)?$/i;
  const allTexts=entities.filter(e=>e&&(e.type==='TEXT'||e.type==='MTEXT')&&e.text);
  const intTexts=[];
  allTexts.forEach(t=>{
    const raw=String(t.text||'').trim();
    if(!raw) return;
    // Strip MTEXT control codes
    const clean=raw.replace(/\\[A-Z][^;]*;/g,'').replace(/[{}]/g,'').trim();
    const m=clean.match(balloonNumRegex);
    if(!m) return;
    if(!Number.isFinite(t.x)||!Number.isFinite(t.y)) return;
    // Extract numeric portion for matching to itemNo
    const numMatch=clean.match(/(\d+)/);
    if(!numMatch) return;
    intTexts.push({entity:t,x:t.x,y:t.y,raw:clean,balloonNo:parseInt(numMatch[1],10)});
  });
  log.integerTextsScanned=intTexts.length;

  // Step 3: pair each circle with its closest contained integer text
  const balloons=[];
  const usedTexts=new Set();
  sizedCircles.forEach(c=>{
    if(!Number.isFinite(c.x)||!Number.isFinite(c.y)) return;
    let best=null,bestD=Infinity;
    intTexts.forEach((t,ti)=>{
      if(usedTexts.has(ti)) return;
      const d=Math.hypot(t.x-c.x,t.y-c.y);
      // Accept text within 1.5x circle radius (some CAD apps center the text by baseline, not by box)
      if(d>c.r*1.5) return;
      if(d<bestD){bestD=d;best={ti,text:t,dist:d};}
    });
    if(best){
      usedTexts.add(best.ti);
      // Confidence: 0.95 if text is centered (d < r/2), 0.85 if inside (d < r), 0.70 if near
      let confidence=0.70;
      if(best.dist<c.r*0.5) confidence=0.95;
      else if(best.dist<c.r) confidence=0.85;
      balloons.push({
        balloonNo:best.text.balloonNo,
        x:c.x,
        y:c.y,
        radius:c.r,
        confidence,
        source:'circle_text',
        circleEntity:c,
        textEntity:best.text.entity,
        textRaw:best.text.raw,
        distance:best.dist,
      });
      log.matched++;
    }
  });

  // Step 4: dedupe — if two balloons claim the same balloonNo, keep the one with higher confidence
  const byNumber=new Map();
  balloons.forEach(b=>{
    const ex=byNumber.get(b.balloonNo);
    if(!ex||b.confidence>ex.confidence) byNumber.set(b.balloonNo,b);
  });
  const finalBalloons=[...byNumber.values()].sort((a,b)=>a.balloonNo-b.balloonNo);

  return {balloons:finalBalloons,log};
}

// Given the detected balloon set and a target itemNo, find the matching balloon (or null).
function findBalloonForItemNo(balloons,itemNo){
  if(!balloons||!balloons.length) return null;
  const n=parseInt(itemNo,10);
  if(!Number.isFinite(n)) return null;
  return balloons.find(b=>b.balloonNo===n)||null;
}

// Distribute detected balloons across sheets by point-in-bounds (uses sheet detector's logic).
// Returns map { sheetId → [balloons] } for reporting/diagnostics.
function groupBalloonsBySheet(balloons,sheets){
  const out={};
  if(!balloons||!balloons.length||!sheets||!sheets.length) return out;
  balloons.forEach(b=>{
    let sid='unknown';
    if(typeof findSheetIdForPoint==='function'){
      sid=findSheetIdForPoint(b.x,b.y,sheets);
    }else if(sheets.length===1){
      sid=sheets[0].id;
    }
    (out[sid]=out[sid]||[]).push(b);
  });
  return out;
}



// ============================================================================
// v0.3.10: PDF PAGE RENDERER (PDF.js + SVG overlay for visual reference sheets)
// ============================================================================
//
// Scope:
// - Render uploaded PDF pages onto canvas via PDF.js (already inlined in the host HTML).
// - Overlay an SVG layer on top of the canvas for marker placement.
// - Maintain marker positions in NORMALIZED coordinates (xNorm, yNorm in 0..1)
//   so they survive canvas resize, zoom, and pan.
// - PDF text layer is INTENTIONALLY NOT USED. The PDFs uploaded for v0.3.10 are
//   Canon-scanner image-only PDFs (verified — see pdf-text-layer-verification.md).
//
// Public API:
//   await loadPDFAsVisualSheet(arrayBuffer, sheetId, sheetName, pageIndex)
//     → { sheetId, sheetName, pageIndex, pdfDoc, pageProxy, widthPt, heightPt }
//
//   renderPDFSheetToCanvas(sheet, canvasEl, scale=1.0)
//     → void  (draws PDF page into canvas at the given scale)
//
//   pdfCanvasToNorm(canvasEl, evt)
//     → { xNorm, yNorm }   convert pointer event coords to normalized 0..1
//
//   pdfNormToCanvas(canvasEl, xNorm, yNorm)
//     → { x, y }   convert normalized 0..1 back to canvas pixel coords
//
// Coord space rationale:
// - PDF logical size is fixed (e.g. 1190.4 × 841.68 pt for A3).
// - Canvas display size depends on container width and user zoom.
// - We store xNorm/yNorm so a marker placed at normalized (0.5, 0.5) is always
//   at the geometric center of the page regardless of how big the canvas is rendered.

const PDF_VISUAL_SHEET_PREFIX = 'sheet_pdf_p';


// v0.4.0N: PDF.js may transfer/detach ArrayBuffer data internally.
// Never pass a reusable ArrayBuffer/TypedArray directly to getDocument().
// Always pass a fresh Uint8Array copy for each PDF.js document load.
function clonePdfDataForPdfjs(input){
  if(input == null) throw new Error('PDF data is empty');
  if(input instanceof Uint8Array) return new Uint8Array(input);
  if(input instanceof ArrayBuffer) return new Uint8Array(input.slice(0));
  if(ArrayBuffer.isView(input)){
    const sliced = input.buffer.slice(input.byteOffset, input.byteOffset + input.byteLength);
    return new Uint8Array(sliced);
  }
  if(input.buffer instanceof ArrayBuffer && Number.isFinite(input.byteLength)){
    const sliced = input.buffer.slice(input.byteOffset || 0, (input.byteOffset || 0) + input.byteLength);
    return new Uint8Array(sliced);
  }
  throw new Error('Unsupported PDF data type: ' + Object.prototype.toString.call(input));
}

function pdfGetDocumentOptions(data){
  return { data: clonePdfDataForPdfjs(data), verbosity: 0 };
}

async function loadPDFAsVisualSheet(arrayBuffer, sheetId, sheetName, pageIndex){
  if(!window.pdfjsLib) throw new Error('PDF.js not loaded — check vendor/pdf.* split files');
  const pageNo = (pageIndex|0) + 1;
  const loadingTask = window.pdfjsLib.getDocument(pdfGetDocumentOptions(arrayBuffer));
  const pdfDoc = await loadingTask.promise;
  if(pageNo > pdfDoc.numPages){
    throw new Error(`PDF has ${pdfDoc.numPages} pages, requested page ${pageNo}`);
  }
  const pageProxy = await pdfDoc.getPage(pageNo);
  const vp = pageProxy.getViewport({scale:1});
  return {
    sheetId: sheetId || `${PDF_VISUAL_SHEET_PREFIX}${pageNo}`,
    sheetName: sheetName || `PDF 도면 ${pageNo}/${pdfDoc.numPages}`,
    source: 'pdf_visual',
    pageIndex: pageIndex|0,
    pageNo,
    pdfDoc,
    pageProxy,
    widthPt: vp.width,
    heightPt: vp.height,
    // bounds in pt coordinate space (origin top-left in canvas-rendering convention)
    bounds: {minX:0, minY:0, maxX:vp.width, maxY:vp.height, width:vp.width, height:vp.height},
    confidence: 1.0,
    coordSpace: 'pdf',  // marks this as a PDF visual sheet (not DXF model space)
  };
}

async function renderPDFSheetToCanvas(sheet, canvasEl, scale){
  if(!sheet || !sheet.pageProxy || !canvasEl) return;
  scale = Number.isFinite(scale) ? scale : 1.0;
  const vp = sheet.pageProxy.getViewport({scale});
  canvasEl.width = Math.max(1, Math.floor(vp.width));
  canvasEl.height = Math.max(1, Math.floor(vp.height));
  const ctx = canvasEl.getContext('2d');
  ctx.clearRect(0,0,canvasEl.width,canvasEl.height);
  await sheet.pageProxy.render({canvasContext:ctx, viewport:vp}).promise;
}

function pdfCanvasToNorm(canvasEl, evt){
  if(!canvasEl) return {xNorm:0, yNorm:0};
  const rect = canvasEl.getBoundingClientRect();
  const xRel = (evt.clientX - rect.left) / rect.width;
  const yRel = (evt.clientY - rect.top)  / rect.height;
  return {
    xNorm: Math.max(0, Math.min(1, xRel)),
    yNorm: Math.max(0, Math.min(1, yRel)),
  };
}

function pdfNormToCanvas(canvasEl, xNorm, yNorm){
  if(!canvasEl) return {x:0, y:0};
  const rect = canvasEl.getBoundingClientRect();
  return {
    x: rect.width  * Math.max(0, Math.min(1, xNorm)),
    y: rect.height * Math.max(0, Math.min(1, yNorm)),
  };
}

// Convenience: route an item to PDF page 2 by default for sheet_2 reclassification.
// Used by generateAutoNumberingFromItems to reclassify items that
//   (a) have drawingZone starting with '2', AND
//   (b) failed to find a matching object in DXF.
function shouldRouteToPDFSheet2(item, dxfSheets){
  if(!item) return false;
  // Only reclassify if no native DXF sheet_2 was detected
  const hasDxfSheet2 = (dxfSheets||[]).some(s=>s.id==='sheet_2' && s.source!=='pdf_visual');
  if(hasDxfSheet2) return false;
  const zone = String(item.drawingZone||'').trim();
  return zone.startsWith('2');
}

// Marker storage format for PDF items (used in STATE.dxfNumbering.items):
//   {
//     id, itemNo, finalSpec, status, matchMethod,
//     coordSpace: 'pdf',
//     sheetId: 'sheet_pdf_p2',
//     pageNo: 2,
//     xNorm: 0..1,
//     yNorm: 0..1,
//     // x, y are NOT used for pdf coord-space items; renderer uses pdfNormToCanvas
//   }
//
// For DXF items, coordSpace='dxf' (or omitted for backward compat with v0.3.9) and
// the existing x/y absolute coordinates are used.

function isPDFItem(item){
  return !!(item && item.coordSpace === 'pdf');
}

function isDXFItem(item){
  return !item || item.coordSpace !== 'pdf';
}

