function pdfVisualNormalize(s){
  if(!s) return '';
  return String(s).trim().replace(/\(/g,'').replace(/\)/g,'').replace(/\s+/g,'');
}

function pdfVisualExtractTokens(spec){
  const s = pdfVisualNormalize(spec);
  if(!s) return [];
  const tokens = new Set([s]);
  if(s.indexOf('전둘레적용') >= 0) tokens.add(s.replace('전둘레적용',''));
  const m1 = s.match(/^깊이([\d\.]+)$/);
  if(m1) tokens.add(m1[1]);
  const m2 = s.match(/^[\d]*x?(M[\d]+X[\d\.]+)/);
  if(m2) tokens.add(m2[1]);
  const m3 = s.match(/^([\d]+x)깊이([\d\.]+)/);
  if(m3){ tokens.add('깊이'+m3[2]); tokens.add(m3[2]); }
  return [...tokens];
}


// ============================================================================
// v0.4.0 PATCH: NOTES SECTION ANCHORS for 주기 entries (#108-#112 area)
// These items don't appear as visible dimensions on the drawing — they correspond
// to the right-side "주 기" paragraph. Each entry has a canonical position in the
// notes box on PDF page 1.
// ============================================================================
const NOTES_SECTION_ANCHORS_P1 = [
  {keywords:['재질','대체가능','금속'],          xNormApprox:0.58, yNormApprox:0.20, label:'1. 재질 및 대체가능 재질'},
  {keywords:['보호피막','피막처리','마스킹','도금','하도','상도'], xNormApprox:0.58, yNormApprox:0.27, label:'2. 보호피막처리'},
  {keywords:['표면거칠기','표면 거칠기','Ra ','날카로운','모서리','공차'],  xNormApprox:0.58, yNormApprox:0.36, label:'3. 공차 및 특기사항'},
  {keywords:['문자음각','문자 음각','음각사양','문자체','돋움체','음각깊이'], xNormApprox:0.58, yNormApprox:0.42, label:'4. 문자 음각 사양'},
  {keywords:['도금처리','도장처리','치수임','도장 후','도금 후'],   xNormApprox:0.58, yNormApprox:0.50, label:'5. 모든 치수는 ... 도장처리 전 치수임'},
];

function matchItemToNotesAnchor(it){
  if(!it) return null;
  const zone = String(it.drawingZone||'').trim();
  if(!zone.startsWith('1') || zone.length < 3) return null;
  const col = zone[2];
  if(col !== '5') return null;
  const specRaw = String(it.finalSpec || it.referenceSpec || '');
  const specNoSpace = specRaw.replace(/\s+/g,'');  // strip whitespace for collapsed-token matching
  const rt = String(it.resultType||'');
  const looksLikeNote = rt === 'ACCEPT_RESULT' || rt === 'NON_MEASURABLE_NOTE' || specRaw.length > 18;
  if(!looksLikeNote) return null;
  let best = null, bestScore = 0;
  for(const a of NOTES_SECTION_ANCHORS_P1){
    let score = 0;
    for(const kw of a.keywords){
      const kwNoSpace = kw.replace(/\s+/g,'');
      if(specRaw.indexOf(kw) >= 0) score++;
      else if(specNoSpace.indexOf(kwNoSpace) >= 0) score++;  // also try whitespace-collapsed match
    }
    if(score > bestScore){ bestScore = score; best = a; }
  }
  if(!best) return null;
  return {
    pdfPage: 'PDF_PAGE_1',
    viewName: '주 기',
    candidateText: best.label,
    normalizedText: best.label,
    dimensionType: 'NOTE',
    approxRegion: zone,
    xNormApprox: best.xNormApprox,
    yNormApprox: best.yNormApprox,
    confidence: 0.90,
    matchPage: 1,
    conflict: false,
    matchedBy: 'notesAnchor',
    matchedKeywords: bestScore,
  };
}

function matchItemToPDFVisualCandidate(item){
  if(!item) return null;
  const zone = String(item.drawingZone||'').trim();
  const expectedPage = zone.startsWith('2') ? 2 : (zone.startsWith('1') ? 1 : 0);
  if(expectedPage === 0) return null;
  const tokens = pdfVisualExtractTokens(item.finalSpec || item.referenceSpec);
  if(!tokens.length) return null;
  const expectedPageKey = 'PDF_PAGE_' + expectedPage;
  // First try: candidates on expected page with matching normalizedText
  let onExpected = PDF_VISUAL_CANDIDATES.filter(c =>
    c.pdfPage === expectedPageKey && tokens.indexOf(c.normalizedText) >= 0
  );
  if(onExpected.length === 1) return {...onExpected[0], matchPage: expectedPage, conflict: false};
  if(onExpected.length > 1){
    // Narrow by approxRegion === drawingZone
    const sameZone = onExpected.filter(c => c.approxRegion === zone);
    if(sameZone.length === 1) return {...sameZone[0], matchPage: expectedPage, conflict: false, narrowedBy: 'zone'};
    // Otherwise return first; multi-match is rare and zone tie-breaker is best effort
    return {...onExpected[0], matchPage: expectedPage, conflict: false, multiCandidate: onExpected.length};
  }
  // Fallback: try other page (zone conflict case)
  const otherPage = expectedPage === 1 ? 2 : 1;
  const onOther = PDF_VISUAL_CANDIDATES.filter(c =>
    c.pdfPage === ('PDF_PAGE_' + otherPage) && tokens.indexOf(c.normalizedText) >= 0
  );
  if(onOther.length === 1) return {...onOther[0], matchPage: otherPage, conflict: true};
  return null;
}



