// 다음 미확정 항목으로 이동
function goToNextUnverified(){
  const items=(STATE.dxfNumbering&&STATE.dxfNumbering.items)||[];
  const current=STATE.dxfNumbering.selectedId;
  const curIdx=items.findIndex(it=>it.id===current);
  // Search from current+1 forward, wrapping around
  for(let offset=1;offset<=items.length;offset++){
    const idx=(curIdx+offset)%items.length;
    const it=items[idx];
    if(it&&it.positionReviewStatus==='AUTO_PLACED_UNVERIFIED'){
      selectDXFNumber(it.id);
      scrollToPDFMarker(it);
      return;
    }
  }
  alert('✅ 미확정 항목이 없습니다! 모든 항목이 검수됐습니다.');
}

// 확정 후 다음 미확정으로 자동 이동
function confirmAndNext(){
  confirmSelectedItemPosition();
  goToNextUnverified();
}

// 선택한 마커가 보이는 위치로 PDF 캔버스 스크롤
function scrollToPDFMarker(item){
  if(!item) return;
  const c=item.pdfOutputCoord||item;
  if(!Number.isFinite(c.xNorm)||!Number.isFinite(c.yNorm)) return;
  // Switch to the correct PDF tab first
  const sheetId=c.sheetId||item.sheetId||('sheet_pdf_p'+(c.pageNo||item.pageNo||1));
  if(STATE.activeSheetId!==sheetId){
    setActiveSheet(sheetId);
    // Wait for PDF to render then scroll
    setTimeout(()=>_scrollPDFCanvasTo(c.xNorm,c.yNorm),400);
  }else{
    _scrollPDFCanvasTo(c.xNorm,c.yNorm);
  }
}

function _scrollPDFCanvasTo(xNorm,yNorm){
  const wrap=el('dxfPdfCanvasWrap');
  const canvas=el('dxfPdfCanvas');
  if(!wrap||!canvas) return;
  const cx=xNorm*canvas.offsetWidth;
  const cy=yNorm*canvas.offsetHeight;
  const halfW=wrap.clientWidth/2;
  const halfH=wrap.clientHeight/2;
  wrap.scrollLeft=Math.max(0,cx-halfW);
  wrap.scrollTop=Math.max(0,cy-halfH);
}

// 선택 변경 시 자동 스크롤 (renderDXFNumberingUI에서 호출)
function scrollToSelectedMarker(){
  const items=(STATE.dxfNumbering&&STATE.dxfNumbering.items)||[];
  const it=items.find(x=>x.id===STATE.dxfNumbering.selectedId);
  if(it) scrollToPDFMarker(it);
}

function exportPositionMapJSON(){
  const items=(STATE.dxfNumbering&&STATE.dxfNumbering.items)||[];
  if(!items.length){ alert('넘버링 항목이 없습니다. 분석을 먼저 실행하세요.'); return; }
  // v0.4.0G: 저장 전 검증 표시
  const VERIFIED=new Set(['USER_CONFIRMED','USER_REPOSITIONED','POSITION_LOCKED']);
  const verifiedCount=items.filter(it=>it&&VERIFIED.has(it.positionReviewStatus)).length;
  const unvCount=items.filter(it=>it&&it.positionReviewStatus==='AUTO_PLACED_UNVERIFIED').length;
  const revCount=items.filter(it=>it&&it.positionReviewStatus==='POSITION_REVIEW_REQUIRED').length;
  const unvNos=items.filter(it=>it&&it.positionReviewStatus==='AUTO_PLACED_UNVERIFIED').slice(0,15).map(it=>it.itemNo||it.number||'?').join(', ');
  const msg='💾 위치맵 저장 전 검증\n\n'+
    '전체: '+items.length+'개\n'+
    '확정/수정/고정: '+verifiedCount+'개\n'+
    '미확정: '+unvCount+'개'+(unvNos?' ('+unvNos+(unvCount>15?' 외':'')+')'  :'')+  '\n'+
    '검토필요: '+revCount+'개\n\n'+
    (unvCount>0?'⚠️ 미확정 항목이 있습니다. 그대로 저장하겠습니까?':'✅ 전체 검수 완료 상태입니다. 저장하겠습니까?');
  if(!confirm(msg)) return;
  const map=items.map(it=>{
    const c=it.pdfOutputCoord||{};
    return {
      itemNo: it.itemNo||it.number,
      pageNo: c.pageNo||it.pageNo||null,
      sheetId: c.sheetId||it.sheetId||null,
      finalSpec: it.finalSpec||'',
      drawingZone: it.drawingZone||'',
      xNorm: Number.isFinite(c.xNorm)?c.xNorm:(Number.isFinite(it.xNorm)?it.xNorm:null),
      yNorm: Number.isFinite(c.yNorm)?c.yNorm:(Number.isFinite(it.yNorm)?it.yNorm:null),
      positionReviewStatus: it.positionReviewStatus||'AUTO_PLACED_UNVERIFIED',
      coordTrustLevel: it.coordTrustLevel||'AUTO_DRAFT',
      anchorValidationStatus: it.positionAnchor?.anchorValidationStatus||'POSITION_REVIEW_REQUIRED',
      positionAnchor: it.positionAnchor||null,
      positionChecks: it.positionChecks||null,
      matchMethod: it.matchMethod||'',
      positionNote: it.positionNote||'',
      failureReason: (it.positionReviewStatus==='FALLBACK_POSITION_INVALID'?'anchor 없음 — 빈 공간 배치':(it.positionReviewStatus==='POSITION_REVIEW_REQUIRED'?'위치 재검토 필요':'')),
      requiredAction: (it.positionReviewStatus==='FALLBACK_POSITION_INVALID'?'수동 위치 지정 후 5개 조건 확인':(it.positionReviewStatus==='POSITION_REVIEW_REQUIRED'?'수치/지시선 기준 재배치':'')),
      updatedAt: it.updatedAt||null,
    };
  });
  // Check if all 112 are verified — determine if this is a FINAL map
  const FINAL_STATUSES = new Set(['POSITION_LOCKED','ANCHOR_VALIDATED','USER_CONFIRMED','USER_REPOSITIONED']);
  const allFinal = map.every(r=>FINAL_STATUSES.has(r.positionReviewStatus));
  const mapType = allFinal && map.length===112 ? 'FINAL_POSITION_MAP' : 'DRAFT_POSITION_MAP';
  const json=JSON.stringify({
    mapType,
    drawingNo:'80871631',
    sheetCount:2,
    itemCount:map.length,
    finalLocked: allFinal && map.length===112,
    exportedAt:new Date().toISOString(),
    items:map.map(r=>({...r, coordTrustLevel: allFinal?'FINAL_LOCKED':(r.coordTrustLevel||'USER_SET')}))
  }, null, 2);
  if(allFinal && map.length===112){
    STATE.finalPositionMapLoaded=true;
    STATE.finalPositionMapMeta={drawingNo:'80871631',itemCount:112,loadedAt:new Date().toISOString()};
  }
  const blob=new Blob([json],{type:'application/json'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');
  a.href=url; a.download='80871631_numbering_position_map_'+(allFinal&&map.length===112?'FINAL':'DRAFT')+'_v0.4.0L.json';
  document.body.appendChild(a); a.click(); document.body.removeChild(a);
  setTimeout(()=>URL.revokeObjectURL(url),2000);
  alert('✅ 위치맵 저장 완료\n파일명: 80871631_numbering_position_map_v0.4.0K.json');
}

function importPositionMapJSON(evt){
  const file=evt.target.files&&evt.target.files[0];
  if(!file) return;
  const reader=new FileReader();
  reader.onload=function(e){
    try{
      const data=JSON.parse(e.target.result);
      const mapItems=data.items||data; // support both wrapped and bare array
      if(!Array.isArray(mapItems)){ alert('올바른 위치맵 파일이 아닙니다.'); return; }
      const items=(STATE.dxfNumbering&&STATE.dxfNumbering.items)||[];
      let updated=0, notFound=[];
      for(const m of mapItems){
        const no=String(m.itemNo||'');
        const it=items.find(x=>String(x.itemNo||x.number||'')==no);
        if(!it){ notFound.push(no); continue; }
        if(!Number.isFinite(m.xNorm)||!Number.isFinite(m.yNorm)) continue;
        // Update pdfOutputCoord
        if(!it.pdfOutputCoord) it.pdfOutputCoord={};
        it.pdfOutputCoord.xNorm=m.xNorm;
        it.pdfOutputCoord.yNorm=m.yNorm;
        it.pdfOutputCoord.pageNo=m.pageNo||it.pdfOutputCoord.pageNo;
        it.pdfOutputCoord.sheetId=m.sheetId||it.pdfOutputCoord.sheetId;
        it.pdfOutputCoord.positionStatus=m.positionReviewStatus||'USER_REPOSITIONED';
        // Update flat legacy fields
        it.xNorm=m.xNorm; it.yNorm=m.yNorm;
        it.coordSpace='pdf'; it.pageNo=m.pageNo;
        it.sheetId=m.sheetId;
        // Set status
        it.positionReviewStatus = m.positionReviewStatus==='POSITION_LOCKED'||m.coordTrustLevel==='FINAL_LOCKED'
          ? 'POSITION_LOCKED' : 'USER_REPOSITIONED';
      it.coordTrustLevel = m.coordTrustLevel || 'USER_SET';
      it.updatedAt = m.updatedAt || new Date().toISOString();
      // v0.4.0L: register in finalPositionMap
      STATE.finalPositionMap[String(m.itemNo)] = {
        xNorm:m.xNorm, yNorm:m.yNorm, pageNo:m.pageNo, sheetId:m.sheetId,
        positionReviewStatus:it.positionReviewStatus, coordTrustLevel:it.coordTrustLevel
      };
      updated++;
      }
      // v0.4.0L: check if all 112 are final-locked
      const finalCount = Object.keys(STATE.finalPositionMap).length;
      if(finalCount >= 112){
        STATE.finalPositionMapLoaded = true;
        STATE.finalPositionMapMeta = {drawingNo:'80871631', itemCount:finalCount, loadedAt:new Date().toISOString()};
      }
      _refreshPosQaStat();
      renderCurrentPDFMarkers();
      renderDXFNumberingUI();
      const VERIFIED2=new Set(['USER_CONFIRMED','USER_REPOSITIONED','POSITION_LOCKED']);
      const items2=(STATE.dxfNumbering&&STATE.dxfNumbering.items)||[];
      const verifiedAfter=items2.filter(it=>it&&VERIFIED2.has(it.positionReviewStatus)).length;
      const p1cnt=items2.filter(it=>it&&(it.pdfOutputCoord?.pageNo===1||it.sheetId==='sheet_pdf_p1')).length;
      const p2cnt=items2.filter(it=>it&&(it.pdfOutputCoord?.pageNo===2||it.sheetId==='sheet_pdf_p2')).length;
      let msg='✅ 위치맵 불러오기 완료\n\n업데이트: '+updated+'개\n확정 상태: '+verifiedAfter+'/112\n1페이지: '+p1cnt+'개 / 2페이지: '+p2cnt+'개';
      if(notFound.length) msg+='\n\n미매칭 (없는 항목): '+notFound.slice(0,10).join(', ')+(notFound.length>10?' 외 '+(notFound.length-10)+'개':'');
      alert(msg);
      _refreshPosQaStat();
      renderCurrentPDFMarkers();
      renderDXFNumberingUI();
    }catch(err){
      alert('위치맵 파일 오류: '+(err.message||err));
    }
  };
  reader.readAsText(file,'utf-8');
  evt.target.value='';
}


function _renderChecksUI(it){
  if(!it) return '';
  const c=it.positionChecks||{};
  const id=it.id||'';
  const checks=[
    ['nearTargetValue',       '① 해당 수치값 바로 옆에 있음'],
    ['nearLeaderEndpoint',    '② 지시선 끝점 근처에 있음'],
    ['visuallyConnectedToFeature','③ 형상/홀/단면과 시각적 연결'],
    ['noCollision',           '④ 다른 번호/치수선과 충돌 없음'],
    ['immediatelyUnderstandable','⑤ 즉시 어떤 항목인지 이해 가능'],
  ];
  return checks.map(([key,label])=>{
    const checked=!!c[key];
    return `<label style="display:flex;align-items:center;gap:6px;margin:2px 0;cursor:pointer;font-size:11px;">
      <input type="checkbox" ${checked?'checked':''} onchange="togglePositionCheck('${id}','${key}',this.checked)" style="margin:0"/>
      <span style="color:${checked?'#059669':'#6b7280'}">${escHtml(label)}</span>
    </label>`;
  }).join('');
}


function anchorValidateSelected(){
  // v0.4.0I: 사용자가 5개 체크박스를 직접 선택해야만 ANCHOR_VALIDATED
  // 버튼이 자동으로 체크를 true 처리하면 안 됨
  const it=getSelectedItem(); if(!it) return;
  if(!it.positionChecks) it.positionChecks=_makeDefaultChecks();
  const c=it.positionChecks;
  const pass=c.nearTargetValue===true&&c.nearLeaderEndpoint===true&&
              c.visuallyConnectedToFeature===true&&c.noCollision===true&&
              c.immediatelyUnderstandable===true;
  if(!pass){
    const missing=[];
    if(!c.nearTargetValue)           missing.push('① 해당 수치 바로 옆');
    if(!c.nearLeaderEndpoint)        missing.push('② 지시선 끝점 근처');
    if(!c.visuallyConnectedToFeature)missing.push('③ 형상/홀/단면과 시각적 연결');
    if(!c.noCollision)               missing.push('④ 충돌 없음');
    if(!c.immediatelyUnderstandable) missing.push('⑤ 즉시 이해 가능');
    alert('🎯 Anchor 검증 불가\n\n미충족 조건 '+missing.length+'개:\n'+missing.join('\n')+
          '\n\n위의 조건을 체크박스로 직접 선택 후 다시 시도하세요.');
    it.positionReviewStatus='POSITION_REVIEW_REQUIRED';
    if(it.positionAnchor) it.positionAnchor.anchorValidationStatus='POSITION_REVIEW_REQUIRED';
    _refreshPosQaStat(); renderCurrentPDFMarkers(); updateItemDetailPanel();
    return;
  }
  it.positionReviewStatus='ANCHOR_VALIDATED';
  if(it.pdfOutputCoord) it.pdfOutputCoord.positionStatus='ANCHOR_VALIDATED';
  if(it.positionAnchor) it.positionAnchor.anchorValidationStatus='ANCHOR_VALIDATED';
  it.updatedAt=new Date().toISOString();
  _refreshPosQaStat(); renderCurrentPDFMarkers(); updateItemDetailPanel();
}
function togglePositionCheck(itemId, key, checked){
  const it=(STATE.dxfNumbering&&STATE.dxfNumbering.items||[]).find(x=>x.id===itemId);
  if(!it) return;
  if(!it.positionChecks) it.positionChecks=_makeDefaultChecks();
  it.positionChecks[key]=checked;
  // Auto-update anchorValidationStatus based on all checks passing
  const c=it.positionChecks;
  const allPass=c.nearTargetValue&&c.nearLeaderEndpoint&&c.visuallyConnectedToFeature&&c.noCollision&&c.immediatelyUnderstandable;
  if(allPass){
    it.positionReviewStatus='ANCHOR_VALIDATED';
    if(it.positionAnchor) it.positionAnchor.anchorValidationStatus='ANCHOR_VALIDATED';
  } else {
    if(it.positionReviewStatus==='ANCHOR_VALIDATED'){
      it.positionReviewStatus='POSITION_REVIEW_REQUIRED';
      if(it.positionAnchor) it.positionAnchor.anchorValidationStatus='POSITION_REVIEW_REQUIRED';
    }
  }
  _refreshPosQaStat();
  updateItemDetailPanel();
  renderCurrentPDFMarkers();
}


// Event delegation for manual placement queue items
document.addEventListener('click', function(e){
  const item = e.target.closest('.mpq-item');
  if(!item) return;
  const id = item.getAttribute('data-itemid');
  const pg = parseInt(item.getAttribute('data-pageno')||'1');
  if(id) selectAndPlaceFallback(id, pg);
});

function updateManualPlacementQueue(){
  const panel = document.getElementById('manualPlacementQueue');
  const list  = document.getElementById('manualPlacementQueueList');
  if(!panel || !list) return;
  const items = (STATE.dxfNumbering && STATE.dxfNumbering.items) || [];
  const fallbackItems = items.filter(it=>it && it.positionReviewStatus==='FALLBACK_POSITION_INVALID');
  panel.style.display = fallbackItems.length ? 'block' : 'none';
  if(!fallbackItems.length){ list.innerHTML=''; return; }
  list.innerHTML = fallbackItems.map(it=>{
    const label = String(it.itemNo||it.number||'?');
    const pg = (it.pdfOutputCoord?.pageNo||it.pageNo||'?');
    const spec = escHtml((it.finalSpec||'').slice(0,50));
    const sel = STATE.dxfNumbering.selectedId===it.id ? 'background:#fef2f2;' : '';
        return '<div data-itemid="'+escHtml(it.id||'')+'" data-pageno="'+pg+'" class="mpq-item" style="display:flex;gap:8px;align-items:center;padding:4px 6px;border-bottom:1px solid #fee2e2;cursor:pointer;'+sel+'border-radius:4px;margin:2px 0;">'
      '<span style="font-weight:700;color:#dc2626;min-width:24px">#'+label+'</span>'+
      '<span style="color:#6b7280;font-size:10px">p'+pg+'</span>'+
      '<span style="flex:1">'+spec+'</span>'+
      '<span style="font-size:10px;color:#dc2626">anchor 없음</span>'+
      '</div>';
  }).join('');
}

function selectAndPlaceFallback(itemId, pageNo){
  const items = (STATE.dxfNumbering && STATE.dxfNumbering.items) || [];
  const it = items.find(x=>x.id===itemId);
  if(!it) return;
  STATE.dxfNumbering.selectedId = itemId;
  STATE.dxfNumbering.pendingAction = {kind:'reposition', targetId:itemId};
  // Switch to correct PDF tab
  const sheetId = 'sheet_pdf_p'+(pageNo||1);
  if(STATE.activeSheetId !== sheetId) setActiveSheet(sheetId);
  else renderCurrentPDFMarkers();
  renderDXFNumberingUI();
  updateItemDetailPanel();
  // Show instruction
  const msg = '📌 #'+(it.itemNo||it.number)+' 선택됨\n\n'+
    'spec: '+(it.finalSpec||'')+'\n\n'+
    'PDF 위 정확한 수치/지시선/형상 옆 위치를 클릭해 배치하세요.';
  setTimeout(()=>alert(msg), 100);
}
