function confirmSelectedItemPosition(){
  // v0.4.0I: USER_CONFIRMED도 5개 체크 완료 후에만 허용
  const it=getSelectedItem(); if(!it) return;
  if(!it.positionChecks) it.positionChecks=_makeDefaultChecks();
  const c=it.positionChecks;
  const pass=c.nearTargetValue&&c.nearLeaderEndpoint&&c.visuallyConnectedToFeature&&c.noCollision&&c.immediatelyUnderstandable;
  if(!pass){
    // Allow without full checks but downgrade to POSITION_REVIEW_REQUIRED-level
    // USER_CONFIRMED without checks = treated as review-required for PDF gate
    const proceed=confirm('⚠️ 5개 조건이 모두 체크되지 않았습니다.\n' +
      '확정 처리하면 PDF 다운로드 게이트에서 막힐 수 있습니다.\n\n' +
      '그래도 확정하시겠습니까? (권장: 체크박스 먼저 확인)');
    if(!proceed){ updateItemDetailPanel(); return; }
  }
  it.positionReviewStatus='USER_CONFIRMED';
  if(it.pdfOutputCoord) it.pdfOutputCoord.positionStatus='USER_CONFIRMED';
  if(it.positionAnchor) it.positionAnchor.anchorValidationStatus='USER_CONFIRMED';
  it.updatedAt=new Date().toISOString();
  _refreshPosQaStat(); renderCurrentPDFMarkers(); updateItemDetailPanel();
}

function markSelectedItemReviewRequired(){
  const it=getSelectedItem(); if(!it) return;
  it.positionReviewStatus='POSITION_REVIEW_REQUIRED';
  if(it.pdfOutputCoord) it.pdfOutputCoord.positionStatus='POSITION_REVIEW_REQUIRED';
  _refreshPosQaStat(); renderCurrentPDFMarkers();
}

function lockSelectedItemPosition(){
  const it=getSelectedItem(); if(!it) return;
  it.positionReviewStatus='POSITION_LOCKED';
  if(it.pdfOutputCoord) it.pdfOutputCoord.positionStatus='POSITION_LOCKED';
  _refreshPosQaStat(); renderCurrentPDFMarkers();
}

function confirmAllVisiblePositions(){
  // v0.4.0F: 경고 먼저 표시
  const sheet=(STATE.pdfReferenceSheets||[]).find(s=>s.sheetId===STATE.activeSheetId);
  const pageName=sheet?sheet.sheetName:'전체 페이지';
  // v0.4.0I: FALLBACK/REVIEW 있으면 일괄 확정 금지
  const items2check=(STATE.dxfNumbering&&STATE.dxfNumbering.items)||[];
  const sheetItems2=sheet ? items2check.filter(it=>it.pdfOutputCoord&&it.pdfOutputCoord.sheetId===sheet.sheetId) : items2check;
  const blocking=sheetItems2.filter(it=>it.positionReviewStatus==='FALLBACK_POSITION_INVALID'||it.positionReviewStatus==='POSITION_REVIEW_REQUIRED');
  if(blocking.length){
    alert('⛔ 일괄 확정 불가\n\n다음 항목이 해결되지 않았습니다:\n'+
      blocking.map(it=>'#'+(it.itemNo||it.number)+' ('+it.positionReviewStatus+')').join('\n')+
      '\n\n각 항목을 수동으로 위치 지정 후 5개 조건을 확인해주세요.');
    return;
  }
  const ok=confirm(
    '⚠️ '+pageName+' 일괄 확정\n\n' +
    '현재 페이지의 모든 번호가 실제 치수값 옆에 있음을 확인했습니까?\n' +
    '틀린 번호가 포함되면 최종 PDF가 잘못 생성됩니다.\n\n' +
    '계속하시겠습니까?'
  );
  if(!ok) return;
  const items=(STATE.dxfNumbering&&STATE.dxfNumbering.items)||[];
  const sheetItems=sheet ? items.filter(it=>it.pdfOutputCoord&&it.pdfOutputCoord.sheetId===sheet.sheetId) : items;
  sheetItems.forEach(it=>{
    if(it.positionReviewStatus==='AUTO_PLACED_UNVERIFIED') it.positionReviewStatus='USER_CONFIRMED';
    if(it.pdfOutputCoord) it.pdfOutputCoord.positionStatus=it.positionReviewStatus;
  });
  _refreshPosQaStat(); renderCurrentPDFMarkers();
  const cnt=sheetItems.filter(it=>it.positionReviewStatus==='USER_CONFIRMED'||it.positionReviewStatus==='USER_REPOSITIONED'||it.positionReviewStatus==='POSITION_LOCKED').length;
  alert('✅ '+pageName+' '+cnt+'개 확정됐습니다.\n틀린 위치는 드래그로 보정 후 다시 확정해주세요.');
}

