// Override updatePdfDownloadReadyState to include positionReviewStatus gate
const __origUpdatePdfBtn = (typeof updatePdfDownloadReadyState==='function') ? updatePdfDownloadReadyState : null;
window.updatePdfDownloadReadyState = function(){
  const btn=el('dlPdfBtn'); if(!btn) return;
  if(!STATE.analysisRun){ btn.disabled=true; btn.title='분석 필요'; return; }
  const items=(STATE.dxfNumbering&&STATE.dxfNumbering.items)||[];
  const pdfReady=(STATE.pdfReferenceSheets||[]).length>=2;
  const itemReady=items.length===112;
  const hasPdfCoord=it=>it&&((it.pdfOutputCoord&&Number.isFinite(it.pdfOutputCoord.xNorm))||(it.coordSpace==='pdf'&&Number.isFinite(it.xNorm)));
  const coordReady=items.filter(hasPdfCoord).length===112;
  // v0.4.0H: ANCHOR_VALIDATED 또는 USER_CONFIRMED/REPOSITIONED/LOCKED가 112개여야 함
  const VERIFIED=new Set(['ANCHOR_VALIDATED','USER_CONFIRMED','USER_REPOSITIONED','POSITION_LOCKED']);
  const verifiedCount=items.filter(it=>it&&VERIFIED.has(it.positionReviewStatus)).length;
  const invalidCount=items.filter(it=>it&&(it.positionReviewStatus==='FALLBACK_POSITION_INVALID'||it.positionReviewStatus==='POSITION_REVIEW_REQUIRED'||it.positionReviewStatus==='AUTO_PLACED_UNVERIFIED')).length;
  const hardInvalidCount=items.filter(it=>it&&it.positionReviewStatus==='FALLBACK_POSITION_INVALID').length;
  const ready=pdfReady&&itemReady&&coordReady&&hardInvalidCount===0;
  btn.disabled=!ready;
  if(!ready){
    if(!pdfReady) btn.title='PDF 미로드';
    else if(!itemReady) btn.title='항목 '+items.length+'/112';
    else if(!coordReady) btn.title='좌표 미완성';
    else btn.title='hard invalid '+hardInvalidCount+'개 해결 필요';
  } else {
    const pending=112-verifiedCount;
    btn.title=pending>0 ? ('검수용 PDF 저장 가능 - anchor 미검증 '+pending+'개') : '최종 넘버링 PDF 저장';
  }
  _refreshPosQaStat();
};

async function autoLoadEmbeddedPDFs(){
  if((STATE.pdfReferenceSheets||[]).length >= 2) return;  // already loaded  // already loaded
  if(STATE._embeddedPDFLoading) return;
  if(typeof EMBEDDED_PDF_P1_B64 === 'undefined') return;
  STATE._embeddedPDFLoading = true;
  try{
    if(typeof waitForPDFJS === 'function') await waitForPDFJS();
    STATE.pdfReferenceSheets = [];
    const pagesData = [
      {b64: EMBEDDED_PDF_P1_B64, pageNo: 1, sheetId:'sheet_pdf_p1', name:'PDF 도면 1/2'},
      {b64: EMBEDDED_PDF_P2_B64, pageNo: 2, sheetId:'sheet_pdf_p2', name:'PDF 도면 2/2'},
    ];
    for(const pd of pagesData){
      try{
        const raw = atob(pd.b64);
        const bytes = new Uint8Array(raw.length);
        for(let i=0;i<raw.length;i++) bytes[i]=raw.charCodeAt(i);
        const sheet = await loadPDFAsVisualSheet(bytes, pd.sheetId, pd.name, 0);
        STATE.pdfReferenceSheets.push(sheet);
        console.log('[v0.4.0] Embedded PDF loaded:', pd.sheetId, sheet.widthPt+'x'+sheet.heightPt+'pt');
      }catch(e){ console.warn('[v0.4.0] Embedded PDF load failed:', pd.sheetId, e); }
    }
    // v0.4.0D: correct execution order inside autoLoadEmbeddedPDFs
    // Step 1: reclassify zone='2*' items to PDF page 2
    if(typeof reclassifyMissingSheet2Items === 'function') reclassifyMissingSheet2Items();
    // Step 2: auto-numbering FIRST so 'out' is defined
    let out = null;
    if(typeof generateAutoNumberingFromItems === 'function'){
      out = generateAutoNumberingFromItems(true);
    }
    // Step 3: build pdfOutputCoord for ALL 112 items (out is now defined)
    if(typeof buildPdfOutputCoordinatesForAllItems === 'function'){
      buildPdfOutputCoordinatesForAllItems(out || STATE.dxfNumbering.items || []);
    }
    // Step 4: update UI
    renderSheetTabs();
    _updatePdfSheetStat();
    // Step 5: activate first PDF tab
    if(STATE.pdfReferenceSheets.length){
      setActiveSheet(STATE.pdfReferenceSheets[0].sheetId);
      // v0.4.0E: PDF 준비 완료 → 버튼 활성화 조건 재평가
      if(typeof updatePdfDownloadReadyState==='function') updatePdfDownloadReadyState();
    }
  }finally{ STATE._embeddedPDFLoading = false; }
}

