// v0.4.0: MARKER DRAG on PDF canvas
// Allows dragging placed markers to adjust xNorm/yNorm positions.
// Called when renderPDFMarkers creates each marker div.
// ══════════════════════════════════════════════════════════════════════
function attachPDFMarkerDrag(div, item, sheet){
  let dragging = false, startX=0, startY=0, origNormX=0, origNormY=0;
  div.addEventListener('pointerdown', ev=>{
    ev.stopPropagation(); ev.preventDefault();
    dragging = true;
    startX = ev.clientX; startY = ev.clientY;
    // v0.4.0E: pdfOutputCoord 우선, legacy xNorm/yNorm 폴백
    const _dc = item.pdfOutputCoord || item;
    origNormX = Number.isFinite(_dc.xNorm) ? _dc.xNorm : 0.5;
    origNormY = Number.isFinite(_dc.yNorm) ? _dc.yNorm : 0.5;
    div.setPointerCapture(ev.pointerId);
    div.classList.add('dragging');
  });
  div.addEventListener('pointermove', ev=>{
    if(!dragging) return;
    const canvas = document.getElementById('dxfPdfCanvas');
    if(!canvas) return;
    const rect = canvas.getBoundingClientRect();
    const dx = (ev.clientX - startX) / rect.width;
    const dy = (ev.clientY - startY) / rect.height;
    const newNX = Math.max(0, Math.min(1, origNormX + dx));
    const newNY = Math.max(0, Math.min(1, origNormY + dy));
    // Update position visually in real time
    const x = newNX * rect.width;
    const y = newNY * rect.height;
    div.style.left = x + 'px';
    div.style.top  = y + 'px';
    item._dragNX = newNX;
    item._dragNY = newNY;
  });
  div.addEventListener('pointerup', ev=>{
    if(!dragging) return;
    dragging = false;
    div.classList.remove('dragging');
    // Commit drag to item
    if(Number.isFinite(item._dragNX)){
      // v0.4.0D: write to pdfOutputCoord AND legacy fields
      const nx = item._dragNX, ny = item._dragNY;
      item.xNorm = nx; item.yNorm = ny;
      delete item._dragNX; delete item._dragNY;
      if(item.pdfOutputCoord){
        item.pdfOutputCoord.xNorm = nx;
        item.pdfOutputCoord.yNorm = ny;
        item.pdfOutputCoord.positionStatus = 'USER_REPOSITIONED';
        item.pdfOutputCoord.matchMethod = 'pdfDragRepositioned';
      }
      item.status               = 'USER_REPOSITIONED';
      item.matchMethod          = 'pdfDragRepositioned';
      item.positionReviewStatus = 'USER_REPOSITIONED';
      renderDXFNumberingUI();
    }
  });
}

