// v0.4.0: NUMBERING PDF EXPORT
// Creates a 2-page PDF (one page per reference PDF) with markers overlaid.
// Uses a minimal self-contained PDF writer — no external libraries needed.
// ══════════════════════════════════════════════════════════════════════
async function exportNumberingPDF(){
  // v0.4.0E: fully wrapped in try/catch; DOM-appended download; position QA gate
  try{
    ensureExportSession();
    const sheets = STATE.pdfReferenceSheets||[];
    const allItems = (STATE.dxfNumbering&&STATE.dxfNumbering.items)||[];
    const EXPECTED = 112;
    const isDevMode = STATE.advancedMode || false;
    const devFileName = isDevMode ? APP_VERSION_SHORT+'_넘버링도면_UNVERIFIED.pdf' : APP_VERSION_SHORT+'_넘버링도면.pdf';
    function _block(msg){ if(isDevMode){ return !confirm('⚠️ [고급 모드] '+msg+'\n\n강제 저장할까요?'); } alert(msg); return true; }

    // ── pre-flight: rebuild pdfOutputCoord + positionReviewStatus ──
    if(!sheets.length){ if(_block('PDF 시각 기준이 없습니다. DXF를 먼저 업로드하세요.')) return; }
    if(typeof buildPdfOutputCoordinatesForAllItems==='function') buildPdfOutputCoordinatesForAllItems(allItems);

    // Gate 1: 항목 수 === 112
    if(allItems.length !== EXPECTED){ if(_block(`항목 수 오류: ${allItems.length}/${EXPECTED} — 분석을 다시 실행하세요.`)) return; }

    // Gate 2: itemNo 1~112 모두 존재
    const noSet = new Set(allItems.map(it=>Number(it.itemNo||it.number)));
    const missingNos=[]; for(let i=1;i<=EXPECTED;i++) if(!noSet.has(i)) missingNos.push(i);
    if(missingNos.length){ if(_block(`검번 누락: ${missingNos.join(', ')}`)) return; }

    // Gate 3: pdfOutputCoord 112개
    const hasPdfCoord=it=>{
      if(it.pdfOutputCoord&&Number.isFinite(it.pdfOutputCoord.xNorm)&&Number.isFinite(it.pdfOutputCoord.yNorm)) return true;
      return it.coordSpace==='pdf'&&Number.isFinite(it.xNorm)&&Number.isFinite(it.yNorm);
    };
    const missingCoord=allItems.filter(it=>!it||!hasPdfCoord(it));
    if(missingCoord.length){
      const nos=missingCoord.slice(0,20).map(it=>it.itemNo||it.number||'?').join(', ')+(missingCoord.length>20?` 외 ${missingCoord.length-20}개`:'');
      if(_block(`PDF 좌표 누락 ${missingCoord.length}개:\n${nos}`)) return;
    }

    // Gate 4: page 분포
    const pdfFull=allItems.filter(it=>it&&hasPdfCoord(it));
    const p1=(it)=>(it.pdfOutputCoord?.pageNo||it.pageNo)===1||(it.pdfOutputCoord?.sheetId||it.sheetId)==='sheet_pdf_p1';
    const p2=(it)=>(it.pdfOutputCoord?.pageNo||it.pageNo)===2||(it.pdfOutputCoord?.sheetId||it.sheetId)==='sheet_pdf_p2';
    const p1c=pdfFull.filter(p1).length, p2c=pdfFull.filter(p2).length;
    if(!p1c){ if(_block('1페이지 마커 없음')) return; }
    if(!p2c){ if(_block('2페이지 마커 없음')) return; }
    if(p1c+p2c!==EXPECTED){ if(_block(`페이지 합계 오류: ${p1c}+${p2c}≠${EXPECTED}`)) return; }

    // Gate 5: positionReviewStatus + anchorValidationStatus 검수 게이트 (v0.4.0H 강화)
    const VERIFIED_STATUSES = new Set(['ANCHOR_VALIDATED','USER_CONFIRMED','USER_REPOSITIONED','POSITION_LOCKED']);
    // v0.4.0L: AUTO_PLACED_UNVERIFIED = also blocks (it's AUTO_DRAFT, not final)
    const unverified = allItems.filter(it=>it && !VERIFIED_STATUSES.has(it.positionReviewStatus));
    const fallbackInvalid2 = allItems.filter(it=>it && it.positionReviewStatus==='FALLBACK_POSITION_INVALID');
    if(fallbackInvalid2.length){
      const fnos=fallbackInvalid2.map(it=>it.itemNo||it.number||'?').join(', ');
      const msg='⛔ PDF 다운로드 불가\n\n' +
        '━ FALLBACK_POSITION_INVALID: '+fnos+'\n' +
        '  → 정확한 도면 anchor 없음 (좌측 홀딩 스택에 있음)\n' +
        '  → 홀딩 마커 클릭 후 PDF 위 정확한 위치를 클릭해 배치\n\n' +
        '조치:\n' +
        '  1. PDF 2/2 탭에서 좌측 ⚠️ 미배치 마커 클릭\n' +
        '  2. 해당 수치/지시선/형상 옆 위치 클릭\n' +
        '  3. 상세 패널에서 5개 조건 체크 → 🎯 anchor 검증';
      if(_block(msg)) return;
    }
    if(unverified.length){
      const uvNos = unverified.slice(0,20).map(it=>it.itemNo||it.number||'?').join(', ')+(unverified.length>20?` 외 ${unverified.length-20}개`:'');
      if(_block(`⛔ anchor 미검증 항목 ${unverified.length}개:\n${uvNos}\n\n조치:\n1. 번호 클릭 → 마커 드래그로 수치/지시선 옆 배치\n2. 상세 패널 5개 체크박스 직접 선택\n3. [🎯 anchor 검증] 클릭 → ANCHOR_VALIDATED`)) return;
    }

    console.log(`[v0.4.0K] exportPDF gates passed: total=${allItems.length} p1=${p1c} p2=${p2c} unverified=${unverified.length}`);

    // ── render each PDF sheet → JPEG → buildMinimalPDF ──
    const pageJpegs=[];
    for(const sheet of sheets){
      const offCanvas=document.createElement('canvas');
      await renderPDFSheetToCanvas(sheet, offCanvas, 1.5);
      const W=offCanvas.width, H=offCanvas.height;
      const ctx=offCanvas.getContext('2d');
      const items=(STATE.dxfNumbering&&STATE.dxfNumbering.items)||[];
      const sheetItems=items.filter(it=>{
        if(!it) return false;
        const c=it.pdfOutputCoord;
        if(c&&c.sheetId===sheet.sheetId&&Number.isFinite(c.xNorm)&&Number.isFinite(c.yNorm)) return true;
        return it.coordSpace==='pdf'&&it.sheetId===sheet.sheetId&&Number.isFinite(it.xNorm)&&Number.isFinite(it.yNorm);
      });
      for(const it of sheetItems){
        const _c=(it.pdfOutputCoord&&Number.isFinite(it.pdfOutputCoord.xNorm))?it.pdfOutputCoord:it;
        const cx=_c.xNorm*W, cy=_c.yNorm*H;
        const r=Math.max(12,Math.min(20,W*0.012));
        const label=it.number!=null?String(it.number):String(it.itemNo||'');
        ctx.beginPath(); ctx.arc(cx,cy,r,0,Math.PI*2);
        ctx.fillStyle='rgba(252,190,200,0.92)'; ctx.fill();
        ctx.strokeStyle='#c0392b'; ctx.lineWidth=Math.max(1.5,r*0.12); ctx.stroke();
        ctx.fillStyle='#7d0000';
        ctx.font=`bold ${Math.round(r*1.1)}px "Malgun Gothic",sans-serif`;
        ctx.textAlign='center'; ctx.textBaseline='middle';
        ctx.fillText(label,cx,cy);
      }
      const jpegB64=offCanvas.toDataURL('image/jpeg',0.92).split(',')[1];
      pageJpegs.push({jpegB64,widthPx:W,heightPx:H,sheetName:sheet.sheetName});
    }

    // ── build PDF bytes ──
    const pdfBytes=buildMinimalPDF(pageJpegs);
    const blob=new Blob([pdfBytes],{type:'application/pdf'});
    const url=URL.createObjectURL(blob);

    // ── DOM-appended download (cross-browser safe) ──
    const a=document.createElement('a');
    a.href=url; a.download=devFileName;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    setTimeout(()=>{
      URL.revokeObjectURL(url);
    },3000);

    alert(`✅ PDF 저장 완료!\n파일명: ${devFileName}\n1페이지 ${p1c}개 + 2페이지 ${p2c}개 마커 포함`);

  }catch(err){
    console.error('[v0.4.0H exportNumberingPDF failed]', err);
    alert('PDF 저장 실패: '+(err.message||String(err))+'\n\n개발자 도구 콘솔에서 상세 오류를 확인하세요.');
  }
}

function buildMinimalPDF(pages){
  const enc=s=>new TextEncoder().encode(s);
  const parts=[]; let offset=0; const offsets=[];
  const push=s=>{const b=(s instanceof Uint8Array)?s:enc(String(s)); parts.push(b); offset+=b.length;};
  const LN='\n';
  push('%PDF-1.4'+LN); push(new Uint8Array([37,226,227,207,211,10]));
  const imageObjBase=4, pageObjBase=4+pages.length*2;
  const pagesObj=pageObjBase+pages.length, catalogObj=pagesObj+1;
  const pageIds=[],imgIds=[];
  for(let pi=0;pi<pages.length;pi++){
    const p=pages[pi];
    const raw=atob(p.jpegB64), imgBytes=new Uint8Array(raw.length);
    for(let i=0;i<raw.length;i++) imgBytes[i]=raw.charCodeAt(i);
    const imgObjId=imageObjBase+pi*2; imgIds.push(imgObjId);
    offsets[imgObjId]=offset;
    push(imgObjId+' 0 obj'+LN+'<<'+LN+'/Type /XObject'+LN+'/Subtype /Image'+LN+
      '/Width '+p.widthPx+LN+'/Height '+p.heightPx+LN+
      '/ColorSpace /DeviceRGB'+LN+'/BitsPerComponent 8'+LN+
      '/Filter /DCTDecode'+LN+'/Length '+imgBytes.length+LN+'>>'+LN+'stream'+LN);
    push(imgBytes);
    push(LN+'endstream'+LN+'endobj'+LN);
    const csObjId=imageObjBase+pi*2+1; offsets[csObjId]=offset;
    const cs='q '+p.widthPx+' 0 0 '+p.heightPx+' 0 0 cm /Im'+pi+' Do Q'+LN;
    push(csObjId+' 0 obj'+LN+'<<'+LN+'/Length '+cs.length+LN+'>>'+LN+'stream'+LN+cs+'endstream'+LN+'endobj'+LN);
    const pgObjId=pageObjBase+pi; pageIds.push(pgObjId); offsets[pgObjId]=offset;
    push(pgObjId+' 0 obj'+LN+'<<'+LN+'/Type /Page'+LN+
      '/Parent '+pagesObj+' 0 R'+LN+
      '/MediaBox [0 0 '+p.widthPx+' '+p.heightPx+']'+LN+
      '/Contents '+csObjId+' 0 R'+LN+
      '/Resources << /XObject << /Im'+pi+' '+imgObjId+' 0 R >> >>'+LN+'>>'+LN+'endobj'+LN);
  }
  offsets[pagesObj]=offset;
  push(pagesObj+' 0 obj'+LN+'<<'+LN+'/Type /Pages'+LN+
    '/Kids ['+pageIds.map(i=>i+' 0 R').join(' ')+']'+LN+
    '/Count '+pages.length+LN+'>>'+LN+'endobj'+LN);
  offsets[catalogObj]=offset;
  push(catalogObj+' 0 obj'+LN+'<<'+LN+'/Type /Catalog'+LN+
    '/Pages '+pagesObj+' 0 R'+LN+'>>'+LN+'endobj'+LN);
  const xrefOffset=offset;
  push('xref'+LN+'0 '+(catalogObj+1)+LN+'0000000000 65535 f '+LN);
  for(let i=1;i<=catalogObj;i++) push(String(offsets[i]||0).padStart(10,'0')+' 00000 n '+LN);
  push('trailer'+LN+'<<'+LN+'/Size '+(catalogObj+1)+LN+'/Root '+catalogObj+' 0 R'+LN+'>>'+LN+'startxref'+LN+xrefOffset+LN+'%%EOF'+LN);
  const totalLen=parts.reduce((s,p)=>s+p.length,0);
  const out=new Uint8Array(totalLen); let pos=0;
  for(const p of parts){ out.set(p,pos); pos+=p.length; }
  return out;
}

// Hook: update the PDF sheet count + matched count in the UI stat
function _updatePdfSheetStat(){
  setEl('dxfNumberingPdfSheets', ((STATE.pdfReferenceSheets||[]).length) + '개');
  // v0.4.0: count items that were auto-matched via PDF visual candidates
  const items = (STATE.dxfNumbering && STATE.dxfNumbering.items) || [];
  const matched = items.filter(it => it.coordSpace==='pdf' && it.matchMethod==='pdfVisualMatch').length;
  setEl('dxfNumberingPdfMatched', matched + '개');
}
// Patch renderDXFNumberingUI to call _updatePdfSheetStat
const __origRenderDXFNumberingUI = (typeof renderDXFNumberingUI === 'function') ? renderDXFNumberingUI : null;
if(__origRenderDXFNumberingUI){
  window.renderDXFNumberingUI = function(){
    __origRenderDXFNumberingUI.apply(this, arguments);
    _updatePdfSheetStat();
    updatePdfDownloadReadyState();
  };
}

// v0.4.0E: PDF 다운로드 버튼 활성화 조건
// pdfReferenceSheets >= 2 AND numbering items 112 AND pdfOutputCoord 112 AND analysisRun
function updatePdfDownloadReadyState(){
  const btn = el('dlPdfBtn'); if(!btn) return;
  if(!STATE.analysisRun){ btn.disabled=true; return; }
  const items = (STATE.dxfNumbering&&STATE.dxfNumbering.items)||[];
  const pdfReady  = (STATE.pdfReferenceSheets||[]).length >= 2;
  const itemReady = items.length === 112;
  const coordReady = items.filter(it=>
    it && it.pdfOutputCoord &&
    Number.isFinite(it.pdfOutputCoord.xNorm) &&
    Number.isFinite(it.pdfOutputCoord.yNorm)
  ).length === 112;
  const ready = pdfReady && itemReady && coordReady;
  btn.disabled = !ready;
  if(!ready){
    const reason = !pdfReady ? 'PDF 미로드' : !itemReady ? `항목 ${items.length}/112` : `좌표 미완성`;
    btn.title = `PDF 저장 준비 중… (${reason})`;
  } else {
    btn.title = 'PDF 1/2 + 2/2 넘버링 저장';
  }
}




// Given an entity, find which detected sheet it belongs to (returns sheet.id or 'unknown')
function findSheetIdForEntity(entity){
  if(!STATE.dxfSheets||!STATE.dxfSheets.length) return 'unknown';
  if(STATE.dxfSheets.length===1) return STATE.dxfSheets[0].id;
  // First, check direct membership (entity is in sheet.entities)
  for(const s of STATE.dxfSheets){
    if(!s.isDetected) continue;
    if((s.entities||[]).includes(entity)) return s.id;
  }
  // Fall back to bounds-based lookup using entity centroid
  const c=entityCentroid(entity);
  if(c) return findSheetIdForPoint(c.x,c.y,STATE.dxfSheets);
  return 'unknown';
}

function renderDXFPreview(){
  const wrap=el('dxfPreviewCanvasWrap'); if(!wrap) return;
  if(STATE.drawingType&&STATE.drawingType!=='dxf'){setDXFPreviewEmpty('PDF 파일은 현재 DXF 도면 미리보기 대상이 아닙니다.');return;}
  if(!STATE.dxfText){setDXFPreviewEmpty();return;}
  try{
    const previewEntities=parseDXFPreviewEntities(STATE.dxfText);
    const drawable=previewEntities.filter(e=>['LINE','LWPOLYLINE','POLYLINE','CIRCLE','ARC','TEXT','MTEXT','DIMENSION','ATTRIB'].includes(e.type));
    if(!drawable.length){setDXFPreviewEmpty('DXF에서 미리보기 가능한 도면 엔티티를 찾지 못했습니다.');return;}
    // v0.3.8: Run sheet detection
    STATE.sheetDetection=detectDXFSheets(drawable,STATE.dxfText);
    STATE.dxfSheets=STATE.sheetDetection.sheets;
    // v0.3.9: Run balloon detection (after sheet detection so bounds are known)
    const _bdBounds=getDXFPreviewBounds(drawable);
    STATE.balloonDetection=detectDXFBalloons(drawable,_bdBounds);
    STATE.dxfBalloons=STATE.balloonDetection.balloons;
    // v0.4.0: Auto-load embedded PDF reference pages if not yet loaded
    if(typeof autoLoadEmbeddedPDFs === 'function') autoLoadEmbeddedPDFs();
    // Default active sheet: first detected sheet (or 'all' if multiple)
    if(STATE.dxfSheets.length>=2) STATE.activeSheetId='all';
    else if(STATE.dxfSheets.length===1) STATE.activeSheetId=STATE.dxfSheets[0].id;
    else STATE.activeSheetId='all';
    const bounds=getActiveSheetBounds()||getDXFPreviewBounds(drawable);
    if(!bounds){setDXFPreviewEmpty('DXF에서 표시 가능한 bounds를 계산할 수 없습니다.');return;}
    const vb=dxfPreviewInitialViewBox(bounds);
    STATE.dxfPreview={entities:getActiveSheetEntities(),bounds,viewBox:vb.slice(),scale:1,collapsed:false,error:null};
    if(STATE.dxfNumbering.autoGenerated) generateAutoNumberingFromItems(true);
    const maxDraw=3500;
    const renderEntities=STATE.dxfPreview.entities;
    const svgBody=renderEntities.slice(0,maxDraw).map(e=>entityToSvg(e,bounds)).join('');
    wrap.classList.remove('collapsed');
    wrap.innerHTML=`<svg class="dxf-preview-svg" id="dxfPreviewSvg" xmlns="http://www.w3.org/2000/svg" viewBox="${vb.join(' ')}" preserveAspectRatio="xMidYMid meet">${svgBody}<g id="dxfNumberLayer"></g></svg>`;
    renderDXFNumberMarkers();
    attachDXFPreviewPan();
    attachDXFNumberingClick();
    renderSheetTabs();
    setEl('dxfPreviewStatus','업로드된 DXF 도면을 미리보기로 표시 중입니다.');
    setEl('dxfPreviewFile',STATE.dxfFile?STATE.dxfFile.name:'DXF');
    setEl('dxfPreviewCount',`엔티티 ${renderEntities.length}${renderEntities.length>maxDraw?' / 표시 '+maxDraw:''}`);
    setEl('dxfPreviewBounds',`${bounds.width.toFixed(1)} x ${bounds.height.toFixed(1)}`);
    renderDXFNumberingUI();
  }catch(e){
    STATE.dxfPreview.error=e;
    wrap.innerHTML=`<div class="dxf-preview-error">DXF 미리보기 렌더링 실패<br>${escHtml(e?.message||String(e))}</div>`;
    setEl('dxfPreviewStatus','DXF 미리보기 렌더링에 실패했습니다. 분석과 XLSX 생성 흐름은 계속 사용할 수 있습니다.');
  }
}
function updateDXFPreviewViewBox(){
  const svg=el('dxfPreviewSvg');
  const vb=STATE.dxfPreview?.viewBox;
  if(svg&&vb) svg.setAttribute('viewBox',vb.join(' '));
  updateDXFNumberMarkerSizing();
}
function fitDXFPreview(){
  const b=STATE.dxfPreview?.bounds; if(!b) return;
  STATE.dxfPreview.viewBox=dxfPreviewInitialViewBox(b);
  STATE.dxfPreview.scale=1;
  updateDXFPreviewViewBox();
}
function zoomDXFPreview(factor){
  const pv=STATE.dxfPreview, vb=pv?.viewBox; if(!vb) return;
  const cx=vb[0]+vb[2]/2, cy=vb[1]+vb[3]/2;
  const nw=vb[2]/factor, nh=vb[3]/factor;
  pv.viewBox=[cx-nw/2,cy-nh/2,nw,nh];
  pv.scale=(pv.scale||1)*factor;
  updateDXFPreviewViewBox();
}
function resetDXFPreview(){renderDXFPreview();}
function toggleDXFPreviewCollapse(){
  const wrap=el('dxfPreviewCanvasWrap'),btn=el('dxfPreviewCollapseBtn'); if(!wrap) return;
  const collapsed=!wrap.classList.contains('collapsed');
  wrap.classList.toggle('collapsed',collapsed);
  if(btn) btn.textContent=collapsed?'미리보기 펼치기':'미리보기 접기';
}
function attachDXFPreviewPan(){
  const svg=el('dxfPreviewSvg'); if(!svg) return;
  let dragging=false,moved=false,last=null,downAt=null;
  svg.addEventListener('pointerdown',ev=>{
    if(ev.target.closest&&ev.target.closest('.dxf-number-marker')) return;
    dragging=true;
    moved=false;
    last={x:ev.clientX,y:ev.clientY};
    downAt={x:ev.clientX,y:ev.clientY};
    if(svg.setPointerCapture) svg.setPointerCapture(ev.pointerId);
  });
  svg.addEventListener('pointermove',ev=>{
    if(!dragging||!last||!STATE.dxfPreview?.viewBox) return;
    const dist=downAt?Math.hypot(ev.clientX-downAt.x,ev.clientY-downAt.y):0;
    if(dist>3) moved=true;
    const vb=STATE.dxfPreview.viewBox;
    const rect=svg.getBoundingClientRect();
    const dx=(last.x-ev.clientX)*vb[2]/Math.max(rect.width,1);
    const dy=(last.y-ev.clientY)*vb[3]/Math.max(rect.height,1);
    STATE.dxfPreview.viewBox=[vb[0]+dx,vb[1]+dy,vb[2],vb[3]];
    last={x:ev.clientX,y:ev.clientY};
    updateDXFPreviewViewBox();
  });
  svg.addEventListener('pointerup',ev=>{
    const wasMoved=moved;
    dragging=false;last=null;downAt=null;moved=false;
    if(wasMoved) return;
    handleDXFPreviewClickForNumbering(ev);
  });
  svg.addEventListener('pointercancel',()=>{dragging=false;moved=false;last=null;downAt=null;});
}
function handleDXFPreviewClickForNumbering(ev){
  const ns=STATE.dxfNumbering;
  if(!ns||ns.mode!=='numbering') return;
  if(ev.target.closest&&ev.target.closest('.dxf-number-marker')) return;
  // v0.4.0D: 객체/문자열 모두 허용
  const pa=ns.pendingAction;
  const kind=pa?(typeof pa==='string'?pa:pa.kind):null;
  if(kind!=='place'&&kind!=='reposition') return;
  const p=svgPointToDXF(ev);
  if(p) addDXFNumberAt(p.x,p.y);
}
function attachDXFNumberingClick(){
  // v0.3.7: click placement is integrated into attachDXFPreviewPan()
  // so drag pan cannot accidentally trigger a numbering click.
}
function cancelDXFNumberingPendingAction(){
  if(!STATE.dxfNumbering?.pendingAction) return;
  STATE.dxfNumbering.pendingAction=null;
  renderDXFNumberingUI();
}

// ── 검증 리포트 ───────────────────────────────────────────────
function renderVerify(){
  const its=STATE.itemStatus,tot=its.length;
  if(!STATE.analysisRun)return;
  const dxfCnt=its.filter(i=>i.specSourceType==='DXF_CONFIRMED').length;
  const refCnt=its.filter(i=>i.specSourceType==='REFERENCE_SPEC_DATABASE').length;
  const genCnt=its.filter(i=>i.resultType==='RANGE_RANDOM_RESULT'||i.resultType==='MULTI_RANGE_RANDOM_RESULT').length;
  const fixCnt=its.filter(i=>i.resultType==='FIXED_TEXT_RESULT'||i.resultType==='ACCEPT_RESULT').length;
  const revCnt=its.filter(i=>i.resultType==='REVIEW_REQUIRED').length;
  const misCnt=its.filter(i=>i.status==='MISSING_SPEC').length;
  const lv=STATE.lastVerify;
  const rows=[
    ['분석 완료', true, '완료'],
    ['성적서 필요 항목', tot===112, `${tot}개`],
    ['DXF 원천 기반', dxfCnt>0, `${dxfCnt}개`],
    ['기준DB 기반', refCnt>0, `${refCnt}개`],
    ['범위 생성값', true, `${genCnt}개`],
    ['고정 결과', true, `${fixCnt}개`],
    ['검토 필요', revCnt===0, `${revCnt}개`],
    ['생성 불가', misCnt===0, `${misCnt}개`],
    ['Excel 재로드', lv?lv.reloadOk:false, lv?'검증됨':'미실행'],
    ['오류 셀', lv?(lv.errorCells||[]).length===0:true, lv?`${(lv.errorCells||[]).length}개`:'—'],
    ['빨간번호 잔류', lv?!lv.redMarkerFound:true, lv?(lv.redMarkerFound?'있음':'없음'):'—'],
    ['원본 탭 유지', lv?(lv.extraSheets||[]).length===0&&(lv.missingSheets||[]).length===0:false, lv?`추가 ${(lv.extraSheets||[]).length} / 누락 ${(lv.missingSheets||[]).length}`:'미실행'],
    ['최종 다운로드', lv?!!lv.passed:false, lv?(lv.passed?'가능':'검증 실패'):'미실행'],
  ];
  const grid=el('verifyGrid');if(!grid)return;
  grid.innerHTML=rows.map(([lbl,ok,val])=>
    `<div class="verify-row">
      <span class="verify-label">${lbl}</span>
      <span class="verify-val ${ok?'vok':'vfail'}">${ok?'✅':'❌'} ${val}</span>
    </div>`
  ).join('');
}

// ── DOM XML Patch Export helpers ────────────────────────────
// RF10 핵심: 최종 XLSX는 SheetJS/ExcelJS로 통합문서를 재작성하지 않는다.
// 원본 XLSX ZIP을 그대로 유지하고, 필요한 셀 XML만 직접 치환한다.
// 이 방식은 원본 양식의 테두리, 행 높이, 열 너비, 병합, 인쇄 설정, 시트 탭 구성을 보존한다.
function sheetAddr(row,col){return XLSX.utils.encode_cell({r:row-1,c:col-1});}
function sheetGet(ws,row,col){return ws ? ws[sheetAddr(row,col)] : null;}
function getSheetRangeRows(ws,fallback=160){
  if(!ws||!ws['!ref']) return fallback;
  try{return Math.max(fallback,XLSX.utils.decode_range(ws['!ref']).e.r+1);}catch(e){return fallback;}
}
function findSheetByNameOrIndex(wb,name,index){
  if(name&&wb.Sheets[name]) return wb.Sheets[name];
  const sn=wb.SheetNames[index]||wb.SheetNames[0];
  return wb.Sheets[sn];
}
function findSheetNameByNameOrIndex(wb,name,index){
  if(name&&wb.Sheets[name]) return name;
  return wb.SheetNames[index]||wb.SheetNames[0];
}
function xmlEscape(v){
  return sanitizePlainText(v,32767)
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;')
    .replace(/"/g,'&quot;');
}
function xmlDecode(v){
  return String(v||'')
    .replace(/&quot;/g,'"')
    .replace(/&apos;/g,"'")
    .replace(/&lt;/g,'<')
    .replace(/&gt;/g,'>')
    .replace(/&amp;/g,'&');
}
function getXmlAttr(attrs,name){
  const re=new RegExp('(?:^|\\s)'+name.replace(':','\\:')+'="([^"]*)"');
  const m=String(attrs||'').match(re);
  return m?xmlDecode(m[1]):'';
}
function escRe(s){return String(s).replace(/[.*+?^${}()|[\]\\]/g,'\\$&');}
function colIndexFromLetters(letters){
  let n=0; letters=String(letters||'').toUpperCase();
  for(let i=0;i<letters.length;i++) n=n*26+(letters.charCodeAt(i)-64);
  return n;
}
function splitCellAddr(addr){
  const m=String(addr).match(/^([A-Z]+)(\d+)$/i);
  return {col:m?m[1].toUpperCase():'A', row:m?parseInt(m[2],10):1};
}
function detectWsPrefix(xml){
  const m=String(xml).match(/<([A-Za-z0-9_]+:)?worksheet\b/);
  return m?(m[1]||''):'';
}
function findColumnStyleId(xml,col){
  const re=new RegExp('<[^:>]*:?c\\b[^>]*\\br="'+escRe(col)+'\\d+"[^>]*\\bs="([0-9]+)"','g');
  const m=re.exec(xml);
  return m?m[1]:'';
}
function normalizeWorksheetPath(target){
  target=String(target||'').replace(/^\//,'');
  if(target.startsWith('xl/')) return target;
  return 'xl/'+target.replace(/^\.\//,'');
}
function crc32Bytes(bytes){
  if(!crc32Bytes.table){
    const t=new Uint32Array(256);
    for(let i=0;i<256;i++){
      let c=i;
      for(let k=0;k<8;k++) c=(c&1)?(0xEDB88320^(c>>>1)):(c>>>1);
      t[i]=c>>>0;
    }
    crc32Bytes.table=t;
  }
  let c=0xFFFFFFFF;
  for(let i=0;i<bytes.length;i++) c=crc32Bytes.table[(c^bytes[i])&255]^(c>>>8);
  return (c^0xFFFFFFFF)>>>0;
}
function u16le(b,o){return b[o]|(b[o+1]<<8);}
function u32le(b,o){return (b[o]|(b[o+1]<<8)|(b[o+2]<<16)|(b[o+3]<<24))>>>0;}
function w16le(b,o,v){b[o]=v&255;b[o+1]=(v>>>8)&255;}
function w32le(b,o,v){b[o]=v&255;b[o+1]=(v>>>8)&255;b[o+2]=(v>>>16)&255;b[o+3]=(v>>>24)&255;}
function concatU8(parts){
  let n=0; parts.forEach(p=>n+=p.length);
  const out=new Uint8Array(n); let o=0;
  parts.forEach(p=>{out.set(p,o);o+=p.length;});
  return out;
}
function strToU8(s){return new TextEncoder().encode(String(s));}
function u8ToStr(b){return new TextDecoder('utf-8').decode(b);}

function base64ToU8(b64){
  const bin=atob(String(b64||''));
  const out=new Uint8Array(bin.length);
  for(let i=0;i<bin.length;i++) out[i]=bin.charCodeAt(i);
  return out;
}
function getCanonicalTemplateBytes(){
  if(!CANONICAL_TEMPLATE_XLSX_BASE64) throw new Error('내장 기준 양식이 없습니다.');
  return base64ToU8(CANONICAL_TEMPLATE_XLSX_BASE64);
}
async function inflateRawZipData(data){
  if(typeof DecompressionStream==='undefined') throw new Error('브라우저가 ZIP deflate 해제를 지원하지 않습니다. Chrome/Edge 최신 버전에서 실행하세요.');
  let last=null;
  for(const fmt of ['deflate-raw','deflate']){
    try{
      const ds=new DecompressionStream(fmt);
      const stream=new Blob([data]).stream().pipeThrough(ds);
      return new Uint8Array(await new Response(stream).arrayBuffer());
    }catch(e){ last=e; }
  }
  throw last||new Error('ZIP deflate 해제 실패');
}
class MiniXlsxZip{
  static async loadAsync(bytes){return new MiniXlsxZip(bytes);}
  constructor(bytes){
    this.bytes=bytes instanceof Uint8Array?bytes:new Uint8Array(bytes);
    this.modified=new Map();
    this.removed=new Set();
    this.entries=[];
    this.map={};
    this._parse();
  }
  _parse(){
    const b=this.bytes;
    let eocd=-1;
    for(let i=b.length-22;i>=0&&i>=b.length-66000;i--){
      if(u32le(b,i)===0x06054b50){eocd=i;break;}
    }
    if(eocd<0) throw new Error('XLSX ZIP EOCD를 찾을 수 없습니다.');
    this.eocdOffset=eocd;
    this.eocd=b.slice(eocd);
    const total=u16le(b,eocd+10);
    const cdSize=u32le(b,eocd+12);
    const cdOffset=u32le(b,eocd+16);
    this.cdOffset=cdOffset; this.cdSize=cdSize;
    let p=cdOffset;
    for(let i=0;i<total;i++){
      if(u32le(b,p)!==0x02014b50) throw new Error('ZIP central directory 오류');
      const nameLen=u16le(b,p+28), extraLen=u16le(b,p+30), commentLen=u16le(b,p+32);
      const recLen=46+nameLen+extraLen+commentLen;
      const name=u8ToStr(b.slice(p+46,p+46+nameLen));
      const localOffset=u32le(b,p+42);
      if(u32le(b,localOffset)!==0x04034b50) throw new Error('ZIP local header 오류: '+name);
      const lnameLen=u16le(b,localOffset+26), lextraLen=u16le(b,localOffset+28);
      const dataStart=localOffset+30+lnameLen+lextraLen;
      const entry={
        name, central:b.slice(p,p+recLen), localOffset,
        method:u16le(b,p+10), flag:u16le(b,p+8), crc:u32le(b,p+16),
        compSize:u32le(b,p+20), uncompSize:u32le(b,p+24),
        localHeader:b.slice(localOffset,dataStart), dataStart
      };
      this.entries.push(entry); this.map[name]=entry;
      p+=recLen;
    }
  }
  file(path,content){
    path=String(path||'').replace(/^\//,'');
    const e=this.map[path];
    if(content===undefined){
      if(this.removed.has(path)) return null;
      if(!e) return null;
      return {async:async(type)=>{
        const data=await this._getData(e);
        if(type==='string') return u8ToStr(data).replace(/^\uFEFF/,'');
        if(type==='uint8array') return data;
        return data.buffer.slice(data.byteOffset,data.byteOffset+data.byteLength);
      }};
    }
    if(!e) throw new Error('원본 ZIP에 없는 파일은 추가하지 않습니다: '+path);
    this.removed.delete(path);
    this.modified.set(path,strToU8(content));
    return this;
  }
  remove(path){
    path=String(path||'').replace(/^\//,'');
    if(this.map[path]){ this.removed.add(path); this.modified.delete(path); }
    return this;
  }
  async _getData(e){
    if(this.modified.has(e.name)) return this.modified.get(e.name);
    const data=this.bytes.slice(e.dataStart,e.dataStart+e.compSize);
    if(e.method===0) return data;
    if(e.method===8) return await inflateRawZipData(data);
    throw new Error('지원하지 않는 ZIP 압축 방식: '+e.method+' / '+e.name);
  }
  async generateAsync(){
    const sorted=this.entries.filter(e=>!this.removed.has(e.name)).slice().sort((a,b)=>a.localOffset-b.localOffset);
    const nextOffset=new Map();
    for(let i=0;i<sorted.length;i++) nextOffset.set(sorted[i].name, i+1<sorted.length?sorted[i+1].localOffset:this.cdOffset);
    const parts=[]; const offsets={}; let outOff=0;
    for(const e of sorted){
      offsets[e.name]=outOff;
      if(this.modified.has(e.name)){
        const data=this.modified.get(e.name);
        const lh=e.localHeader.slice();
        const flag=e.flag & ~8;
        w16le(lh,6,flag); w16le(lh,8,0);
        w32le(lh,14,crc32Bytes(data)); w32le(lh,18,data.length); w32le(lh,22,data.length);
        parts.push(lh,data); outOff+=lh.length+data.length;
      }else{
        const seg=this.bytes.slice(e.localOffset,nextOffset.get(e.name));
        parts.push(seg); outOff+=seg.length;
      }
    }
    const cdParts=[];
    for(const e of this.entries){
      if(this.removed.has(e.name)) continue;
      const c=e.central.slice();
      if(this.modified.has(e.name)){
        const data=this.modified.get(e.name);
        const flag=e.flag & ~8;
        w16le(c,8,flag); w16le(c,10,0);
        w32le(c,16,crc32Bytes(data)); w32le(c,20,data.length); w32le(c,24,data.length);
      }
      w32le(c,42,offsets[e.name]);
      cdParts.push(c);
    }
    const cd=concatU8(cdParts);
    const eocd=this.eocd.slice();
    w16le(eocd,8,cdParts.length); w16le(eocd,10,cdParts.length);
    w32le(eocd,12,cd.length); w32le(eocd,16,outOff);
    const out=concatU8([...parts,cd,eocd]);
    return out.buffer.slice(out.byteOffset,out.byteOffset+out.byteLength);
  }
}

async function loadXlsxZip(templateBytes){
  if(typeof JSZip!=='undefined' && JSZip && typeof JSZip.loadAsync==='function'){
    console.log('[XLSX_EXPORT] using JSZip');
    return await JSZip.loadAsync(templateBytes);
  }
  console.warn('[XLSX_EXPORT] JSZip unavailable, using MiniXlsxZip fallback');
  return await MiniXlsxZip.loadAsync(templateBytes);
}
async function generateXlsxZip(zip){
  if(zip && typeof zip.generateAsync==='function' && !(zip instanceof MiniXlsxZip)){
    return await zip.generateAsync({type:'arraybuffer',compression:'DEFLATE'});
  }
  return await zip.generateAsync();
}
function removeXlsxZipPath(zip,path){
  try{ if(zip && typeof zip.remove==='function') zip.remove(path); }catch(e){ console.warn('[XLSX_EXPORT] remove skipped',path,e); }
}
async function getWorkbookSheetInfo(zip){
  const wbFile=zip.file('xl/workbook.xml');
  const relFile=zip.file('xl/_rels/workbook.xml.rels');
  if(!wbFile||!relFile) throw new Error('xlsx 내부 workbook.xml 또는 workbook.xml.rels를 찾을 수 없습니다.');
  const wbXml=await wbFile.async('string');
  const relXml=(await relFile.async('string')).replace(/^\uFEFF/,'');
  const rels={};
  relXml.replace(/<Relationship\b([^>]+?)\/?>(?:<\/Relationship>)?/g,(all,attrs)=>{
    const id=getXmlAttr(attrs,'Id');
    const target=getXmlAttr(attrs,'Target');
    const type=getXmlAttr(attrs,'Type');
    if(id && target && /worksheet$/i.test(type)) rels[id]=normalizeWorksheetPath(target);
    return all;
  });
  const sheets=[];
  wbXml.replace(/<[^:>]*:?sheet\b([^>]+?)\/?>(?:<\/[^:>]*:?sheet>)?/g,(all,attrs)=>{
    const name=getXmlAttr(attrs,'name');
    const rid=getXmlAttr(attrs,'r:id')||getXmlAttr(attrs,'id');
    const sheetId=getXmlAttr(attrs,'sheetId');
    if(name && rid && rels[rid]) sheets.push({name, rid, sheetId, path:rels[rid]});
    return all;
  });
  return sheets;
}
function buildCellXml(prefix,addr,value,styleId){
  const styleAttr=styleId?` s="${styleId}"`:'';
  const v=safeCellValue(value);
  if(v===null||v===undefined||v==='') return `<${prefix}c r="${addr}"${styleAttr}/>`;
  if(typeof v==='number') return `<${prefix}c r="${addr}"${styleAttr}><${prefix}v>${v}</${prefix}v></${prefix}c>`;
  if(typeof v==='boolean') return `<${prefix}c r="${addr}"${styleAttr} t="b"><${prefix}v>${v?1:0}</${prefix}v></${prefix}c>`;
  return `<${prefix}c r="${addr}"${styleAttr} t="inlineStr"><${prefix}is><${prefix}t>${xmlEscape(v)}</${prefix}t></${prefix}is></${prefix}c>`;
}
function getOutputResultValue(it){
  return getMainOutputResultValue(it);
}
function patchWorksheetCellXml(xml,addr,value){
  const parser=new DOMParser();
  const doc=parser.parseFromString(xml,'application/xml');
  const parseErr=doc.getElementsByTagName('parsererror')[0];
  if(parseErr) throw new Error('worksheet XML parse error: '+parseErr.textContent.slice(0,200));
  const ns='http://schemas.openxmlformats.org/spreadsheetml/2006/main';
  const prefix=detectWsPrefix(xml);
  const q=n=>prefix ? prefix+n : n;
  const parts=splitCellAddr(addr);
  const rowNo=String(parts.row);
  const colNo=colIndexFromLetters(parts.col);
  const sheetData=doc.getElementsByTagNameNS(ns,'sheetData')[0] || doc.getElementsByTagName(q('sheetData'))[0];
  if(!sheetData) throw new Error('worksheet sheetData not found');
  let row=null;
  const rows=Array.from(doc.getElementsByTagNameNS(ns,'row')).concat(Array.from(doc.getElementsByTagName(q('row'))));
  for(const r of rows){ if(r.getAttribute('r')===rowNo){ row=r; break; } }
  if(!row){
    row=doc.createElementNS(ns,q('row'));
    row.setAttribute('r',rowNo);
    let inserted=false;
    for(const r of Array.from(sheetData.children)){
      const rn=parseInt(r.getAttribute('r')||'0',10);
      if(rn>parts.row){ sheetData.insertBefore(row,r); inserted=true; break; }
    }
    if(!inserted) sheetData.appendChild(row);
  }
  let cell=null;
  const cells=Array.from(row.children).filter(n=>n.localName==='c');
  for(const c of cells){ if(c.getAttribute('r')===addr){ cell=c; break; } }
  let styleId='';
  if(cell && cell.getAttribute('s')) styleId=cell.getAttribute('s');
  if(!styleId) styleId=findColumnStyleId(xml,parts.col);
  if(!cell){
    cell=doc.createElementNS(ns,q('c'));
    cell.setAttribute('r',addr);
    if(styleId) cell.setAttribute('s',styleId);
    let inserted=false;
    for(const c of cells){
      const ref=c.getAttribute('r')||'';
      const m=ref.match(/^([A-Z]+)/);
      if(m && colIndexFromLetters(m[1])>colNo){ row.insertBefore(cell,c); inserted=true; break; }
    }
    if(!inserted) row.appendChild(cell);
  }
  while(cell.firstChild) cell.removeChild(cell.firstChild);
  if(styleId) cell.setAttribute('s',styleId);
  const val=safeCellValue(value);
  cell.removeAttribute('t');
  if(val==='' || val===null || val===undefined){
    cell.removeAttribute('t');
    return new XMLSerializer().serializeToString(doc);
  }
  if(typeof val==='number'){
    const v=doc.createElementNS(ns,q('v'));
    v.textContent=String(val);
    cell.appendChild(v);
  }else if(typeof val==='boolean'){
    cell.setAttribute('t','b');
    const v=doc.createElementNS(ns,q('v'));
    v.textContent=val?'1':'0';
    cell.appendChild(v);
  }else{
    cell.setAttribute('t','inlineStr');
    const is=doc.createElementNS(ns,q('is'));
    const t=doc.createElementNS(ns,q('t'));
    const s=String(val);
    if(/^\s|\s$/.test(s)) t.setAttribute('xml:space','preserve');
    t.textContent=s;
    is.appendChild(t);
    cell.appendChild(is);
  }
  return new XMLSerializer().serializeToString(doc);
}


function getSharedStringsModel(zip){
  const file=zip.file('xl/sharedStrings.xml');
  if(!file) throw new Error('sharedStrings.xml을 찾을 수 없습니다. 기준 양식 구조가 아닙니다.');
  return file.async('string').then(xml=>{
    const sis=[];
    String(xml).replace(/<si\b[\s\S]*?<\/si>/g,m=>{sis.push(m);return m;});
    return {xml:String(xml),items:sis,added:[]};
  });
}
function makeSharedStringSi(value){
  const s=safeCellValue(value);
  const preserve=/^\s|\s$/.test(String(s))?' xml:space="preserve"':'';
  return `<si><t${preserve}>${xmlEscape(String(s))}</t></si>`;
}
function appendSharedString(ss,value){
  const idx=ss.items.length+ss.added.length;
  ss.added.push(makeSharedStringSi(value));
  return idx;
}
function finalizeSharedStringsXml(ss){
  if(!ss || !ss.added || !ss.added.length) return ss?ss.xml:'';
  let xml=ss.xml;
  const total=ss.items.length+ss.added.length;
  if(/<sst\b[^>]*\bcount="[^"]*"/i.test(xml)) xml=xml.replace(/(<sst\b[^>]*\bcount=")[^"]*(")/i,`$1${total}$2`);
  else xml=xml.replace(/<sst\b/i,`<sst count="${total}"`);
  if(/<sst\b[^>]*\buniqueCount="[^"]*"/i.test(xml)) xml=xml.replace(/(<sst\b[^>]*\buniqueCount=")[^"]*(")/i,`$1${total}$2`);
  else xml=xml.replace(/<sst\b/i,`<sst uniqueCount="${total}"`);
  return xml.replace(/<\/sst>\s*$/i,ss.added.join('')+'</sst>');
}
function ensureSharedStringContentType(zip){
  // 기준 양식에는 이미 sharedStrings relationship/content type이 있으므로 추가 생성하지 않는다.
  return zip;
}
function getCellAttrValue(attrs,name){
  const re=new RegExp('\\b'+name+'=\"([^\"]*)\"');
  const m=String(attrs||'').match(re);
  return m?m[1]:'';
}
function stripCellTypeAttrs(attrs){
  return String(attrs||'')
    .replace(/\bt="[^"]*"/g,'')
    .replace(/\bcm="[^"]*"/g,'')
    .replace(/\bvm="[^"]*"/g,'')
    .replace(/\s+/g,' ')
    .trim();
}
function buildExistingCellReplacement(addr,value,oldAttrs,sharedStringsModel){
  const val=safeCellValue(value);
  const baseAttrs=stripCellTypeAttrs(oldAttrs).replace(/\br="[^"]*"/g,'').trim();
  const extra=baseAttrs?(' '+baseAttrs):'';
  if(val==='' || val===null || val===undefined) return `<c r="${addr}"${extra}/>`;
  if(typeof val==='number') return `<c r="${addr}"${extra}><v>${String(val)}</v></c>`;
  if(typeof val==='boolean') return `<c r="${addr}"${extra} t="b"><v>${val?'1':'0'}</v></c>`;
  if(!sharedStringsModel) throw new Error('문자 결과값을 쓰려면 sharedStrings 모델이 필요합니다: '+addr);
  const idx=appendSharedString(sharedStringsModel,String(val));
  return `<c r="${addr}"${extra} t="s"><v>${idx}</v></c>`;
}
function patchExistingWorksheetCellXmlString(xml,addr,value,sharedStringsModel){
  const escAddr=String(addr).replace(/[.*+?^${}()|[\]\\]/g,'\\$&');
  const re=new RegExp('<c\\b([^>]*)\\br=\"'+escAddr+'\"([^>]*)(?:\\/>|>[\\s\\S]*?<\\/c>)');
  const m=String(xml).match(re);
  if(!m) throw new Error('기준 양식 셀이 없습니다: '+addr);
  const oldAttrs=(m[1]||'')+(m[2]||'');
  const replacement=buildExistingCellReplacement(addr,value,oldAttrs,sharedStringsModel);
  return xml.slice(0,m.index)+replacement+xml.slice(m.index+m[0].length);
}
function patchExistingWorksheetCellXml(xml,addr,value,sharedStringsModel){
  // RF18: Excel 호환성을 위해 inlineStr 대신 sharedStrings 인덱스를 사용한다.
  // 기존 셀 노드만 찾아 스타일/병합/행높이/열너비는 그대로 보존한다.
  return patchExistingWorksheetCellXmlString(xml,addr,value,sharedStringsModel);
}
function setWorksheetCellXml(xml,addr,value){
  return patchWorksheetCellXml(xml,addr,value);
}
function setExistingWorksheetCellXml(xml,addr,value,sharedStringsModel){
  return patchExistingWorksheetCellXml(xml,addr,value,sharedStringsModel);
}
function removeCalcChainRefs(zip){
  const rel=zip.file('xl/_rels/workbook.xml.rels');
  if(rel){
    rel.async('string').then(()=>{}).catch(()=>{});
  }
}
async function forceWorkbookFullRecalc(zip){
  const wbFile=zip.file('xl/workbook.xml');
  if(!wbFile) return;
  let wbXml=await wbFile.async('string');
  if(/<[^:>]*:?calcPr\b/i.test(wbXml)){
    wbXml=wbXml.replace(/<([^:>]*:)?calcPr\b[^>]*(?:\/>|><\/\1?calcPr>)/i,(m,prefix='')=>`<${prefix||''}calcPr calcMode="auto" fullCalcOnLoad="1" forceFullCalc="1"/>`);
  }else{
    wbXml=wbXml.replace(/<\/([^:>]*:)?workbook>/i,(m,prefix='')=>`<${prefix||''}calcPr calcMode="auto" fullCalcOnLoad="1" forceFullCalc="1"/>`+m);
  }
  zip.file('xl/workbook.xml',wbXml);
}
async function stripCalcChainRelationship(zip){
  removeXlsxZipPath(zip,'xl/calcChain.xml');
  const relFile=zip.file('xl/_rels/workbook.xml.rels');
  if(relFile){
    let relXml=await relFile.async('string');
    const old=relXml;
    relXml=relXml.replace(/<Relationship\b[^>]*calcChain[^>]*(?:\/>|><\/Relationship>)/gi,'');
    if(relXml!==old) zip.file('xl/_rels/workbook.xml.rels',relXml);
  }
  const ctFile=zip.file('[Content_Types].xml');
  if(ctFile){
    let ctXml=await ctFile.async('string');
    const old=ctXml;
    ctXml=ctXml.replace(/<Override\b[^>]*PartName="\/xl\/calcChain\.xml"[^>]*(?:\/>|><\/Override>)/gi,'');
    if(ctXml!==old) zip.file('[Content_Types].xml',ctXml);
  }
}
function isCellMarkerValue(cell,inum){
  if(!cell) return false;
  const v=cell.v;
  if(typeof v==='number' && Number.isInteger(v) && v===inum) return true;
  if(typeof v==='string' && String(v).trim()===String(inum)) return true;
  return false;
}
function makeTemplatePreserveVerify(buffer,originalSheetNames){
  const rep={reloadOk:false,tab1Count:0,form3Count:0,errorCells:[],redMarkerFound:false,redMarkerCells:[],sheetNames:[],sheetCount:0,extraSheets:[],missingSheets:[],passed:false,messages:[]};
  try{
    const wb=XLSX.read(new Uint8Array(buffer),{type:'array',cellFormula:true,cellNF:true,cellDates:true});
    rep.reloadOk=true;
    rep.sheetNames=wb.SheetNames.slice();
    rep.sheetCount=wb.SheetNames.length;
    const original=originalSheetNames||[];
    rep.extraSheets=rep.sheetNames.filter(n=>!original.includes(n));
    rep.missingSheets=original.filter(n=>!rep.sheetNames.includes(n));
    const sn=findSheetNameByNameOrIndex(wb,STATE.dataSheetName,0);
    const ws=wb.Sheets[sn];
    if(ws){
      for(let n=1;n<=112;n++){
        const r=mainResultRowForInum(n);
        const rc=sheetGet(ws,r,RESULT_COL);
        const rv=rc?rc.v:undefined;
        if(rv!==null&&rv!==undefined&&rv!=='') rep.tab1Count++;
        if(typeof rv==='number'&&Number.isInteger(rv)&&rv===n){rep.redMarkerFound=true;rep.redMarkerCells.push(`I${r}==${n}`);}
        if(typeof rv==='string'&&String(rv).trim()===String(n)){rep.redMarkerFound=true;rep.redMarkerCells.push(`I${r}==${n}`);}
      }
    }
    const ws4=wb.Sheets['80871631-3']||wb.Sheets[wb.SheetNames[3]];
    if(ws4){
      for(let n=1;n<=112;n++){
        const r=form3ResultRowForInum(n); if(!r) continue;
        const v5=sheetGet(ws4,r,FORM3_RESULT_COL)?.v;
        if(v5!==null&&v5!==undefined&&v5!=='') rep.form3Count++;
        if(typeof v5==='number' && Number.isInteger(v5) && v5===n){rep.redMarkerFound=true;rep.redMarkerCells.push(`Form3 E${r}==${v5}`);}
        if(typeof v5==='string' && String(v5).trim()===String(n)){rep.redMarkerFound=true;rep.redMarkerCells.push(`Form3 E${r}==${v5}`);}
      }
    }
    if(rep.extraSheets.length) rep.messages.push('추가 시트가 남아 있습니다: '+rep.extraSheets.join(', '));
    if(rep.missingSheets.length) rep.messages.push('원본 시트가 누락되었습니다: '+rep.missingSheets.join(', '));
    if(rep.redMarkerFound) rep.messages.push('빨간번호 마커가 결과 셀에 남아 있습니다: '+rep.redMarkerCells.slice(0,10).join(', '));
    if(!rep.tab1Count) rep.messages.push('1탭 결과가 삽입되지 않았습니다.');
    rep.passed=rep.reloadOk && rep.tab1Count>0 && !rep.redMarkerFound && rep.extraSheets.length===0 && rep.missingSheets.length===0;
  }catch(e){
    rep.reloadOk=false;
    rep.messages.push('재로드 실패: '+(e.message||String(e)));
  }
  return rep;
}

// ── downloadXLSX (RF18: 원본 양식 보존 + sharedStrings 기반 셀 치환 패치) ─────────
// v0.4.0M: removed stray standalone `async` token that raised ReferenceError before export/session init.
// ══════════════════════════════════════════════════════════════
// v0.4.0D: 출력 단위 generationRunId 정책
// XLSX와 넘버링 PDF는 항상 같은 generationRunId를 공유한다.
// [성적서 생성 실행] 또는 [다운로드] 단위로 한 번만 증가.
// - 고정값(FIXED_TEXT, ACCEPT, REFERENCE): 항상 동일
// - 범위값(RANGE_RANDOM, MULTI_RANGE_RANDOM): 매 실행마다 새 값
// ══════════════════════════════════════════════════════════════
let _exportSessionId = 0;  // 현재 출력 세션 — XLSX/PDF 같은 세션이면 동일 runId

function regenerateForExport(){
  // 새 출력 세션 시작 — runId 올리고 범위값 재계산
  STATE.generationRunId = (STATE.generationRunId||0) + 1;
  _exportSessionId = STATE.generationRunId;
  // 범위값 항목 재계산 (recalcItemStatus 존재 시)
  if(typeof recalcItemStatus === 'function'){
    recalcItemStatus(STATE.dxfSourceMap);
  }
  // 넘버링 아이템 재계산은 하지 않음 (위치 정보를 보존해야 하므로)
  console.log('[v0.4.0K] regenerateForExport runId='+STATE.generationRunId);
}

function isCurrentSession(){
  return _exportSessionId > 0 && _exportSessionId === STATE.generationRunId;
}

// v0.4.0D: ensureExportSession — XLSX/PDF가 같은 세션을 공유하도록 보장
// - 첫 출력: 새 세션 생성
// - 같은 세션 내 두 번째 출력(XLSX→PDF or PDF→XLSX): 기존 세션 유지
function ensureExportSession(){
  if(!isCurrentSession()){
    regenerateForExport();
  }
}

async function downloadXLSX(){
  // v0.4.0D: 같은 세션이면 재생성 안 함 (XLSX↔PDF 동일 runId 공유)
  ensureExportSession();
  if(!STATE.xlsxBuffer && !STATE.xlsxOriginalBuffer){showAlert('오류','빈 검사성적서 양식을 먼저 업로드해주세요.');return;}
  const btn=el('dlXlsxBtn');
  btn.disabled=true; btn.textContent='생성 중...';
  openProg('원본 양식 보존 출력 중...');
  try{
    setProg(5,'출력 기준 양식 선택');
    const uploadedTemplateBuffer=STATE.xlsxOriginalBuffer||STATE.xlsxBuffer;
    const uploadedBytes=uploadedTemplateBuffer instanceof Uint8Array ? uploadedTemplateBuffer : new Uint8Array(uploadedTemplateBuffer);
    let templateBytes=uploadedBytes;
    let templateSource='업로드 양식';
    let uploadedIssues=[];
    try{
      const uploadedWb=XLSX.read(uploadedBytes,{type:'array',cellFormula:true,cellNF:true,cellDates:true});
      uploadedIssues=verifyExactTemplateShape(uploadedWb);
    }catch(e){ uploadedIssues=['업로드 양식 재검증 실패: '+(e.message||String(e))]; }
    if(uploadedIssues.length){
      console.warn('[XLSX_EXPORT] 업로드 양식은 기준 구조가 아니므로 내장 기준 양식으로 대체합니다:', uploadedIssues);
      templateBytes=getCanonicalTemplateBytes();
      templateSource='내장 기준 양식(완성본 구조)';
    }
    STATE.templatePositionWarnings=uploadedIssues;

    setProg(10,templateSource+' ZIP 로드');
    const zip=await loadXlsxZip(templateBytes);
    const sharedStringsModel=await getSharedStringsModel(zip);

    setProg(14,'원본 시트 매핑 확인');
    const sheetInfo=await getWorkbookSheetInfo(zip);
    if(!sheetInfo.length) throw new Error('원본 XLSX 시트 매핑을 찾을 수 없습니다.');
    const originalSheetNames=sheetInfo.map(s=>s.name);
    const mainInfo=sheetInfo.find(s=>s.name===STATE.dataSheetName)||sheetInfo.find(s=>s.name==='80871631')||sheetInfo[0];
    const form3Info=sheetInfo.find(s=>s.name==='80871631-3')||sheetInfo[3]||null;

    setProg(20,'기준 양식 셀 위치 계산');
    const wb=XLSX.read(templateBytes,{type:'array',cellFormula:true,cellNF:true,cellDates:true});
    const canonIssues=verifyExactTemplateShape(wb);
    if(canonIssues.length){
      throw new Error('내장/출력 기준 양식 검증 실패: '+canonIssues.join(' / '));
    }
    const mainName=findSheetNameByNameOrIndex(wb,mainInfo.name,0);
    const ws1=wb.Sheets[mainName];
    if(!ws1) throw new Error('1번째 탭을 찾을 수 없습니다: '+mainInfo.name);

    const certItems=normalizeResultItemsForCertificate();

    setProg(35,'1탭 결과 셀 XML 직접 패치');
    const mainFile=zip.file(mainInfo.path);
    if(!mainFile) throw new Error('원본 1탭 XML을 찾을 수 없습니다: '+mainInfo.path);
    let mainXml=await mainFile.async('string');
    let inserted=0;
    certItems.forEach(it=>{
      const r=mainResultRowForInum(it.inum);
      if(r){
        mainXml=setExistingWorksheetCellXml(mainXml,sheetAddr(r,RESULT_COL),getMainOutputResultValue(it),sharedStringsModel);
        inserted++;
      }
    });
    zip.file(mainInfo.path,mainXml);
    zip.file('xl/sharedStrings.xml',finalizeSharedStringsXml(sharedStringsModel));

    setProg(55,'4탭 Form3 수식/양식 보존');
    let form3Patched=0;
    // RF16: Form3 탭은 원본 양식의 수식과 특수 NOTE 결과값이 이미 기준 완성본과 일치한다.
    // E10:E115는 1탭 I열을 참조하는 수식이므로 직접 값으로 덮어쓰지 않는다.
    // 따라서 4탭은 행수/열너비/수식/테두리 보존을 위해 XML을 변경하지 않는다.

    setProg(72,'원본 calcChain/workbook 관계 보존');

    setProg(75,'원본 탭 구성 유지 상태로 XLSX 재압축');
    const buffer=await generateXlsxZip(zip);

    setProg(90,'출력 검증');
    const vRep=makeTemplatePreserveVerify(buffer,originalSheetNames);
    STATE.lastVerify=vRep;
    renderVerify();
    closeProg();

    if(!vRep.passed){
      showAlert('품질 검증 실패',`1탭 결과: ${vRep.tab1Count}개\n4탭 Form3: ${vRep.form3Count}개\n시트 수: ${vRep.sheetCount}개\n추가 시트: ${vRep.extraSheets.length}개\n재로드: ${vRep.reloadOk?'성공':'실패'}\n\n`+(vRep.messages.join('\n')||'원인 불명'));
      return;
    }

    showAlert('다운로드 준비 완료',`✅ 원본 양식 보존 출력\n✅ 출력 기준: ${templateSource}\n✅ 1탭 결과 삽입: ${inserted}개\n✅ 4탭 Form3 보정: ${form3Patched}개\n✅ 원본 시트 수 유지: ${vRep.sheetCount}개\n✅ 추가 진단 시트 생성 없음\n\n※ RF18은 worksheet 전체 재직렬화 없이 기존 셀 XML만 치환하고, 문자값은 sharedStrings에 추가해 Excel 호환성을 높입니다. calcChain/workbook 관계는 원본 기준 양식 그대로 보존합니다.`);
    const blob=new Blob([buffer],{type:'application/vnd.openxmlformats-officedocument.spreadsheetml.sheet'});
    const url=URL.createObjectURL(blob);
    const a=document.createElement('a');a.href=url;
    a.download=`검사성적서_${STATE.drawingNo}_${APP_VERSION_SHORT}_${new Date().toISOString().slice(0,10)}.xlsx`;
    document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(url);
  }catch(e){
    closeProg();showAlert('다운로드 오류',(e.message||String(e))+'\n'+(e.stack||'').substring(0,500));
  }finally{
    btn.disabled=false;btn.textContent='검사성적서 다운로드';
  }
}

function downloadReport(){
  const hdr=['inum','drawingZone','finalSpec','specSourceType','sourceObjectId','sourceRawText',
             'matchMethod','matchConfidence','tolerance','method','resultType','generatedResult',
             'resultSourceType','generationRule','seed','minValue','maxValue',
             'outputCell','form3Cell','status'].map(csvE).join(',');
  const csv=hdr+'\n'+STATE.itemStatus.map(it=>[it.inum,it.drawingZone,it.finalSpec,it.specSourceType,
    it.sourceObjectId||'',it.sourceRawText||'',it.matchMethod,it.matchConfidence,it.tol,it.method,
    it.resultType,it.generatedResult,it.resultSourceType,it.generationRule,it.seed,
    it.minValue??'',it.maxValue??'',it.outputCell,it.form3Cell,it.status].map(csvE).join(',')).join('\n');
  dlTxt(csv,`분석리포트_${STATE.drawingNo}_${APP_VERSION_SHORT}.csv`,'text/csv');
}
function downloadLog(){
  const hdr=['inum','finalSpec','specSourceType','sourceObjectId','sourceRawText','resultType',
             'generatedResult','resultSourceType','seed','minValue','maxValue','status'].map(csvE).join(',');
  const csv=hdr+'\n'+STATE.itemStatus.map(it=>[it.inum,it.finalSpec,it.specSourceType,it.sourceObjectId||'',
    it.sourceRawText||'',it.resultType,it.generatedResult,it.resultSourceType,
    it.seed,it.minValue??'',it.maxValue??'',it.status].map(csvE).join(',')).join('\n');
  dlTxt(csv,`Generation_Log_${STATE.drawingNo}_${APP_VERSION_SHORT}.csv`,'text/csv');
}
function dlTxt(content,name,mime){
  const blob=new Blob(['\uFEFF'+content],{type:mime+';charset=utf-8;'});
  const url=URL.createObjectURL(blob);
  const a=document.createElement('a');a.href=url;a.download=name;
  document.body.appendChild(a);a.click();document.body.removeChild(a);URL.revokeObjectURL(url);
}

// ── 고급 모드 ─────────────────────────────────────────────────
function showAL(btn,tab){
  document.querySelectorAll('.adv-tab').forEach(b=>b.classList.remove('active'));btn.classList.add('active');
  document.querySelectorAll('[id^="AL_"]').forEach(c=>c.classList.add('hidden'));
  const e=el('AL_'+tab);if(e)e.classList.remove('hidden');
}
function renderAdv(){renderALRaw();renderALText();renderALDim();renderALInum();renderALNoise();renderALSrcComp();renderALRefDb();renderALZone();renderALTmpl();renderTrace();}

function mkTd(c){return `<td style="font-size:11px;padding:5px 8px">${c}</td>`;}
function mkRow(cols){return `<tr>${cols.map(mkTd).join('')}</tr>`;}

function renderALRaw(){
  const tb=el('AL_rawTb');if(!tb)return;
  const src=STATE.entities.length>0?STATE.entities.map((e,i)=>({objectId:`E${(i+1).toString().padStart(4,'0')}`,type:e.type,layer:e.layer||'',cleanedText:DXFParser.cleanText(e.text||'').substring(0,30),x:e.x||0,y:e.y||0,role:'',confidence:'',isNoise:false})):DXF_RAW_SAMPLE;
  tb.innerHTML=src.slice(0,400).map(o=>mkRow([
    `<span style="font-size:9px;color:var(--text-dim)">${escHtml(o.objectId||'')}</span>`,
    `<span class="bdg bdg-noise">${escHtml(o.type||'')}</span>`,
    `<span style="color:var(--text-dim)">${escHtml(o.layer||'')}</span>`,
    `<span style="font-family:Consolas,'Malgun Gothic',monospace">${escHtml((o.cleanedText||'').substring(0,30))}</span>`,
    o.x||0,o.y||0,
    `<span class="bdg bdg-noise">${escHtml(o.role||'')}</span>`,
    o.confidence||'—',
    o.isNoise?'<span style="color:var(--c-miss)">Y</span>':'',
  ])).join('');
}

