function renderALSrcComp(){
  const sum=el('SC_summary');
  const its=STATE.itemStatus;
  const dxfCnt=its.filter(i=>i.specSourceType==='DXF_CONFIRMED').length;
  const refCnt=its.filter(i=>i.specSourceType==='REFERENCE_SPEC_DATABASE').length;
  if(sum)sum.innerHTML=[
    ['전체 객체',STATE.entities.length||DXF_CANDS_EMBEDDED.length],
    ['치수 후보',STATE.parsedCands.length||DXF_CANDS_EMBEDDED.filter(c=>c.role==='SPEC_TEXT').length],
    ['DXF 원천 연결',dxfCnt],['기준DB 보완',refCnt],
    ['미사용 후보',Math.max(0,(STATE.parsedCands.length||0)-dxfCnt)],
    ['노이즈 제외',STATE.parsedNoise.length||DXF_RAW_SAMPLE.filter(o=>o.isNoise).length],
  ].map(([l,v])=>`<div class="stat-item"><div class="stat-val" style="font-size:18px">${v}</div><div class="stat-lbl">${l}</div></div>`).join('');
  const tb=el('AL_scTb');if(!tb)return;
  tb.innerHTML=its.map(it=>mkRow([
    `<span style="font-weight:700;color:var(--accent)">${it.inum}</span>`,
    `<span style="font-family:Consolas,'Malgun Gothic',monospace">${escHtml(it.drawingZone)}</span>`,
    escHtml(it.referenceSpec.substring(0,25)),
    it.specSourceType==='DXF_CONFIRMED'?'<span style="color:var(--c-dxf)">✓</span>':'—',
    `<span style="font-size:10px;color:var(--text-dim)">${escHtml(it.sourceObjectId||'—')}</span>`,
    `<span style="font-family:Consolas,'Malgun Gothic',monospace;font-size:10px">${escHtml((it.sourceRawText||'').substring(0,20)||'—')}</span>`,
    it.matchMethod||'—',
    it.matchConfidence?(it.matchConfidence.toFixed?it.matchConfidence.toFixed(2):it.matchConfidence):'—',
    srcBdg(it.specSourceType),rtBdg(it.resultType),
    `<span style="font-family:Consolas,'Malgun Gothic',monospace;font-weight:700;color:var(--c-ok)">${escHtml(it.generatedResult||'—')}</span>`,
  ])).join('');
}

