function filterTrace(){
  const q=(el('traceSearch')?.value||'').toLowerCase();
  const src=el('traceSrcSel')?.value||'all';
  const rt=el('traceRtSel')?.value||'all';
  let its=STATE.itemStatus;
  if(src!=='all')its=its.filter(i=>i.specSourceType===src);
  if(rt!=='all') its=its.filter(i=>i.resultType===rt);
  if(q)its=its.filter(i=>String(i.inum).includes(q)||(i.drawingZone||'').includes(q)||(i.finalSpec||'').toLowerCase().includes(q));
  renderTrace(its);
}

function renderTrace(items){
  items=items||STATE.itemStatus;
  const tb=el('traceTbody');if(!tb)return;
  tb.innerHTML=items.map(it=>`
    <tr onclick="showDetail(${it.inum})" style="cursor:pointer">
      <td style="font-weight:700;color:var(--accent)">${it.inum}</td>
      <td style="font-family:Consolas,'Malgun Gothic',monospace;font-size:10px">${escHtml(it.drawingZone||'')}</td>
      <td style="font-size:11px;max-width:100px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${escHtml(it.finalSpec)}">${escHtml(it.finalSpec)}</td>
      <td>${srcBdg(it.specSourceType)}</td>
      <td style="font-size:9px;color:var(--text-dim);font-family:Consolas,'Malgun Gothic',monospace">${escHtml(it.sourceObjectId||'—')}</td>
      <td style="font-family:Consolas,'Malgun Gothic',monospace;font-size:10px;max-width:80px;overflow:hidden;text-overflow:ellipsis;white-space:nowrap" title="${escHtml(it.sourceRawText||'')}">${escHtml(it.sourceRawText||'—')}</td>
      <td style="font-size:10px">${escHtml(it.matchMethod||'—')}</td>
      <td style="font-size:10px">${it.matchConfidence||(it.matchConfidence===0?'0':'—')}</td>
      <td>${rtBdg(it.resultType)}</td>
      <td style="font-family:Consolas,'Malgun Gothic',monospace;font-weight:700;color:var(--c-ok)">${escHtml(it.generatedResult||'—')}</td>
      <td style="font-size:10px;color:var(--text-dim)">${escHtml(it.resultSourceType||'—')}</td>
      <td style="font-size:10px;color:var(--text-dim)">${escHtml(it.outputCell||'—')}</td>
      <td>${stsBdg(it.status)}</td>
    </tr>
  `).join('');
}

// ── 초기화 ────────────────────────────────────────────────────
// v0.3.2_FIXED8: 정적 오염도 진단 후 중복 waitForPDFJS, libError 오타 load listener, PDF UI raw innerHTML 일부를 정리했다.
// v0.3.2_FIXED9: ExcelJS 재저장으로 발생하는 sheet1~4 XML 복구 경고를 피하기 위해 최종 XLSX 출력을 SheetJS 안전 경로로 전환했다.
// v0.3.2_RF16: 위치 검증은 hard fail 금지. 1탭 I11:I19/I26:I128, Form3 E9:E118/E119/E121에 값 주입하고 검번 셀도 기준 위치로 보정한다.
// v0.3.3_DXF_PREVIEW_BOTTOM_VIEW: 사용자 모드 하단에 독립 SVG 기반 DXF 도면 미리보기 영역을 추가했다.
// v0.3.4_DXF_PREVIEW_NUMBERING_MODE: DXF 미리보기에 일반/넘버링 모드와 수동 원형 번호 오버레이를 추가했다.
// v0.3.5_AUTO_ITEM_NUMBERING_OVERLAY: 성적서 항목 기준 자동 넘버링을 기본 동작으로 전환하고 수동 기능은 보정용으로 재정의했다.
// v0.3.6_AUTO_NUMBERING_ACCURACY_REVIEWED: 자동 넘버링 매칭을 보수화하고 중복 후보/구획 fallback/겹침 보정을 검수 기준에 맞게 조정했다.
// v0.3.7_PREVIEW_PAN_NUMBERING_UX_FIXED: 넘버링 모드에서도 pan을 허용하고, 위치 지정은 pendingAction의 짧은 클릭에서만 실행되도록 분리했다.
// 아래 명시적 전역 바인딩은 inline onchange와 drag/drop 모두를 안전하게 보강한다.
window.onDxfFile=onDxfFile;
window.onXlsxFile=onXlsxFile;
window.diagXlsxUpload=diagXlsxUpload;
window.checkReady=checkReady;
window.toggleDark=toggleDark;
window.toggleAdv=toggleAdv;
window.goStep=goStep;
window.runAnalysis=runAnalysis;
window.downloadXLSX=downloadXLSX;
window.downloadReport=downloadReport;
window.downloadLog=downloadLog;
window.renderDXFPreview=renderDXFPreview;
window.fitDXFPreview=fitDXFPreview;
window.zoomDXFPreview=zoomDXFPreview;
window.resetDXFPreview=resetDXFPreview;
window.toggleDXFPreviewCollapse=toggleDXFPreviewCollapse;
window.setDXFPreviewMode=setDXFPreviewMode;
window.deleteSelectedDXFNumber=deleteSelectedDXFNumber;
window.deleteLastDXFNumber=deleteLastDXFNumber;
window.clearDXFNumbers=clearDXFNumbers;
window.toggleDXFNumberList=toggleDXFNumberList;
window.deleteDXFNumber=deleteDXFNumber;
window.selectDXFNumber=selectDXFNumber;
window.generateAutoNumberingFromItems=generateAutoNumberingFromItems;
window.regenerateAutoNumbering=regenerateAutoNumbering;
window.beginSelectedDXFNumberReposition=beginSelectedDXFNumberReposition;
window.beginSelectedDXFNumberPlacement=beginSelectedDXFNumberPlacement;
window.setDXFNumberFilter=setDXFNumberFilter;
window.handleDXFPreviewClickForNumbering=handleDXFPreviewClickForNumbering;
window.cancelDXFNumberingPendingAction=cancelDXFNumberingPendingAction;
// v0.3.8 multi-sheet
window.setActiveSheet=setActiveSheet;
window.renderSheetTabs=renderSheetTabs;
window.detectDXFSheets=detectDXFSheets;

document.addEventListener('keydown',ev=>{
  if(ev.key==='Escape') cancelDXFNumberingPendingAction();
});

window.addEventListener('load',()=>{
  try{
    if(typeof XLSX==='undefined'||typeof XLSX.read!=='function')el('libErr').style.display='inline';
    setEl('refCnt',REFERENCE_SPEC_DATABASE_EMBEDDED.length);
    setEl('refDbCnt',REFERENCE_SPEC_DATABASE_EMBEDDED.length);
    setDXFPreviewEmpty();
    checkReady();
  }catch(e){console.error('[INIT] 기본 초기화 실패:', e);}

  const dxfInput=document.querySelector('#cardDxf input[type=file]');
  const xlsxInput=document.querySelector('#cardXlsx input[type=file]');
  if(dxfInput){dxfInput.onchange=function(){window.onDxfFile(this);};}
  if(xlsxInput){xlsxInput.onchange=function(){window.onXlsxFile(this);};}

  // DnD
  ['cardDxf','cardXlsx'].forEach(id=>{
    const e=el(id);if(!e)return;
    e.addEventListener('dragover',ev=>{ev.preventDefault();e.style.borderColor='var(--accent)';});
    e.addEventListener('dragleave',()=>e.style.borderColor='');
    e.addEventListener('drop',ev=>{
      ev.preventDefault();e.style.borderColor='';
      const file=ev.dataTransfer.files[0];if(!file)return;
      const inp=e.querySelector('input[type=file]');
      if(inp){const dt=new DataTransfer();dt.items.add(file);inp.files=dt.files;inp.dispatchEvent(new Event('change',{bubbles:true}));}
    });
  });
});
